window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q14"]=window.__LIBQ["tien-nghich"]["q14"]||{};window.__LIBQ["tien-nghich"]["q14"]["cotTruyen"]=[{"chuong":1451,"tieuDe":"Rời Đi","tomTat":"Vương Lâm cùng người điên trở về Liên Minh Tinh Vực, cảm thụ khí tức quen thuộc, lòng tràn ngập bi thương nhớ về nhà ở Côn Hư và Chu Tước, nhớ Thanh Thủy và Tư Đồ Nam, người nhà đã mất từ lâu. Hai người phát hiện một tu chân tinh cấp thấp vô cùng to lớn, Vương Lâm nhìn thấu bên trong có bốn lão quái bế quan ở trung tâm. Người điên đòi ở lại chơi, bị Vương Lâm dùng kim quang kéo lại nhưng thi triển thần thông bí ẩn thoát khỏi trong nháy mắt, tự xưng bổn vương nói có nhiều sư tôn không ai quản được. Vương Lâm nhận người điên có ân tái tạo, quyết bảo vệ, liền mở trữ vật triệu hồi Hứa Lập Quốc và Lưu Kim Bưu giao nhiệm vụ trông coi người điên trên tu chân tinh. Hứa Lập Quốc bị người điên gọi là tiểu nương tử, tức giận phản bác, người điên cười lăn bò rồi dần mê man nhắc Tiểu Hồng mang ô. Vương Lâm một mình biến mất trong tinh không đi thẳng tới tổng bộ Tu Chân Liên Minh, thầm gọi Thanh Thủy sư huynh."},{"chuong":1452,"tieuDe":"Ba Bảo Vật","tomTat":"Vương Lâm một mình xuyên tinh không với tốc độ đỉnh điểm, chỉ ba bước Súc Địa Thành Thốn quét ngang Côn Hư tinh vực hướng về tổng bộ Tu Chân Liên Minh. Bước đầu lướt qua nơi Lỗ Phu Tử đang bố trí trận pháp thượng cổ; Lỗ Phu Tử thoáng cảm nhận khí tức quen thuộc nhưng cho rằng mình hoa mắt. Bước thứ hai đưa hắn tới vùng cấm thức gần trung tâm Côn Hư — nơi tinh không sụp đổ do đại chiến trước đây, hắn suy đoán mình đã ở trong U Minh thú rất lâu và chiến cục giới nội-ngoại đã trải qua nhiều lần giao tranh. Tại đây, Vương Lâm phát hiện Viêm Lôi Tử (Toái Niết đại viên mãn) bị hai tu sĩ giới ngoại thuộc Hỏa Tước tộc và Phụng Thiên Lang tộc truy sát. Qua đối thoại, tiết lộ phó hội trưởng Trường Tôn hội Thiên Triệu Thượng Sư có ước định tạm hoãn giao chiến với giới nội, Hồng Sam Tử đang bị vây và Nam Vân Tử chưa xuất quan. Viêm Lôi Tử nhắc chiến tích Phong Tôn từng giết lão tổ Hỏa Tước tộc trước mười vạn tu sĩ giới ngoại. Bị dồn vào đường cùng, Viêm Lôi Tử đốt sinh mạng quyết tử, nhưng Vương Lâm kịp ra tay cứu — hiện hình trong bạch y, phóng kim quang vạn trượng, quát một tiếng khiến hai tu sĩ Toái Niết giới ngoại tê dại kinh hồn, tuyên bố trở về."},{"chuong":1453,"tieuDe":"Biến Hóa Trong Vài Thập Niên","tomTat":"Vương Lâm dùng kim quang giết dễ dàng hai tu sĩ Toái Niết giới ngoại — tu sĩ Hỏa Tước tộc hóa mây khói, tu sĩ Phụng Thiên Lang tộc phát điên tiêu tan vì nhớ lại ác mộng năm xưa khi Phong Tôn cầm búa cản mấy vạn quân. Viêm Lôi Tử, Chỉ huy phó chiến tuyến tây bắc La Thiên, hành lễ tham kiến Phong Tôn rồi tường thuật toàn cảnh tình hình giới nội vài thập niên qua: Thất Thải Giới là bẫy vạn năm của Chưởng Tôn, ba trận đại chiến đã nổ ra — Hồng Sam Tử bị phong ấn vây trong Thất Thải Giới ở Triệu Hà, Nam Vân Tử bị Chưởng Tôn đánh trọng thương bế quan, tiên đế Thanh Lâm thi triển viễn cổ tiên thuật phong kín Thất Thải Giới cứu giới nội nhưng bản thân trọng thương. Hiện đã chín năm sau đại chiến thứ ba, ánh sáng viễn cổ sắp bị phá, đại chiến thứ tư cận kề, giới nội nguy cấp. Bốn tinh vực tình hình khác nhau: Triệu Hà bị vây khốn, Vân Hải gần sụp, La Thiên bình yên, Côn Hư bị phân liệt. Vương Lâm dùng kim quang chữa trị Viêm Lôi Tử khiến hắn thoát thai hoán cốt, rồi quyết định hướng tới tổng bộ Tu Chân Liên Minh để hủy diệt Thất Thải Giới, dù bên trong có Thiên Triệu Thượng Sư tu vi Không Linh sơ kỳ và Trọng Huyền Tử đã phản bội thành tay sai giới ngoại."},{"chuong":1454,"tieuDe":"Dư Uy Của Vương Lâm","tomTat":"Vương Lâm bước xuyên tinh không đưa Viêm Lôi Tử tới bên ngoài tổng bộ Tu Chân Liên Minh, đối mặt dòng xoáy phong ấn khổng lồ — trận pháp cấm chế truyền thừa từ thượng cổ có nguồn gốc Vũ Tiên giới mà năm xưa Lỗ Phu Tử cùng tu sĩ bước ba liên thủ cũng chỉ làm chậm. Vương Lâm chỉ điểm một ngón tay khiến dòng xoáy dừng hẳn rồi xé nát, đạp sụp tinh không, tạo cơn lốc vàng diệt mấy ngàn tu sĩ giới ngoại, phá bức màn lộ ra tu chân tinh tổng bộ. Mấy ngàn rồi hơn vạn tu sĩ giới ngoại vừa nhận ra Phong Tôn liền kinh hoàng sụp đổ tâm thần. Viêm Lôi Tử xác nhận Trọng Huyền Tử đang ở tổng đàn. Từ tu chân tinh, Thiên Triệu Thượng Sư — lão già hắc bào tu sĩ Không Linh — xuất hiện trong sương mù đen, tuyên bố muốn giết Phong Tôn để đứng nhất Thái Cổ Tinh Thần bảng, thi triển đòn sát thủ ba hắc long tế luyện ngàn năm chứa hương hỏa giới nghênh chiến. Phía dưới tu chân tinh tổng bộ có khe nứt phát ra huyết quang bất thường."},{"chuong":1455,"tieuDe":"Hỏi Thiên Hạ Ai Nắm Quyền Sinh Sát","tomTat":"Thiên Triệu Thượng Sư tuy bề ngoài ngông cuồng nhưng nội tâm cực kỳ khiếp hãi Vương Lâm, nhớ lại danh tiếng Phong Tôn, cái chết thảm khốc của Nam Chiếu Thượng Nhân, và dòng xoáy vạn cổ Tu Chân Liên Minh bị xé tan. Hắn tự trấn an rằng không có Khai Thiên Phủ thì Vương Lâm không đấu nổi, rồi vung tay áo điều khiển ba hương hỏa hắc long tấn công. Vương Lâm quyết định dùng toàn lực bất chấp rút ngắn thời gian áp chế lực bài xích, vì mục tiêu cứu Thanh Thủy và lấy đạo quả. Hai mắt hắn lóe kim quang tiên lực chính tông tràn ngập tinh không — ba hắc long nhận ra trong truyền thừa linh hồn, sợ hãi bái lạy; hơn vạn tu sĩ giới ngoại bị uy áp linh hồn phun máu quỳ xuống. Thiên Triệu Thượng Sư nhận ra kim quang, nhớ lại năm xưa bắt hắc long từng gặp tiên nhân, chỉ bị nhìn một cái đã hôn mê mười năm — hoảng sợ cực điểm bỏ hết chống cự. Vương Lâm bước tới, lần lượt dùng nắm tay vàng đánh nát thân thể, tiên lôi đánh tan hồn phách hương hỏa, Thiên Hoàng Lô thiêu hủy nguyên thần — Thiên Triệu Thượng Sư chết. Từ đầu tới cuối Vương Lâm không nói một lời. Sau trận, cơ thể hắn bắt đầu đau đớn mơ hồ do lực bài xích dần muốn bộc phát."},{"chuong":1456,"tieuDe":"Long Bàn Tử","tomTat":"Vương Lâm đứng giữa tinh không trước gần vạn tu sĩ giới ngoại, quan sát tu chân tinh tổng bộ Tu Chân Liên Minh và nhận ra cấm chế trận pháp thứ hai — mấy chục tinh cầu nhỏ tương trợ tạo thành cửa lớn thứ hai, uy lực vượt cơn lốc xoáy vạn cổ. Hắn chụp ba con hắc long hương hỏa: con thứ nhất phong ấn tặng Viêm Lôi Tử giúp có cơ duyên đạt bước thứ ba, con thứ hai gửi cho Thân Công Hổ đáp lại hai chữ tôn chủ năm xưa, cả hai đều bị bức ra hồn phách tu sĩ giới nội trước khi trao. Con thứ ba được sai nuốt gần vạn tu sĩ giới ngoại rồi lao vào tu chân tinh phá trận, gây nứt vỡ. Đạo khí tức thứ tư bên trong thức tỉnh — tu chân tinh sống lại thành hình người khổng lồ, lão già tóc bạc hư ảo xuất hiện trên đỉnh chính là Long Bàn Tử, thái thượng trưởng lão Liên Minh, sư phụ Trọng Huyền Tử, đã dung hợp nguyên thần với tinh cầu trở thành tinh hồn vạn cổ bất diệt. Cuối chương, từ bên trong tu chân tinh truyền ra tiếng gào thét chứa sát lục bổn nguyên, Vương Lâm nhận ra cực kỳ quen thuộc, sắc mặt lần đầu biến đổi dữ dội, thốt lên Thanh Thủy sư huynh."},{"chuong":1457,"tieuDe":"Sơn Hà Đồ","tomTat":"Chương mở đầu bằng hồi tưởng về ân tình giữa Vương Lâm và sư huynh Thanh Thủy — người từng truyền thần thông và che chở hắn năm xưa. Toàn bộ bi kịch đời Thanh Thủy được kể lại: từng là vua Thanh Thủy Quốc bị truy sát, thức tỉnh Cực Cảnh báo thù máu chảy thành sông, vào Lôi Tiên Giới gặp sư tôn Bạch Phàm và nữ tử thay đổi đời mình, trở thành Thanh Thủy tiên quân rồi lại phát điên tự tay giết vợ, bị Bạch Phàm phong ấn nhưng lưu hồn phách. Nghe tiếng gào thét điên cuồng từ tu chân tinh, Vương Lâm xác nhận Thanh Thủy còn sống, vui mừng thề sẽ giúp khôi phục thần trí. Hắn phóng thích con hắc long hương hỏa cho tự do nhưng cảnh cáo không được giết tu sĩ giới nội. Không còn kiên nhẫn, Vương Lâm giải phóng toàn lực — bảy tinh điểm vàng trên mi tâm xoay tròn — đánh quyền phá nát hai cánh tay tu chân tinh rồi ba bước tiến vào vùng trời. Lão già trên đỉnh tu chân tinh kích hoạt Sơn Hà Đồ — chí bảo chân chính Vũ Tiên Giới — hai dãy núi nổi lên tựa trục cuộn, mở ra cuộn tranh sơn thủy mười vạn trượng tạo lực hút khổng lồ kèm thời gian trôi nhanh. Vương Lâm đáp trả bằng Dịch Linh Ấn chính tông bậc nhất nhờ tiên huyết mạch, phóng tiên khí tinh thuần cấp hoàng tộc tiên chấn động cả giới nội — khiến một thanh niên bí ẩn ở Triệu Hà kinh hoàng nhận ra hoàng tộc tiên giáng lâm, Chiến lão quỷ thần bí khiếp sợ, và Viễn Cổ Tiên Vực đang bị phong ấn cũng kinh động."},{"chuong":1458,"tieuDe":"Ngươi Nói Cái Gì","tomTat":"Tại Lôi Tiên Giới hoang tàn trong La Thiên Tinh Vực, Chiến lão quỷ ẩn cư trong vầng sáng ngàn trượng, cảm nhận được tiên khí hoàng tộc tiên huyết mạch La Huyền Thiên Địa, tiết lộ tu vi đạt Không Kiếp Sơ Kỳ tương đương Địa Tiên và nảy ý đoạt huyết mạch. Trong Viễn cổ Tinh Vực, tứ đại chiến tướng của Viễn cổ Tiên Tôn — Thanh Long, Bạch Hổ, Huyền Vũ, Chu Tước — lần đầu lộ diện, đang bị phong ấn trong mi tâm bốn pho tượng Cổ Thần khổng lồ; Bạch Hổ muốn thoát ra lấy tiên lực cho chủ nhân khôi phục trí nhớ nhưng bị chặn, Chu Tước tiết lộ có kế hoạch đang tiến hành. Tại tổng bộ Tu Chân Liên Minh, Vương Lâm bất chấp lực bài xích giữa nguyên tiên và Đạo cổ, bộc phát tiên lực biến Dịch Linh Ấn thành tiên thuật thực sự xé rách Sơn Hà Đồ, nhưng bị pháp bảo tự khôi phục và phản kích, thân thể chịu tổn thương nặng. Vương Lâm rút ra cây cung, công khai tự xưng đương kim Phong Tôn, vạch trần Liên Minh bị tu sĩ giới ngoại chiếm cứ, Trọng Huyền Tử là tay sai, tuyên bố mục đích hủy Thất Thải Giới, cứu Thanh Thủy, giết tu sĩ giới ngoại. Long Bàn Tử sửng sốt dừng lại."},{"chuong":1459,"tieuDe":"Trọng Huyền Tử","tomTat":"Long Bàn Tử tỉnh lại sau giấc ngủ dài, nhận ra Vương Lâm xưng Phong Tôn thì nhớ ân tình năm xưa. Hắn lôi Trọng Huyền Tử và hai đại trưởng lão từ tu chân tinh ra tra hỏi, giết Trương Tịch vì do dự không dám nói thật, giết đại trưởng lão còn lại sau khi đọc ký ức xác nhận tội trạng. Trọng Huyền Tử quỳ cầu xin tha mạng, khai ra toàn bộ: bắt tay giới ngoại vì giới nội không phải đối thủ, tiết lộ sự tồn tại Long Bàn Tử cho giới ngoại đổi cơ duyên, đổ lỗi cho Thanh Thủy Tiên Quân buộc hắn phá phong ấn Thất Thải Giới. Long Bàn Tử tiết lộ mục đích thật của Tu Chân Liên Minh không phải khống chế Côn Hư mà nâng cao tu vi tu sĩ Côn Hư để đánh giới ngoại, hồi tưởng Trọng Huyền Tử vốn là đồng tử ăn mày tên Tống nhi được chính tay tạo đạo cốt. Long Bàn Tử gánh tội thay đệ tử, vái Vương Lâm rồi tự thiêu đốt nguyên thần bộc phát sức mạnh Không Huyền Sơ Kỳ, tuyên bố sẽ giết toàn bộ tu sĩ giới ngoại trong giới nội và giành lại Triệu Hà. Tu chân tinh sụp đổ hoàn toàn, Long Bàn Tử cuốn Trọng Huyền Tử rời đi và mở lối vào Thất Thải Giới qua khe nứt lộ ánh sáng bảy màu. Vương Lâm hỏi Thanh Thủy đang ở đâu."},{"chuong":1460,"tieuDe":"Huyền Vũ","tomTat":"Trọng Huyền Tử nói với Viêm Lôi Tử rằng chuyện năm đó không hoàn toàn như hắn nhìn thấy, giọng bi thương hối hận, rồi cùng Long Bàn Tử rời đi. Viêm Lôi Tử hồi tưởng quá khứ: vốn là đạo hữu chí cốt với Trọng Huyền Tử, ba người thường luận đạo, hắn cùng đạo lữ theo yêu cầu Trọng Huyền Tử gia nhập Liên Minh, nhưng một sự việc bí ẩn đã biến tình bạn thành thù hận sâu như biển. Viêm Lôi Tử nói rõ với Vương Lâm rằng mối thù là việc riêng, lấy đại cục làm trọng, rồi từ biệt ra đi với dáng vẻ già nua cô độc. Vương Lâm một mình kiên định bước vào Thất Thải Giới lần thứ hai. Bên trong, hắn phát hiện gần mười vạn ngọn núi tạo thành trận pháp khổng lồ, trên mỗi đỉnh núi có tu sĩ bị đá nhọn xuyên thân giam cầm, máu chảy bốc thành khói hồng bay về ngọn núi trung tâm, nửa là tu sĩ giới ngoại, nửa là tu sĩ Liên Minh. Khi Vương Lâm bước vào, cấm chế kích hoạt, mười vạn tu sĩ đồng loạt rít gào phun máu tạo sương máu tràn ngập. Hắn lao thẳng tới ngọn núi cao nhất, phát hiện mười vạn ngọn núi thực chất là gai trên lưng một con Huyền Vũ khổng lồ đã hóa đá chiếm cứ toàn bộ Thất Thải Giới. Trên đầu Huyền Vũ có một trung niên bí ẩn mang khí tức vạn cổ ngồi khoanh chân, thân thể nối liền Huyền Vũ, thiên linh bị gai dài ba tấc đâm xuyên từ dưới lên."},{"chuong":1461,"tieuDe":"Thanh Thủy","tomTat":"Vương Lâm tìm thấy thi thể Huyền Vũ Thánh Hoàng trên đỉnh núi, chết trong tư thế đang hấp thụ sức mạnh chân thân Huyền Vũ bằng đá, vẻ mặt vừa mừng vừa sợ. Tiến lên đỉnh núi cao nhất, phát hiện Thanh Thủy bị mười cái cọc phát ánh sáng bảy màu đóng chặt trên vách núi, thần trí điên cuồng, mi tâm bị ngón tay trỏ bảy màu khổng lồ hấp thụ sát lục bổn nguyên. Thanh Thủy phóng Cực Cảnh chứa sát lục bổn nguyên và huyết ảnh đầu lâu tấn công Vương Lâm, Vương Lâm dùng kim lôi và kim hỏa đối kháng nhưng bị thương phải lùi. Vương Lâm gào to gọi tên, Thanh Thủy thoáng tỉnh nói hồn phách bị Huyền Vũ trấn áp rồi lập tức bị khí xám xâm nhập trở lại điên cuồng. Vương Lâm phát hiện cọc thứ mười ẩn giấu, giải mã toàn bộ trận pháp: mười vạn ngọn núi hóa cọc phong ấn, mười vạn tu sĩ nuôi Huyền Vũ bằng máu, Thanh Thủy là lò luyện sát lục bổn nguyên, ngón tay trỏ bảy màu thu hoạch thành quả. Suy luận Huyền Vũ Thánh Hoàng phản bội vì Tu Chân Liên Minh tìm được chân thân Huyền Vũ — có thể là tứ đại chiến tướng Tiên Tôn — hắn muốn sức mạnh tổ tiên. Sương máu hiện cảnh tượng quá khứ Thanh Thủy: vốn là thái tử nước nhỏ phàm trần, nước bị tàn phá, bỏ trốn bái nhập sơn môn bị lăng nhục, từ đó sinh ra Cực Cảnh, suốt quá trình có ánh sáng bảy màu với hư ảnh bí ẩn quan sát. Vương Lâm chấn động, nảy ra phán đoán đáng sợ về kẻ đứng sau thao túng cuộc đời Thanh Thủy."},{"chuong":1462,"tieuDe":"Ánh Mắt Cổ Quái","tomTat":"Vương Lâm nhìn thấy toàn bộ quá khứ bi thảm của Thanh Thủy qua sương máu trong Thất Thải Giới: thiếu niên lớn lên, cố quốc bị diệt, bảy ngày đẫm máu, sau đó vào Tiên Giới gặp Bạch Phàm và nữ tử ôn nhu sống hạnh phúc. Tuy nhiên một người bảy màu trên bầu trời chỉ xuống kích phát Thanh Thủy điên cuồng giết chóc khắp Lôi Tiên Giới, giết cả người yêu. Ánh mắt bảy màu đó khiến Vương Lâm cảm thấy cổ quái, như nhìn vào gương, người kia giống chính mình. Ký ức sụp đổ rồi tuần hoàn liên tục, sức mạnh mờ ám dùng vòng lặp tàn khốc kích thích sát lục bổn nguyên trong cơ thể Thanh Thủy dần thực chất hóa. Vương Lâm thề liều mạng cứu Thanh Thủy, nhận ra Huyền Vũ hóa đá là mấu chốt trận pháp, dùng mười quyền thất tinh Cổ Thần đánh nhưng không phá nổi, cánh tay bị phản chấn. Mười vạn tu sĩ tử thi thức tỉnh tự nổ tung, máu thịt ngưng tụ thành cây đao khổng lồ chém xuống. Vương Lâm hóa Cổ Thần ngàn trượng đỡ đao, bộc phát dung hợp tiên-thần, mượn lực đối phương, lần đầu tiên thi triển sức mạnh Cổ Thần cả hai tay đập vào lưng Huyền Vũ, khiến mai phát ra tiếng rắc rắc."},{"chuong":1463,"tieuDe":"Rút Cọc","tomTat":"Vương Lâm đánh nứt mai Huyền Vũ khiến khí xám phun ra, một phần nhập vào thi thể Huyền Vũ Thánh Hoàng khiến y sắp sống lại. Hắn lập tức vung huyết kiếm chém đứt đầu Huyền Vũ Thánh Hoàng và chém đứt cọc, xóa tan mối nguy. Cây đao máu thịt từ phía sau lao tới tấn công, Vương Lâm tung quyền liên tục phá nát nó hoàn toàn. Chịu lực bài xích toàn thân rỉ máu, hắn vẫn quyết tâm phá mai Huyền Vũ bằng mấy trăm quyền xen kim quang, lửa, lôi đình, rồi thi triển Dịch Linh Ấn đập nát mai, giải phóng hồn phách Thanh Thủy. Mười vạn gai trên lưng Huyền Vũ sụp đổ, gần mười vạn gai xuyên khắp thân Vương Lâm kể cả mắt, biến hắn thành quả cầu gai. Nửa nén nhang sau hắn đấm phá quả cầu thoát ra, tự rút gai khỏi mắt, nhiều gai gãy gắn liền xương thịt không thể lấy ra. Toàn thân đẫm máu, hắn từng bước đi tới Thanh Thủy trong đám mây bảy màu, rút cái cọc thứ nhất khỏi ngực Thanh Thủy."},{"chuong":1464,"tieuDe":"Thân Ảnh Bảy Màu","tomTat":"Vương Lâm rút lần lượt bốn cây cọc phong ấn trên người Thanh Thủy — cọc ngực phong ấn trái tim, cọc cổ họng phong ấn gân cốt, hai cọc cánh tay phong ấn thần thức — mỗi cọc gây phản lực tấn công khiến hắn phun máu hai lần, thần thức trọng thương. Lực bài xích giữa tiên lực và Đạo cổ lực phá vỡ gai bên ngoài thân thể nhưng gai trong da thịt vẫn mọc rễ không loại bỏ được. Ngón tay bảy màu đã tiêu tan ngưng tụ thành thân ảnh bảy màu hư ảo, chỉ Vương Lâm nhìn thấy; Thanh Thủy không thể thấy. Thân ảnh bảy màu cho Vương Lâm cơ hội cứu Thanh Thủy, hướng dẫn tác dụng từng cọc, nhận biết Vương Lâm mang truyền thừa Đạo cổ thân thể bất diệt tiên tộc và năm đạo bổn nguyên nhưng nói tạm thời không có tác dụng. Thân ảnh so sánh Vương Lâm với tiểu tu sĩ thờ phụng Chiến Nguyên năm đó từng khiến hắn kinh ngạc, khẳng định giữa hắn và Vương Lâm không có quan hệ. Sau khi Vương Lâm rút đủ ba cọc, thân ảnh tiết lộ Đạo cổ Diệp Mịch trước khi chết phun ra tam thiên tiên huyết — một thiên hóa cổ Thần, một thiên hóa cổ Ma, một thiên hóa cổ Yêu — tạo nên nguồn gốc ba bộ tộc cổ đại. Vương Lâm liên kết lời này với lời cổ Yêu Bối La năm xưa, suy luận cổ Tộc là thế hệ nghịch tu thứ nhất, sau đánh với trời phân tán, tam thiên tiên huyết dung hợp phần nhiều chính là vương tộc, nhưng hắn không chắc thật giả."},{"chuong":1465,"tieuDe":"Đa Tạ","tomTat":"Vương Lâm tiếp tục rút cọc phong ấn trên thân Thanh Thủy trong Thất Thải Giới: rút cọc thứ năm ở đan điền (phong ấn nguyên thần), cọc sáu-bảy ở hai chân đồng thời, và cọc thứ tám gần thiên linh — cọc này không phải phong ấn mà để mở ra luân hồi, khi rút vô số ký ức vặn vẹo tràn vào đầu Vương Lâm. Thanh Thủy tách khỏi ngọn núi, ngã vào vai Vương Lâm nói một tiếng Đa tạ rồi hôn mê. Thân ảnh bảy màu tặng Vương Lâm đạo quả màu vàng làm lễ vật, gọi Thanh Thủy là đồ chơi, tiết lộ mục đích: muốn xem linh tu có thể xuất hiện biến hóa tuyệt diệu như tiểu tử của Chiến Nguyên để tìm được thứ hắn cần. Vương Lâm hỏi đối phương có phải Tiên Tôn không, được đáp Phải mà cũng không phải. Thân ảnh vung tay đẩy Vương Lâm ra, khe Thất Thải Giới co lại biến mất hoàn toàn giữa tinh không Côn Hư Tinh Vực. Vương Lâm suy ngẫm, liên hệ tiểu tử Chiến Nguyên với Chiến lão quỷ, nhận ra chuyện Thanh Thủy chỉ là trò chơi của thân ảnh. Đưa Thanh Thủy tới tu chân tinh hoang dã ngoài tổng bộ Tu Chân Liên Minh, cố đè nén lực bài xích trong cơ thể nhưng chỉ giảm đau chút ít."},{"chuong":1466,"tieuDe":"Rượu Mạnh","tomTat":"Vương Lâm dùng song chỉ rút cây cọc thứ chín (đen, mềm, đã dung hợp phân nửa) ra khỏi xương sống Thanh Thủy, máu đen phun ra nhưng xương sống hồi phục. Hai sư huynh đệ cùng uống rượu sảng khoái, Thanh Thủy cảm khái sư đệ đã trưởng thành thành nhất đại cao thủ khiến tinh không rung chuyển. Tiếp đó Vương Lâm rút cây cọc thứ mười — cây cuối cùng, màu tím, mềm như rắn, nằm trong toàn bộ huyết quản — ra hơn phân nửa. Thanh Thủy yêu cầu rượu mạnh hơn, Vương Lâm lấy bầu viêm long huyết mà lão Chu Tước từng cho để thay rượu. Thanh Thủy tự đứng lên bẻ gãy cọc làm đôi, dùng sát lục bổn nguyên giết chết phần cọc còn lại trong cơ thể, tự xưng bổn tiên quân. Phun máu đen, thân thể gầy gò bành trướng khôi phục hình dáng năm xưa, sát lục bổn nguyên bộc phát kinh thiên, thiên địa biến đen, tuyết đen tràn ngập, và một cánh cửa hư ảo — Không Đại Môn — xuất hiện ở chân trời."},{"chuong":1467,"tieuDe":"Rượu Mạnh","tomTat":"Vương Lâm phân tích bí ẩn đạo nhân bảy màu, suy luận mục đích thật sự không phải sát lục bổn nguyên mà có thể là hạ luân hồi vào sát lục bổn nguyên của Thanh Thủy. Hắn hồi tưởng chuỗi sự kiện xuyên suốt từ Tham Lang ở Điện Lạc, pho tượng bảy màu, Chiến lão quỷ ở Vân Hải, tinh thạch lưng Huyền Vũ từ Thất Thải Giới — tất cả là bộ phận của bí ẩn cực lớn liên quan giới nội. Hắn tự nhận đã có hai đạo quả trong ba đạo bổn nguyên sinh tử, nhân quả, thật giả, chỉ cần thêm một đạo nữa. Thanh Thủy dùng sát lục bổn nguyên ngưng tụ hắc kiếm chém vỡ non nửa không môn, đột phá thành công lên Không Niết Sơ Kỳ — trở thành tu sĩ bước thứ ba. Khi không môn hiện ra, tàn hồn thê tử Hàm Yên xuất hiện mỉm cười giữa vô số hồn phách quỳ lạy, Thanh Thủy ôm nàng khóc rống, sẵn sàng bỏ tu vi để giữ nàng. Vương Lâm dùng hơn mười lá Cổ Tức Diệp kết hợp máu tiên nhân (huyết mạch tiên nhân) tạo phong ấn thiên địa ngưng kết tàn hồn Hàm Yên. Thanh Thủy cài thoa cổ xưa — di vật từ diệt giới — lên đầu nàng, rồi thu toàn bộ hồn phách vào hắc kiếm tặng Vương Lâm, nói nếu luyện hóa cảm ngộ sẽ có sát lục bổn nguyên — đây là pháp bảo bổn nguyên bước thứ ba cực kỳ hiếm gặp."},{"chuong":1468,"tieuDe":"Triệu Hà","tomTat":"Không môn phá, Thanh Thủy ôm hồn phách thê tử hóa ấn ký đặt tại trái tim rồi tặng Vương Lâm thanh sát lục kiếm, khiến bổn nguyên Vương Lâm đạt sáu đạo. Vương Lâm quyết chưa luyện hóa sát lục bổn nguyên, đợi ba bổn nguyên nhân quả, sinh tử, thật giả đại thành rồi mới phá không môn. Hai người ngồi trên tu chân tinh hoang dã uống long huyết tửu, Thanh Thủy nhắc tới phát hiện ở tổng bộ Tu Chân Liên Minh gọi đó là một trò chơi với vẻ khổ sở. Hai người lập lời hứa mai táng cho nhau: Thanh Thủy muốn được chôn ở quê, bia không ghi danh; Vương Lâm muốn được đưa về Chu Tước Tinh Triệu Quốc Vương gia. Thanh Thủy tiết lộ có con gái thất lạc, vai trái mang hồng ấn nhận dạng, nhờ Vương Lâm chiếu cố nếu gặp. Sau đó sát lục bổn nguyên Thanh Thủy bộc phát, hai người hóa sóng gợn quét sạch tu sĩ giới ngoại còn sót khắp Côn Hư rồi tiến vào Triệu Hà đã bị chiếm cứ hoàn toàn, lao thẳng vào Thất Thải Giới cuối cùng nơi bổn tôn Hồng Sam Tử bị phong ấn. Bên trong Long Bàn Tử đang chiến đấu với điện chủ Thiên Phạt Điện tu vi Không Huyền sơ kỳ, mấy vạn tu sĩ giới ngoại tụng chú hỗ trợ. Thanh Thủy lao vào giết mấy vạn tu sĩ, Vương Lâm ngẩng đầu nhìn thấy đạo quả cực lớn trong đám mây bảy sắc."},{"chuong":1469,"tieuDe":"Đạo Quả Thứ Ba!","tomTat":"Bổn tôn Hồng Sam Tử bị giam trong đạo quả mơ hồ trong suốt, đang bị sợi tơ hấp thu dưỡng chất, không có Thiên Nghịch nên kết cục chỉ có tử vong. Thanh Thủy dùng sát lục bổn nguyên tạo cơn lốc đen đóng băng toàn bộ sinh linh quỷ dị và phong tỏa cửa Thất Thải Giới ngăn Điện chủ Thiên Phạt Điện rút lui. Long Bàn Tử thiêu đốt tu vi hòa hợp với Sơn Hà Đồ hóa bàn tay khổng lồ, Thanh Thủy thi triển Bạch Phàm Thuật — Âm Nguyệt và Hữu Tình, hai người liên thủ đánh trọng thương Điện chủ khiến hương hỏa giới vỡ nát, mặt nứt năm vết rách, lưng in chưởng ấn sơn hà. Đại chiến khiến Thất Thải Giới sụp đổ diện rộng, ba khối đại lục tan thành tro bụi, tu sĩ giới ngoại còn sống sót đều tử vong. Điện chủ nhận ra Bạch Phàm Thuật và xác nhận đối thủ là Thanh Thủy. Điện chủ trọng thương đề nghị giúp mở đạo quả đổi lấy được rời đi, Vương Lâm lạnh lùng từ chối. Vương Lâm tay phải phát ánh sáng nhu hòa xuyên vào đạo quả không hề bị phản chấn, cứu Hồng Sam Tử ra. Sau đó dùng huyết kiếm chặt cành cây thu đạo quả thứ ba, tuyên bố sẽ nuốt hấp thu toàn bộ."},{"chuong":1470,"tieuDe":"Thập Tam","tomTat":"Hồng Sam Tử hồi phục, cùng Long Bàn Tử, Thanh Thủy và Vương Lâm hợp lực đánh bại Tần Cửu Duyên — Điện chủ Thiên Phạt Điện bước thứ ba. Tần Cửu Duyên bị Hồng Sam Tử giam cầm mang đi, tuyên bố sẽ luyện thành huyết thân. Long Bàn Tử linh hồn bị thiêu đốt được giúp dập tắt, mang Trọng Huyền Tử rời đi. Thanh Thủy rời đi tìm con gái, thề chỉ cần Vương Lâm gọi sẽ trở về. Hồng Sam Tử tuyên bố Phong Tôn đã trở lại, giao Vương Lâm lấy danh nghĩa Phong Tôn chủ huy cuộc phản kích cuối cùng tại chiến trường Vân Hải. Thất Thải Giới sụp đổ, Triệu Hà được giành lại, tu sĩ giới nội bừng lên niềm tin. Tại tu chân tinh Côn Hư Nhất Linh ở ranh giới bốn tinh vực, nữ tử áo tím Chu Tử Hồng từ Chu Tước Tinh kể chuyện từng gặp Mã Lương (Vương Lâm) thời Trúc Cơ và nhắc Lý Mộ Uyển là bạn cùng phòng. Một thanh niên áo đen ngồi riêng thầm gọi Sư tôn, kinh ngạc kích động khi thấy một nam tử áo trắng bước vào khách sạn — gợi ý trùng phùng sư đồ giữa Thập Tam và Vương Lâm."},{"chuong":1471,"tieuDe":"Ngươi Là Chu Tử Hồng","tomTat":"Trong khách sạn trên một tu chân tinh buôn bán, nữ tử áo tím Chu Tử Hồng hồi tưởng và kể cho các tu sĩ xung quanh nghe về quá khứ huyền thoại của Phong Tôn trên Chu Tước Tinh: thời Trúc Cơ giết hơn trăm tu sĩ cùng cấp, cứu Lý Mộ Uyển bị truy sát vào Tu Ma Hải, rồi quay về Triệu Quốc diệt cả nhà họ Đằng báo thù máu chảy thành sông. Vương Lâm bước vào khách sạn gặp lại đệ tử Thập Tam, cho biết đang trên đường về Chu Tước Tinh bái tế cha mẹ và dự định luyện hoá ba bổn nguyên nhân quả, sinh tử, chân giả. Hắn ngồi nghe chuyện cũ của chính mình, uống rượu, lòng đầy bi ai nhớ cha mẹ. Khi Vương Lâm quay đầu mỉm cười trước lúc rời đi, Chu Tử Hồng tâm thần chấn động nhận ra thân ảnh quen thuộc chính là người trong ký ức nhưng không nói ra. Trên đỉnh núi cao nhất, Vương Lâm từ chối cho Thập Tam theo hầu, dạy bảo hắn phải tự đối mặt gió mưa, có ý chí nghịch thiên, tuyên bố từ nay Thập Tam lấy danh nghĩa đồ đệ bắt đầu con đường tu đạo riêng, rồi vỗ đỉnh đầu Thập Tam."},{"chuong":1472,"tieuDe":"Tiếng Gào Thét Của Người Điên","tomTat":"Vương Lâm dùng một chưởng hóa cảm ngộ đại thành về lôi hỏa bổn nguyên thành hạt giống màu vàng chứa tiên lực huyết mạch, gieo sâu vào hồn phách Thập Tam, nói đây là vật chí bảo trong thiên địa. Hắn lấy lại pho tượng Cổ Yêu từ Thập Tam, đặt trong không gian trữ vật chờ thời điểm mấu chốt mới hấp thụ vào mắt trái. Dặn dò Thập Tam sống theo lương tâm rồi chia tay, Thập Tam quỳ giập đầu chín cái tiễn sư phụ. Vương Lâm một mình đi trong tinh không, ngang qua cửa lớn Vũ Tiên Giới nhưng không đủ thời gian nên không vào, hướng tới tu chân tinh cấp bảy tìm người điên. Tại đó, Hứa Lập Quốc và Lưu Kim Bưu đã hợp mưu nhiều ngày lừa người điên bằng cách hứa dẫn gặp nữ tử để đổi lấy máu tươi quý giá từ hắn. Người điên bị dẫn qua nhiều truyền tống trận liên tiếp, mất kiên nhẫn gào thét dọa mách sư phụ khiến cả hai hoảng sợ. Vương Lâm bước ra từ tinh không bên ngoài tu chân tinh, phát hiện tình trạng, nhướn mày nói một chữ “Hồ đồ!”."},{"chuong":1473,"tieuDe":"Ta Không Làm Gì Hết!","tomTat":"Hứa Lập Quốc và Lưu Kim Bưu dẫn Người điên qua truyền tống trận tới động phủ trong ngọn núi phía tây bắc tu chân tinh. Lưu Kim Bưu bóp vai xin thưởng rồi kể chi tiết chi phí mười ba ngày qua để ép Người điên áy náy cắn ngón tay cho tám chín giọt máu tươi. Hứa Lập Quốc dụ Người điên vào phòng gặp Pháp Hoa Tử — nam giới đóng giả tiểu nương tử. Hai người bàn mưu bên ngoài, Lưu Kim Bưu tiết lộ trước đây đã dùng mấy chục truyền tống trận lấy không ít máu tươi. Hứa Lập Quốc dùng ngọc giản triệu hồi hơn mười tu sĩ đồng mưu, dẫn đầu là một nữ tu mặt lạnh. Cả nhóm diễn kịch: Hứa Lập Quốc và Lưu Kim Bưu giả bị thương, nữ tu quát mắng đòi Người điên đổ đầy mười bình ngọc bằng máu tươi chuộc mạng. Người điên hoảng sợ kêu mình không làm gì. Cuối chương, một thân ảnh áo trắng âm thầm xuất hiện phía sau, ánh mắt hàn quang, quát đích danh Hứa Lập Quốc và Lưu Kim Bưu — chủ nhân đã trở về bắt quả tang."},{"chuong":1474,"tieuDe":"Thu Thập Ác Nô","tomTat":"Vương Lâm xuất hiện trong động phủ, uy áp chấn nhiếp toàn bộ tu sĩ khiến họ phun máu. Hứa Lập Quốc và Lưu Kim Bưu quỳ sụp cầu xin tha mạng. Vương Lâm chỉ một ngón tay phế ba thành tu vi Hứa Lập Quốc vì dám đem người điên ra cho bọn họ chơi đùa, nói rõ nếu không có công lao trước đó sẽ hủy hồn phách. Lưu Kim Bưu bị tước cơ duyên tự do, bắt làm nô bộc một ngàn năm vì bản tính khó sửa. Thanh niên áo đen Pháp Hoa Tử nhận ra Vương Lâm chính là Phong Tôn từ manh mối Chu Tước Tinh và Hỏa Tước Tộc, toàn bộ tu sĩ kích động bái kiến. Vương Lâm thu hai nô bộc vào không gian trữ vật, lấy lại hơn phân nửa giọt máu vàng, mang người điên rời đi. Người điên sau sự kiện trở nên cực kỳ keo kiệt với linh thạch và ngân lượng. Vương Lâm nhìn bộ dạng nói liến thoắng của người điên, mơ hồ cảm thấy giống một người từng gặp một lần ở giới ngoại Thái Cổ Tinh Thần, rồi lắc đầu không nghĩ thêm, hướng về Chu Tước Tinh."},{"chuong":1475,"tieuDe":"Chu Tước Tinh","tomTat":"Vương Lâm mang theo người điên đi trong tinh không hướng về Chu Tước Tinh. Người điên gào thét đòi trừng phạt thêm Hứa Lập Quốc và Lưu Kim Bưu, nhưng Vương Lâm vạch trần rằng máu hắn hứa cho hai người chỉ là thứ vất đi, chẳng bằng nửa giọt máu chính thức — người điên cũng đã lừa gạt lại bọn họ. Khi nhìn thấy quê hương Chu Tước Tinh, Vương Lâm thân thể khẽ run, nhiều khuôn mặt người thân hiện lên trước mắt, cảm thán cảnh còn người mất. Hắn kinh ngạc phát hiện bên ngoài Chu Tước Tinh có trận pháp mênh mông mới được bố trí vài thập niên gần đây. Bốn tu sĩ dẫn đầu bởi Đạo Đức Tử từ Minh Hồng Tinh thuộc Triệu Hà tới chầu thánh, cung kính gọi đây là cố hương của Phong Tôn và thánh địa của Côn Hư tinh vực cùng giới nội. Vương Lâm chọn đi từ cửa chính qua trận pháp vào quê hương, hai hư ảnh canh giữ cảm thấy hắn quen mặt nhưng không nhận ra. Bậc cuối cầu thang mây chính là ngọn núi cao nhất trên Chu Tước Tinh."},{"chuong":1476,"tieuDe":"Lá Rụng Về Cội","tomTat":"Vương Lâm trở lại Chu Tước Tinh cùng người điên, phát hiện quê hương đã thay đổi hoàn toàn sau hơn hai ngàn năm — ngọn núi cao nhất được khắc thành pho tượng khổng lồ của chính hắn dưới danh hiệu Phong Tôn, tay cầm Khai Thiên Phủ ngẩng đầu nhìn trời, kỷ niệm trận chiến đầu tiên ở Vân Hải tinh vực. Hắn lang thang khắp nơi tìm lại dấu vết cũ nhưng Luyện Hồn Tông đã biến mất, Cự Ma tộc thành thảo nguyên, Tuyết Vực quốc không còn tuyết, Tu Ma Hải sương tan, sơn động nơi hắn sống cùng Lý Mộ Uyển và sơn cốc nơi Chu Như lớn lên đều bị san bằng — tất cả không còn chút gì quen thuộc, hắn cô độc tột cùng như kẻ xa nhà không tìm được đường về. Duy nhất Triệu Quốc được Chu Vũ Thái ra lệnh bảo toàn tuyệt đối bằng trận pháp hào quang, không cho bất kỳ ai bước vào hay động tới cây cỏ. Vương Lâm dùng lực vô hình tách trận pháp bước vào Triệu Quốc, kinh động toàn bộ tu sĩ đại thần thông và cửu đại tông môn trên Chu Tước Tinh, một lão già tu sĩ phẫn nộ đuổi theo. Hắn thi triển Súc Địa Thành Thốn tới Hằng Nhạc Sơn, tìm thấy ngôi nhà năm xưa ở thành Hoàng Tổ Hảo không hề thay đổi, phía đông sân có ngôi mộ cha mẹ được hậu nhân đời đời tu bổ. Vương Lâm quỳ trước mộ khóc, tự xưng Thiết Trụ, nói chỉ cần cha mẹ còn sống để cả nhà mình cùng Uyển Nhi và Bình Nhi đoàn tụ thì không cần gì khác. Lão già đuổi tới nơi, nhìn thấy cảnh tượng ấy liền chấn động nhận ra trong thiên hạ chỉ có một người duy nhất có tư cách quỳ trước ngôi mộ đó — chính là Phong Tôn."},{"chuong":1477,"tieuDe":"Ôn Lại Chuyện Xưa","tomTat":"Vương Lâm quỳ trước mộ cha mẹ tại Triệu Quốc, vuốt ve bia mộ rơi lệ, từ cơ thể phát ra ánh sáng và bên cạnh xuất hiện ba hư ảnh — nữ tử bên trái, thanh niên tướng mạo giống hắn cùng một nữ tử bên phải — cả bốn người quỳ trước mộ như gia đình đoàn tụ. Người điên bay tới gây náo loạn, trận pháp Triệu Quốc dao động, hơn mười tu sĩ đại thần thông trên Chu Tước Tinh bay tới và nhận ra Phong Tôn đã trở về, kinh hô xôn xao. Chu Vũ Thái — người đứng đầu Chu Tước Tinh — xuất hiện từ đám mây đỏ, hướng mộ vái rồi dùng thân phận xua hết tu sĩ rời đi. Hai người cùng uống rượu Tằng gia cất từ hơn ngàn năm trước, ôn lại chuyện cũ suốt đêm: Vân Tước Tử đã hết tuổi thọ mà chết, Chu Tử Hồng theo mẫu thân Phượng Tuý rời Chu Tước Tinh bái nhập tông phái ở Triệu Hà với đao lữ đã tử vong, Vân Thiên Tông thành chín đại tông môn nhưng cố nhân tứ tán, Tằng Ngưu được Chu Vũ Thái nhận làm đệ tử. Chu Vũ Thái tâm sự hâm mộ Vương Lâm dám rời đi, còn mình chỉ thủ hộ nơi đây hơn ngàn năm vì đã hứa bầu bạn đệ tử ý cảnh Hỏa Thần đã chết và mai táng trên Chu Tước Tinh. Khi trời vừa sáng, Chu Vũ Thái trong trạng thái hồn say bất ngờ nói ra: Hồng Điệp có thể vẫn chưa chết."},{"chuong":1478,"tieuDe":"Thanh Ti Hồn","tomTat":"Vương Lâm được Chu Vũ Thái dẫn tới xem một trận pháp bí ẩn trong động phủ pho tượng Chu Tước — Hồn Truyền Tống Trận, chứa đám tóc đen Hồng Điệp đóng trong hàn băng. Vương Lâm phân tích trận pháp và kết luận Hồng Điệp có thể chưa chết: phần hồn phách đã được truyền tống đi trước khi nàng bị mất mạng, có thể đã đoạt xá sống lại ở nơi nào đó trong tinh hải. Trận pháp cần tu sĩ Tịnh Niết hậu kỳ đại viên mãn mới bố trí nổi, nguồn gốc vẫn là bí ẩn. Chu Vũ Thái tiết lộ tu sĩ Tuyết Vực Quốc và Cự Ma tộc đều từ bên ngoài tới Chu Tước Tinh. Trước khi rời đi, Vương Lâm cho biết Liễu Mi đã chết, khiến Chu Vũ Thái khổ sở — lộ ra gần hai ngàn năm vẫn yêu Liễu Mi, uống rượu say cười trong bi ai. Vương Lâm trở về căn nhà cũ Triệu Quốc giữ đạo hiếu bảy ngày trước mộ phụ mẫu, người điên tỉnh dậy líu lo đoạt rượu hát hò. Ngày thứ tám, Vương Lâm dập đầu rồi một bước từ phàm nhân trở lại làm tu sĩ lãnh khốc, mang theo người điên bay thẳng tới mục tiêu cuối trên Chu Tước Tinh: tầng thứ mười chín hố sâu Phù Văn tộc."},{"chuong":1479,"tieuDe":"Bí Mật Tầng Mười Chín","tomTat":"Vương Lâm cùng người điên tới hố sâu Phù Văn tộc trên Chu Tước Tinh. Người điên từ chối xuống hố, muốn ở lại chơi đùa và đi tìm ba nương từ trước không cho hắn biết tên, rồi đắc ý bay đi. Vương Lâm một mình xuyên qua các tầng không gặp trở ngại, phong ấn tầng 16 tự sụp trước uy áp vô hình trên người hắn. Tới tầng 18 — thạch thất tối tăm đầy u hồn quỷ mị với ngọn lửa bổn nguyên lực hỗn tạp — hắn vuốt tan ngọn lửa, lộ ra cánh cửa hình tròn dẫn vào tầng 19 với phong ấn phù văn dày đặc tích luỹ vô số năm, lực phong ấn tổng hợp ngang Thiên Nhân đệ ngũ suy. Vương Lâm dùng kim quang phá toàn bộ phong ấn chỉ còn ký hiệu cuối cùng — một vòng tròn đơn giản chứa cả uy áp huyết mạch tiên nhân lẫn khí tức Đạo Cổ. Hắn nhận ra khí tức quen thuộc của Đạo Cổ Diệp Mịch, suy đoán vật bị phong ấn chính là mắt trái Đạo Cổ Diệp Mịch bị Lý Quảng bắn rơi năm xưa — mũi tên dính máu Lý Quảng khiến mắt trái mang cả hai khí tức bài xích nhau, Phù Văn tộc đã lợi dụng lực bài xích đó biến thành phong ấn, che giấu bí mật khỏi thiên hạ."},{"chuong":1480,"tieuDe":"Khởi Đầu","tomTat":"Vương Lâm nhận ra phong ấn tầng thứ mười chín của Phù Văn tộc là sự dung hợp giữa tiên lực và khí tức Đạo Cổ — chỉ người đồng thời mang cả hai mới mở được, tức chỉ mình hắn trong thiên địa đủ điều kiện. Hắn hồi tưởng chuỗi nhân duyên từ khi rời Chu Tước Tinh qua vùng Yêu Linh, La Thiên tinh vực, gặp U Minh thú, gặp người điên nhận huyết mạch tiên nhân — thiếu một mắt xích nào cũng không thể sở hữu lực bài xích để mở phong ấn này. Hắn dồn lực bài xích ra ngón trỏ, chịu đau đớn cực hạn vẽ lại ký hiệu vòng tròn trên cánh cửa đá trong khoảng một nén nhang rưỡi. Khi hoàn thành, phản lực bùng nổ phá vỡ Quang ảnh thuẫn và đẩy bật Thiên Hoàng Lô, đánh Vương Lâm lùi hơn mười trượng va vào vách tường nứt nẻ. Cánh cửa đá mở ra sau vạn năm phong ấn, Vương Lâm bước vào tầng 19 — bên trong là thông đạo kỳ dị do vòng tròn tiên lực và Đạo Cổ dung hợp tạo thành, tràn ngập khí tức tang thương và hơi thở ác liệt. Hắn tiến tới vòng tròn cuối cùng rộng mấy ngàn trượng, bước vào trung tâm và nhìn thấy thứ gì đó — chương kết thúc đột ngột."},{"chuong":1481,"tieuDe":"Nguyên Nhân","tomTat":"Vương Lâm tiến vào thiên địa bên trong phong ấn, thấy mũi tên dài mấy vạn trượng xuyên thấu bầu trời mắc kẹt một nửa trong lỗ thủng rộng mấy ngàn trượng, mặt đất là bình nguyên hoang tàn. Hàn khí từ mũi tên kích hoạt ký ức truyền thừa Đạo cổ ở mắt trái, mắt trái chảy máu, tiếng gào thét của Đạo cổ Diệp Mịch đòi trả mắt trái vang trong đầu. Vương Lâm phun máu, thổ nạp hồi phục rồi phân tích ra bản chất: trên đầu mũi tên có ấn ký hình tròn và vết máu khô từ mắt trái Đạo cổ là nguồn lực bài xích. Hắn ghép nối toàn bộ lai lịch: Lý Quảng bắn mũi tên rơi mắt trái Đạo cổ trong vùng đất cổ mộ, mũi tên bay xuyên tinh không phá tu chân tinh, mắt trái tách rơi vào tinh hải, mũi tên mắc kẹt ở thiên địa này, sát khí dung hợp máu mắt trái tạo cơn lốc hủy diệt toàn cảnh. Phù Văn Tộc tìm được nhưng không điều khiển được, phong ấn lại chờ Chưởng Tôn, nhưng Phù Văn Tộc bị Tứ Đại Tiên Giới đồ sát tan tác, một phần thành Tiên Di Tộc, chân tướng dần thành truyền thuyết. Chưởng Tôn từng vào giới nội lấy mũi tên nhưng bị tiếng rống trọng thương cuốn ra. Cuối cùng Vương Lâm ngồi lên mũi tên, dùng tinh điểm Cổ Thần hấp thụ vết máu chứa yêu khí cực đậm, đồng thời lấy pho tượng Cổ Yêu ra ấn tay vào."},{"chuong":1482,"tieuDe":"Vực Ngoại","tomTat":"Vương Lâm dùng mười ngày luyện hóa huyết dịch mắt trái Đạo cổ trên đầu mũi tên, chuyển cổ Yêu lực vào pho tượng cổ Yêu ở tay trái, ngưng tụ tinh điểm thứ sáu. Sau đó phá phong ấn cổ Yêu lấy từ Huyết Thần Tử, đập tan yêu tinh dồn yêu lực, ngưng tụ tinh điểm thứ bảy — giữ lời hứa năm xưa, lưu hồn phách cổ Yêu phong ấn cất giữ. Vương Lâm vận chuyển huyết mạch tiên lực hiện cung Lý Quảng trong cơ thể, cảm ứng linh hồn mũi tên khổng lồ, ra lệnh thu nhỏ nhiều lần và thu phục thành bảo vật. Hắn triệu Thiên Hoàng Lô lôi hồn Nam Chiếu Thượng Nhân và Thiên Triệu Thượng Sư ra gia tăng vào hai trong bốn ký hiệu trên mũi tên, rồi cân nhắc dùng ba thần hồn trong lầu các địa phủ Diệp Mịch cho hai ký hiệu còn lại nhưng quyết không thả vì thực lực chưa đủ. Cuối cùng thu mũi tên hóa bảy đạo kim quang nhập thất khiếu, quay về tầng 18 Phù Văn Tộc phong ấn cửa đá, phát hiện khe nứt trên vách tường thông sang chiến trường vực ngoại."},{"chuong":1483,"tieuDe":"Thiên Biến","tomTat":"Vương Lâm phá vách tường tầng thứ mười tám Phù Văn Tộc, phát hiện nó không nằm dưới lòng đất Chu Tước Tinh mà thông thẳng ra chiến trường vực ngoại — hắn đứng bên trong đầu một bộ xương thú hình rồng khổng lồ. Tản thần thức phá vỡ lớp màng ngăn cách, hắn khám phá phía bên ngoài là một chiến trường rộng lớn hơn nhiều lần, chứa hài cốt tiên nhân phát kim quang và xương mãnh thú to hàng vạn trượng, ngoại trừ U Minh Thú thì mọi loại mãnh thú hắn từng gặp đều có xương ở đây. Bao trùm toàn bộ bằng thần thức, hắn kinh hoàng nhận ra toàn bộ chiến trường vực ngoại là mảnh vỡ khổng lồ của một cánh cửa nối liền Chu Tước Tinh, xác nhận lời Lão Chu Tước trước khi chết và liên tưởng tới lời ngân y nữ tử. Ngồi trên đỉnh núi tổng kết phát hiện, hắn xác lập mục tiêu: luyện hóa lực bài xích, đại thành sinh tử, nhân quả, chân giả bổn nguyên, luyện sát lục bổn nguyên kiếm do Thanh Thủy tặng, dùng sáu đạo bổn nguyên chứng đạo phá Không Môn lên bước thứ ba. Khi chuẩn bị rời đi, đám mây đen kèm lôi đình cuồn cuộn ập tới, hắn nhận ra ba dấu hiệu dị thường trước đó và cảm giác nguy hiểm vượt xa mọi lần — gọi đó là Thiên biến, sinh tử đại kiếp phải gặp một lần trong đời giống như Hồng Điệp. Hắn lập tức tản thần thức bao trùm Chu Tước Tinh rồi đưa vào tinh không, thần sắc đột biến khi nhìn thấy tình hình."},{"chuong":1484,"tieuDe":"Sát Kiếp Của Phong Tôn","tomTat":"Tinh không bên ngoài Chu Tước Tinh bị tràn ngập lam quang, Vương Lâm bị tách ra khỏi Chu Tước Tinh thật vào không gian riêng biệt do toàn bộ cao thủ Không Huyền Thái Cổ Tinh Thần liên thủ cùng Viễn Cổ Tiên Phi bố trí. Lam Mộng Đạo Tôn hiện thân từ lam quang niệm tình cũ cảnh báo: vùng thiên địa tồn tại ba canh giờ, đây chính là sát kiếp mà Phong Tôn đời trước đã chết, và khẳng định bản thân không tham gia giết Phong Tôn. Ba cao thủ tu vi thật Không Huyền bị áp chế còn Không Linh Trung Kỳ liên thủ tấn công Vương Lâm: lão già áo xám phóng rồng xám hương hỏa hồn tạp, bà lão áo đen tập kích sau lưng, nam tử áo trắng dùng hàn kiếm đóng băng Quang Ảnh Thuẫn và cắt đứt Dịch Linh Ấn. Vương Lâm thi triển Hô Phong Thuật cực hạn mười ba hắc long kim quang đối kháng, rút huyết kiếm đánh vỡ đôi hàn kiếm, phun máu hai lần nhưng chiến ý bất khuất. Kim quang bí ẩn trong thần thông Vương Lâm khiến lão già áo xám mơ hồ sợ hãi. Vương Lâm tuyên bố không ai có thể quyết định vận mệnh của hắn, tái thi triển Dịch Linh Ấn chưởng ấn kim quang vạn trượng."},{"chuong":1485,"tieuDe":"Kịch Chiến","tomTat":"Vương Lâm dùng Dịch Linh Ấn phản kích ba cường giả giới ngoại nhưng bị ba người phối hợp Táng Linh, quỷ ảnh móng tay và huyết băng phá hủy hoàn toàn, trọng thương nặng. Ba người áp sát không cho uống đan dược, Vương Lâm triệu Thiên Hoàng Lô và Quang Ảnh Thuẫn phòng thủ nhưng cả hai đều bị phá nát trong tích tắc. Cổ Thần hộ tí bùng phát hóa hư ảnh khổng lồ hứng ba sát chiêu, tinh điểm nổ tung đánh lui ba người, cánh tay cuối cùng ôm Vương Lâm ném xuống nước rồi tiêu tán hoàn toàn. Vương Lâm từ đáy nước lao lên phản công liều mạng, dùng một quyền cùng đầu lâu đạo cổ bức lui nam tử bạch y, dùng tiên lôi đánh lão già áo xám, dùng lửa tiên lực đánh bà lão áo đen — cả ba phun máu lùi lại, hoảng sợ nhận ra Vương Lâm sở hữu tiên lực. Tranh thủ cơ hội, Vương Lâm thi triển Phần Giới Cổ Tán, bầu trời hóa cây ô khổng lồ màu lam, biển lửa bao phủ."},{"chuong":1486,"tieuDe":"Giết Một Người","tomTat":"Vương Lâm hiến tế sinh cơ toàn thân kích hoạt Phần Giới Cổ Tán, tạo biển lửa diệt thế bao phủ thiên địa. Ba hình chiếu Thái Cổ Tinh Thần hoảng sợ rút lui, nhận xét Phong Tôn đời này cũng khó giết như đời trước. Nam tử bạch y thi triển Băng Phong Vạn Cổ đóng băng cả thiên địa và Cổ tán, nhưng bị Vương Lâm phá vỡ. Vương Lâm điều khiển lửa giết hình chiếu bà lão hắc y, đánh trọng thương lão già áo xám khiến lão bóp nát ngọc giản thoát thân, và phong ấn nam tử bạch y. Tại lầu các trong Thái Cổ Tinh Thần, bổn tôn bà lão và lão già phun máu, một giọng nói già nua bí ẩn từ đại điện tuyên bố Vương Lâm vẫn chịu ràng buộc bởi mình. Khi Vương Lâm tiến tới định giết nam tử bạch y, một nữ tử bí ẩn từ hư vô bước ra thi triển Ngũ Tạng Tiên Đạo, phá hủy hai quả thận của Vương Lâm và nhắm tiếp vào phế, tỳ. Vương Lâm sinh cơ cạn kiệt, nội tạng bị phá mà Cổ thân không khôi phục nổi, nhưng sát khí vẫn đạt đỉnh điểm."},{"chuong":1487,"tieuDe":"Âm Nguyệt Hữu Tình","tomTat":"Nữ tử tiên phi hoàn tất Ngũ tạng kỳ thuật — phá hủy can tạng và tâm tạng Vương Lâm, ngũ tạng mất bốn, sinh cơ chặt đứt, Giới Cổ Tán tiêu tán. Vương Lâm thử ngọc giản truyền tống và triệu hoán U Minh thú đều thất bại do phong ấn, cương quyết không quỳ trước nữ tử. Hắn dung nhập tiên lực kim quang thi triển Hô Phong Hoán Vũ và Sơn Băng Địa Liệt dưới dạng tiên thuật để câu thời gian, rồi lần đầu thi triển Âm Nguyệt Hữu Tình — vầng trăng sáng xuất hiện trên mặt nữ tử, khe nứt lan từ mặt xuống cổ, hủy dung hoàn toàn. Nữ tử nhận ra đây là thần thông Âm Nguyệt Tông, tiết lộ Bạch Phàm từng là phản đồ. Vương Lâm dùng Cổ lực đối công, cánh tay phải vỡ nát nhưng đánh lùi nữ tử. Nữ tử biến ảo cổ cầm thi triển khúc Táng Hoàng Tuyền, tiếng đàn oanh kích tâm thần Vương Lâm khiến hắn lùi trăm trượng thất khiếu chảy máu. Một nữ tử tử y thân hư ảo vô thanh vô tức xuất hiện phía sau, gọi tiên phi là tỷ tỷ, dùng thuật bói thần tiên dự ngữ Vương Lâm ba nhịp thở tử vong."},{"chuong":1488,"tieuDe":"Tiên Nhân Bất Diệt Thể","tomTat":"Nữ tử Tiên Phi thứ hai thi triển thuật bói toán ba nhịp thở tấn công Vương Lâm, hủy thịt, nát xương và tấn công hồn phách, đẩy hắn đến cận tử. Vương Lâm vẫn kiên quyết giữ cây cung chờ Chưởng Tôn, vỗ mi tâm chuyển đổi từ thân Cổ Thần sang tiên thể, bộc lộ tiên nhân bất diệt thể chưa hoàn chỉnh — kim quang vạn trượng nhuộm vàng cả Chu Tước Tinh. Hai Tiên Phi kinh hoàng: nữ tử bói toán hét lên vạn tiên khấu bái, hỏi Vương Lâm có quan hệ gì với Tiên Hoàng, mất hết ý chí chiến đấu; nữ tử đánh đàn run tay nhưng cắn răng nhận định bất diệt thể chưa hoàn chỉnh, phóng chín thanh phi đao máu. Vương Lâm trong trạng thái thân thể liên tục tan vỡ rồi ngưng tụ, thi triển Tàn Dạ và Lưu Nguyệt dung hợp tiên lực phản công, phá phần lớn phi đao và khiến nữ tử bói toán phun máu. Ngay lúc đó Hư Thần Thiên Tôn — một trong Thái Cổ Ngũ Tôn — xuất hiện dưới dạng thân ảnh sương mù, đánh một chưởng vào hậu tâm Vương Lâm khiến hắn phun máu vàng bắn xuống Chu Tước Tinh. Hư Thần Thiên Tôn hút máu tiên nhân, tuyên bố phải đoạt thân thể bất diệt và huyết mạch tiên nhân, rồi hóa mây đuổi theo."},{"chuong":1489,"tieuDe":"Thiên Tôn Đoạt Xá","tomTat":"Thân thể Vương Lâm rơi như lưu tinh xuống Chu Tước Tinh (bản Tĩnh Trung Lao Nguyệt), phá ngọn núi xuyên tới tầng mười tám Phù Văn Tộc, thân thể bất diệt không ngừng tan vỡ rồi ngưng tụ. Hư Thần Thiên Tôn (một trong Thái Cổ Ngũ Tôn) bước ra từ lỗ hổng vách tường, hóa sương mù dung nhập vào thân thể đang tan vỡ để đoạt xá tiên thể, chiếm gần hết thân thể và bắt đầu xóa ký ức, Vương Lâm chỉ còn tay trái mơ hồ điều khiển được. Trong khoảnh khắc cuối cùng, Vương Lâm dùng tay trái bấm ấn ký triệu hồi vô số du hồn từ chiến trường vực ngoại — do Tĩnh Trung Lao Nguyệt không tạo được phép tắc ngăn cản nên du hồn lần đầu xông ra tự do, hình thành cơn lốc đen khổng lồ đẩy Hư Thần Thiên Tôn ra khỏi thân xác, đoạt xá thất bại. Cơn lốc du hồn khiến Chu Tước Tinh nổ tung. Sau khi thân thể ngưng tụ lại, Vương Lâm rút cung Lý Quảng giương mũi tên chứa hồn phách Nam Chiếu và Thiên Triệu, uy lực kinh hoàng khiến Hư Thần Thiên Tôn hoảng sợ lui lại, tuyên bố không tham gia nữa, hai Tiên Phi cũng run rẩy. Cả ba bóp ngọc giản muốn rời đi nhưng không có phản ứng, bị mắc kẹt đối mặt cung Lý Quảng."},{"chuong":1490,"tieuDe":"Uy Lực Của Một Tiễn","tomTat":"Vương Lâm bị bốn kẻ thù (nam tử áo trắng, hai Tiên Phi, Hư Thần Thiên Tôn) dồn vào đường chết, quyết định bắn mũi tên vốn dành cho Chưởng Tôn. Hắn dồn toàn bộ linh hồn, nguyên thần, sức mạnh Đạo Cổ và tiên huyết mạch vào một tiễn duy nhất, phản lực khiến thân thể chấn động, máu tràn, rơi xuống mặt nước. Mũi tên xuyên mi tâm nam tử áo trắng khiến hắn tan rã, phá vỡ cây đàn Tiên Tôn ban tặng rồi giết chết Tiên Phi Âm Nguyệt, nhưng xuyên qua Tiên Phi bói toán mà không gây thương tổn nhờ viên đá đen bảo hộ của Tiên Tôn — viên đá xuất hiện vết nứt. Hư Thần Thiên Tôn cố ngưng tụ sương mù nhưng vẫn bị mũi tên xuyên mi tâm tiêu tán, trước khi chết gào gọi Chưởng Tôn phải giải thích. Dư lực mũi tên lao về phía phong ấn bầu trời thì Chưởng Tôn xuất hiện từ trong tấm màn, mặc hắc bào, uy áp không bị giới hạn Không Linh Trung Kỳ, vươn cánh tay khô héo chụp lấy mũi tên. Chưởng Tôn tự xưng danh, nhắc lại hai lần gặp Vương Lâm trước đó ở mộ địa Đạo Cổ và Vân Hải tinh vực."},{"chuong":1491,"tieuDe":"Tiên, Cổ Phân","tomTat":"Chưởng Tôn — người đứng đầu Thái Cổ Ngũ Tôn — hiện thân sau khi Vương Lâm bắn mũi tên, xóa tan mũi tên bằng tay rồi tiết lộ toàn bộ nơi sát kiếp là một hồi Tĩnh Trung Lao Nguyệt do hắn bố trí, thứ mò ra chính là Chu Tước Tinh và Vương Lâm. Chưởng Tôn triệu mặt trời dùng bổn nguyên thái sơ quy tắc phóng cột sáng bao phủ Vương Lâm, thiêu hủy toàn bộ du hồn và tách hoàn toàn huyết mạch tiên nhân khỏi cơ thể, ngưng tụ thành giọt máu tỏa kim quang vạn trượng chứa nửa ký hiệu tiên nhân bất diệt thể. Vương Lâm chịu đau cực hạn nhưng vẫn giấu chiêu sát thủ: khi Chưởng Tôn định đoạt giọt máu, hắn cắn lưỡi phun máu Đạo Cổ mở một cửa sổ Hắc Tháp giải phong ấn Xích Hồn Tử — linh hồn cực mạnh bị Diệp Mịch giam vô số năm. Xích Hồn Tử được giải phóng, huyết ảnh va vào Chưởng Tôn đẩy lùi hơn mười trượng, nhưng không đánh Chưởng Tôn mà lao nuốt Tiên Phi khiến nàng tan chảy biến mất rồi phá bầu trời bay đi. Mũi tên tuy bị xóa tan vẫn theo phương thức kỳ dị quay về trong hồn Vương Lâm. Ở giới nội trên Chu Tước Tinh thực sự, người điên ngồi giữa đám ăn mày chợt cảm ứng, tức giận vì Vương Lâm bỏ mặc và quyết đi tìm hắn."},{"chuong":1492,"tieuDe":"Ân Đoạn","tomTat":"Xích Hồn Tử cười điên cuồng phá tan phong ấn Tĩnh Trung Lao Nguyệt của Chưởng Tôn, tạo lỗ thủng lớn trên thiên địa rồi tuyên bố ân oán với Vương Lâm triệt tiêu, rời đi tự do. Chưởng Tôn bị bức lui, bản thể ở đại điện Thái cổ Tinh Thần phun hai ngụm máu tươi, mất cơ hội đoạt huyết dịch tiên thể. Vương Lâm thoát giam cầm, nắm lấy huyết dịch tiên nhân bất diệt thể — Thái sơ lực và Tĩnh Trung Lao Nguyệt của Chưởng Tôn vô tình tách cổ lực và tiên lực, hóa giải nguy cơ bài xích chí mạng, thân thể trở về thuần Cổ Thần, ngũ tạng tái sinh. Vương Lâm quyết định luyện hóa huyết dịch thành pháp bảo tiên thể thay vì dung hợp trực tiếp. Phong ấn vỡ, khí tức bộc phát ra ngoài — Hồng Sam Tử, sư phụ Trọng Huyền Tử, Thanh Lâm, Nam Vân Tử, Thanh Thủy, Chiến lão quỷ và nhiều tu sĩ bước thứ ba từ khắp nơi đều cảm ứng, lao về Côn Hư. Vương Lâm lao vào lỗ thủng định thoát nhưng Chưởng Tôn gọi Lam Mộng thực hiện ước định, Lam Mộng thở dài xuất thủ dùng lam quang chặn lỗ thủng bắn ngược Vương Lâm — ân nghĩa giữa hai người nhất đao lưỡng đoạn. Chưởng Tôn ngưng tụ ánh sáng bảy màu thành cây trường thương khổng lồ mang khí tức hủy thiên diệt địa ném về phía Vương Lâm — cây thương tử vong."},{"chuong":1493,"tieuDe":"Sinh Tử","tomTat":"Thất Thải Thương lao tới với sức mạnh hủy thiên diệt địa, Vương Lâm biết không thể tránh, chấp nhận cái chết. Lồng ngực vỡ tung, huyết nhục bị xé, hắn buông xuôi nói lời từ biệt cha mẹ, xin lỗi Lý Mộ Uyển và Bình Nhi, hồi tưởng ba cảnh ấm áp nhất đời. Người điên đột ngột xuất hiện từ lam quang, tay cầm đùi gà ăn dở, thân phát kim quang nồng đậm. Chưởng Tôn kinh hãi tột cùng gọi hắn là Chủ, hồn phi phách tán. Người điên phát tiếng rống kinh thiên lao vào ánh sáng bảy màu ôm lấy Vương Lâm, chịu bảy lần bạo phát khiến tiên nhân bất diệt thể hoàn chỉnh cũng tan vỡ liên tục; vùng thiên địa phong tỏa tan hoàn toàn, tinh không bị xé tạo hắc động, cả hai bị hút vào biến mất. Chưởng Tôn lẩm bẩm khẳng định tiên nhân bất diệt thể do người điên truyền cho Vương Lâm, tự an ủi hắn sẽ không nhận ra ta rồi tiêu tán, liền bị Chiến lão quỷ xuất hiện bất ngờ điểm một chỉ đánh tan vỡ biến mất. Chiến lão quỷ nhìn hắc động suy tư, tiếc nuối máu tiên thể, nghi ngờ người điên là người trong ký ức kia, nhận xét hắc động tỏa khí tức tầng phủ bích rồi trầm mặc rời đi."},{"chuong":1494,"tieuDe":"Mộng Tiên Hay Là Tiên Mộng","tomTat":"Hạt bụi nơi Vương Lâm gặp sát kiếp vỡ vụn trong tinh không Chu Tước Tinh. Hồng Sam Tử, Nam Vân Tử và Thanh Lâm lần lượt xuất hiện quét thần thức nhưng không tìm thấy khí tức Vương Lâm, tin rằng hắn lành ít dữ nhiều. Thanh Thủy biến đổi khuôn mặt thành hình dạng Vương Lâm, tuyên bố bế quan thay trên đài chiến Vân Hải tinh vực, trở thành biểu tượng cho giới nội và thề báo thù cho sư đệ. Thập Tam quỳ dập đầu trước pho tượng Vương Lâm thề công khai danh phận đệ tử; Chu Như cùng Lão Hồ đến khóc gọi thúc thúc; Hứa Mộc cầm rượu khóc rống ân hận đã chỉ dẫn Vương Lâm tu đạo và lấy đi Thiên Nghịch; Mộc Băng Mi đứng ngây rồi yên lặng rời đi hai giọt lệ rơi; một nữ tử áo hồng nhạt bí ẩn nói thiếp biết chàng. Trong hư vô, Vương Lâm thân thể tan nát cùng người điên nằm trong vầng sáng do giọt máu vàng tạo thành. Hắn gắng tỉnh dậy nuốt ba Thăng Tiên Quả lấy đạo niệm, nắm tay người điên liên kết, rồi thi triển thần thông thứ ba Mộng Đạo trên bản thân — mộng về ngàn năm trước để ba đạo bổn nguyên sinh tử, nhân quả, thật giả đại thành. Cảnh chuyển sang nhà trọ bên đường, Vương Lâm hóa thành thanh niên thư sinh say rượu, ngâm thơ rồi nói vừa mơ thấy bản thân thành tiên."},{"chuong":1495,"tieuDe":"Mộng Như Nhân Sinh","tomTat":"Toàn bộ chương diễn ra trong một thực tại mà Vương Lâm là thư sinh phàm nhân mười tám mười chín tuổi, quê ở sơn thôn vùng rừng núi thuộc Triệu quốc, lần đầu rời nhà vào kinh ứng thí. Tại nhà trọ bên quan đạo, hắn tỉnh dậy sau cơn say rượu chỉ hai chén, tiểu nhị kể đêm qua hắn say nói về giấc mộng thành tiên. Hắn nhớ rõ ba năm trước tứ thúc đến, hắn gia nhập Hằng Nhạc phái, nhưng chỉ nhớ tới đoạn gia nhập, phần sau hoàn toàn trống. Hắn thử thi triển Dẫn Lực Thuật theo ấn quyết trong trí nhớ mộng nhưng chén trà không nhúc nhích, xác nhận hoàn toàn là phàm nhân. Hắn tự nhủ không tin quỷ thần, sửa soạn hành trang lên đường vào kinh, mang chí nguyện đỗ đạt bảng vàng rồi đón cha mẹ rời sơn thôn. Chiều tối gặp mưa, hắn đứng dưới gốc cây ngắm cảnh ngâm thơ, bị một cô gái xinh xắn trên đầu thuyền gần bờ mắng là thư sinh ngốc, hắn sửng sốt gãi đầu."},{"chuong":1496,"tieuDe":"Vẫn Chưa Tỉnh Lại","tomTat":"Vương Lâm trong thân phận thư sinh phàm nhân (mộng cảnh, vẫn chưa tỉnh lại) lần đầu ra khỏi thôn, trú mưa bên bờ sông và gặp hai nữ tu sĩ Hằng Nhạc Phái: thiếu nữ áo xanh Từ Phi cầm ô trên thuyền trêu hắn là tiểu tử ngốc, và sư tỷ Chu Nhị — nữ tử áo tím dung nhan tuyệt sắc vén rèm lộ diện. Chu Nhị nhìn Vương Lâm liền ngẩn ra, nói đã gặp ở đâu rồi, dùng thân pháp đỡ hắn lên thuyền khi trượt chân. Cả hai nữ tử đều cảm thấy tên Vương Lâm vô cùng quen thuộc nhưng không thể nhớ ra. Chu Nhị thi triển pháp thuật khiến Vương Lâm dần buồn ngủ rồi ngủ say, khẳng định nhất định đã từng gặp người này, cuối cùng đoán có lẽ gặp từ kiếp trước. Từ Phi nhắc sư tỷ cần tụ họp với đám Vương Trác, tiết lộ chưởng môn phát hiện phía đông có kim quang tràn ngập, tính toán có dị bảo xuất hiện, nhiều môn phái khác cũng sẽ tìm kiếm."},{"chuong":1497,"tieuDe":"Nhân Sinh Như Trò Đùa, Ta Là Ai?","tomTat":"Nữ tử áo tím trước khi rời thuyền do dự quay lại, lấy áo khoác dày đắp lên người Vương Lâm đang ngủ, thì thầm nói về kiếp trước rồi than nhẹ rời khỏi. Vương Lâm ngủ say trong mưa, mộng thấy mình quay về Hằng Nhạc Phái, gọi tên Từ Phi, Chu sư tỷ, Vương Trác, Vương Hạo, Trương Hổ. Sáng tỉnh dậy thấy hai nữ tử đã đi, chiếc áo khoác trên người xác nhận đêm qua không phải ảo giác. Đứng đầu thuyền nhìn thiên địa u ám, cảm giác cô độc tịch mịch tràn ngập, nước mắt tự rơi, mơ hồ nhìn thấy ảo ảnh vực sâu vạn trượng với thân ảnh cô độc và thanh niên áo trắng tóc trắng đi trong tinh không — hình ảnh kiếp tu tiên của bản thân. Vô thức giơ tay chỉ ngọn đèn khiến nó tự bốc cháy mà không hay biết. Con chim bi ai từ trong núi bay lướt qua, khi nó rời đi thì nỗi bi ai tiêu tan, ngọn đèn tắt. Thu hành trang xuống thuyền lên đường. Hai tu sĩ bay bằng cầu vồng xuất hiện, nữ tử áo lam dừng lại nhìn Vương Lâm mê man, nói hình như đã gặp ở đâu, thanh niên anh tuấn nhận định hắn chỉ là phàm nhân, thúc giục đi tụ họp sư môn tới nơi phát ra kim quang."},{"chuong":1498,"tieuDe":"Cổ Miếu Dạ Vũ Quy Hồn Lai","tomTat":"Vương Lâm chấn động mạnh sau khi chứng kiến nữ tử bay qua trời, cảm thấy thân ảnh nàng quen thuộc như đã tồn tại trong tâm trí từ vô số năm tháng, nỗi đau đớn khó hiểu dâng trào. Hắn bắt đầu nghi ngờ ranh giới giữa mộng và thực, tự hỏi mình mơ thành tiên nhân hay tiên nhân mơ thành mình. Suốt bảy ngày hành trình cô độc trên quan đạo tới kinh thành, thân thể phàm nhân từ yếu ớt dần rắn chắc, ban đêm trong bóng tối hắn không hề sợ hãi mà trái tim bình lặng như nước. Ngày thứ tám gặp mưa bão lớn, hắn trú vào miếu thổ địa bỏ hoang có mấy bộ xương trắng trong sân và pho tượng thổ địa phai màu. Một nam tử trung niên quần áo tả tơi chạy vào miếu, vừa khóc vừa cười lẩm bẩm hỏi mình là ai, rõ ràng là người mất trí. Vương Lâm thương xót người điên rồi thì thào suy tư về mộng tựa nhân sinh, nhân sinh là luân hồi hay nhân quả và khi nào mới tỉnh, đánh dấu bước tiến quan trọng trong quá trình ngộ đạo Toái Niết."},{"chuong":1499,"tieuDe":"Quay Đầu Nhìn Lại Luân Hồi Tại","tomTat":"Vương Lâm trong trạng thái Mộng Đạo (thân phận thư sinh) trú mưa qua đêm tại miếu hoang cùng nam tử trung niên điên, chia sẻ lương khô và trò chuyện suốt đêm. Người điên vô thức buột miệng xưng bổn vương và nhắc tới linh thạch nhưng không hiểu vì sao mình nói vậy, kể rằng khi tỉnh lại bốn phía có kim quang và nhiều người truy bắt. Hắn khoe bí mật dấu tay trên cổ tay phải, ban ngày không ai thấy nhưng trong bóng tối phát kim quang mờ hiện hình dấu tay, và mơ hồ nhớ có người hứa chăm sóc nhưng đã bỏ đi. Vương Lâm thổ lộ lý tưởng vào kinh ứng thí vì cha mẹ, đồng thời bộc lộ nỗi hoang mang không phân biệt nổi mộng và thực. Nhờ lời người điên rằng chỉ cần vui vẻ là đủ, Vương Lâm dần ngộ ra: dù nhân sinh là giấc mộng thì hắn cũng muốn sống kiên định, coi đây là một cuộc đời khác của mình. Trong đêm tối khi lửa tắt, hắn phát hiện dấu tay kim quang trên cổ tay người điên, cảm giác vô cùng quen thuộc nhưng không nhận ra. Sáng hôm sau Vương Lâm không nỡ bỏ lại, quay đầu nhận người điên làm thư đồng — hành vi này chính là luân hồi lặp lại chuyện cũ ở Nhân phương giới vùng đất Điên Lạc, nơi hắn từng có quản gia và thư đồng bên cạnh cuộc sống khác của mình."},{"chuong":1500,"tieuDe":"Người Của Luyện Hồn Tông","tomTat":"Vương Lâm trong kiếp luân hồi mang thân phận thư sinh, cùng thư đồng Đại Phúc đi trên quan đạo hướng tới huyện thành ứng thí. Triệu quốc có 49 huyện thành, thư sinh phải qua ba lần khảo thí mới thành danh. Hai người tới huyện thành trong mưa, tìm nhà trọ khó khăn, Đại Phúc lẩm bẩm về ký ức mơ hồ kiếp trước khi trả tiền phòng. Đêm bão lớn, Vương Lâm nhìn thấy cánh chim trắng từng hiện trong giấc mộng bay tới đậu trước cửa sổ, trong đầu vang tiếng nói mê mang về nhân quả. Sấm sét quấy rầy, Vương Lâm theo tiềm thức điểm một chỉ, mắt phải lóe ấn ký hình tia chớp, ý chí như quân vương lôi điện khiến toàn bộ sấm sét mây mưa Triệu quốc ngừng hẳn trong nháy mắt. Khí tức chấn động mọi tu sĩ trong Triệu quốc: nhóm Vương Trác Hằng Nhạc Phái hoảng sợ, Liễu Mi tái nhợt mê mang, Đằng Hóa Nguyên hãi hùng, Hoàng Long Chân Nhân tính toán tay rung máu túa. Trên Chu Tước Tinh, tại Luyện Hồn Tông — tông phái đủ quét ngang tu chân quốc cấp năm — sư huynh Độn Thiên đã tính toán 37 lần cả đời đều thất bại, than thở tông phái không còn hi vọng."},{"chuong":1501,"tieuDe":"Quả Của Luyện Hồn Tông","tomTat":"Nam tử trung niên hắc bào — sư huynh Độn Thiên tại Luyện Hồn tông — đang tuyệt vọng vì tông phái không thể quật khởi thì đột nhiên phát hiện dấu hiệu lạ, bắt quyết tính toán chín lần đều ra kết quả một, kinh ngạc tiêu hao thọ nguyên dùng thuật Na Di phóng về Triệu quốc. Tại huyện thành, Vương Lâm suốt đêm trầm tư vì tiếng nói về nhân quả vang vọng trong đầu, mi tâm mơ hồ đau nhức. Năm ngày sau, kỳ thi diễn ra, đề bài là bức tranh ẩn ý đống lương chi tài, hầu hết thí sinh đều viết theo hướng này. Vương Lâm ngồi cả ngày không hạ bút, gần hết giờ mới bừng tỉnh viết bài luận riêng biệt về nhân quả. Các giám quan cười nhạo bỏ đi, riêng vị giám quan già đọc kỹ, kinh ngạc đánh giá Vương Lâm sẽ thành đại nho một đời và khoanh tròn tên hắn. Rời trường thi, Vương Lâm thấy Đại Phúc ngủ khò dưới gốc cây, chưa kịp gọi thì thiên địa tối sầm, hắc phong giáng xuống bao phủ cả hai. Trong hắc phong hiện ra sư huynh Độn Thiên, nói sẽ không làm tổn thương mà chỉ cần hỏi một vấn đề — hóa ra mấy ngày qua hắn đã hỏi từng thư sinh rồi xóa trí nhớ, thất vọng đi tìm người tiếp theo."},{"chuong":1502,"tieuDe":"Một Câu Nói Mấy Trăm Năm Trước","tomTat":"Niệm Thiên — tông chủ Luyện Hồn tông cảnh giới Anh Biến, sư huynh Độn Thiên — hao phí rất nhiều thọ nguyên và sinh cơ tính toán chín lần tìm con đường thông thiên cho tông phái, chín lần đều chỉ về một thư sinh ở Triệu quốc. Hắn tới huyện thành tìm kiếm mấy ngày, cuối cùng gặp Vương Lâm. Vung tay áo tạo hắc phong và âm hồn thị uy nhưng Vương Lâm hoàn toàn bình tĩnh, Niệm Thiên nhận ra hắn có khí tức đại nho hiếm có. Vương Lâm yêu cầu được đưa tới Luyện Hồn tông, đi khắp sơn môn với cảm giác quen thuộc mãnh liệt như đã từng ở đây. Khi nhìn thấy Độn Thiên xuất hiện trên chủ phong, trong đầu Vương Lâm ầm ầm nổ vang, mơ hồ nhớ ra điều gì đó, hai hàng nước mắt chảy xuống. Hắn thì thào nói ra lời tiên tri: mấy trăm năm sau ngày Độn Thiên tọa hóa tử vong sẽ có người tới, đó chính là thông thiên lộ của Luyện Hồn tông. Niệm Thiên chấn động ghi tạc lời này, cả đời không nói với Độn Thiên, mãi mấy trăm năm sau khi đại hạn phủ lưu di ngôn mới nhớ lại."},{"chuong":1503,"tieuDe":"Một Lần Ước Hẹn","tomTat":"Niệm Thiên thọ nguyên cạn kiệt, nhớ lại lời nho sinh mấy trăm năm trước, thần thức khuếch tán khắp Luyện Hồn tông và kinh hãi phát hiện nho sinh đó đang có mặt trong đám người bái nhập. Nguyên Anh hắn dấn thân vào Luyện Hồn Phiên trở thành chủ hồn đại phiên, mang theo mê mang không lời giải. Vương Lâm bị đưa trở về huyện thành Triệu quốc, lĩnh ngộ nhân quả, nhìn cánh chim trắng biến mất trong mây. Hắn đậu tú tài nhưng hoàn toàn bình thản, tâm tính biến đổi sâu sắc — không còn ý niệm được mất, khí tức đại nho bừng lên, tâm như nước lặng trong giếng cổ. Rời huyện thành cùng Đại Phúc, hai tháng đi đường uống rượu ngắm cảnh, tửu lượng tiến bộ, khí chất chuyển từ thư sinh sang hào hiệp. Tới Tô thành — thành phố lớn nổi tiếng nhờ đại nho Tô Đạo và Quế Hoa Tửu — Vương Lâm đứng trên đầu cầu nói đang chờ một người trong mộng sẽ đến tặng bầu rượu, nếu xuất hiện sẽ ấn chứng suy đoán của hắn về nhân quả."},{"chuong":1504,"tieuDe":"Tô Đạo","tomTat":"Tô thành tháng sáu, tơ liễu tung bay như tuyết, hoa đào rơi xuống mặt sông. Vương Lâm giả dạng công tử bạch y thuê họa thuyền cùng thư đồng Đại Phúc trôi trên sông hơn một tháng, uống rượu ngâm thơ, chờ đợi cảnh tượng trong mộng — trên cầu đá sẽ xuất hiện một con người khác của mình. Hắn chê tiếng đàn của nữ tử trên thuyền rồi tự tay gảy khúc đàn bi ai mà năm xưa Lý Mộ Uyển từng đàn, nước mắt chảy ra rơi lên dây đàn. Họa thuyền trôi qua cầu đá, trên cầu đứng hai lão giả tóc bạc: đại văn hào Tô Đạo và đệ tử Tô Tam — chính là lão già trường thi từng đọc bài thi Vương Lâm cho tới cuối cùng. Tô Đạo khen khúc đàn bi hồn tuyệt vời rồi hai lần hỏi Vương Lâm nhân quả là gì. Vương Lâm mê mang vì không gặp người trong mộng mà gặp lão già, đáp rằng ta là nhân, ta chính là quả. Tô Đạo mỉm cười, quay lại hỏi đệ tử tên chàng thiếu niên."},{"chuong":1505,"tieuDe":"Mười Năm","tomTat":"Tô Tam mang bài thi của Vương Lâm tới cho đại nho Tô Đạo, Tô Đạo tuyên bố đây là môn sinh cuối cùng muốn nhận. Vương Lâm rời họa thuyền cùng Đại Phúc, nhìn thấy cánh chim trắng quen thuộc hạ xuống cầu đá nhìn hắn rồi biến mất trong mây, thì thào nhận ra nó. Được mời vào phủ Tô Đạo, Vương Lâm nhận ra lão già từng hỏi mình trên cầu chính là đại nho; một già một trẻ uống Quế Hoa tửu đàm luận suốt đêm về đạo lý thiên địa, nho sinh và tu tiên. Tô Đạo truyền dạy tư tưởng nhân quả — ngộ ra từ cái chết của thê tử năm 50 tuổi, tiết lộ nhiều tu sĩ muốn đạt Hóa Thần từng tìm đến hỏi đạo. Vương Lâm vái lạy nhận sư khi 19 tuổi, từ bỏ khoa cử, ở lại phủ mười năm truy tìm câu hỏi nhân quả. Khí tức đại nho ngày càng nồng đậm, danh tiếng vượt qua các Tô cử, thay mặt sư phụ tiếp mọi người. Mười năm sau, Tô Đạo già yếu luận rằng tơ liễu là nhân sinh là nhân quả, nhớ lại lần đầu gặp Vương Lâm trên cầu — thấy hắn như tơ liễu không gốc rễ mê mang, nói hắn là nhân quả cuối cùng trong đời mình. Vương Lâm hình như nhìn thấy hai đám tơ liễu cuốn lấy nhau, bên tai vọng tới tiếng đàn mất mát giống nữ tử cô độc chờ đợi."},{"chuong":1506,"tieuDe":"Thư Nhà","tomTat":"Mười năm trôi qua, Tô Đạo hết thọ qua đời vào mùa đông ba năm trước. Vương Lâm đẩy xe đưa ông lên đỉnh Tô sơn, chứng kiến ông áp mặt vào bia mộ vợ mỉm cười nhắm mắt tắt thở, rồi chôn cất bên cạnh. Trước khi chết Tô Đạo dặn dò chỉ Vương Lâm mới có tư tưởng tương đương và tặng phủ đệ cho hắn. Ba năm sau cái chết của Tô Đạo, tiếng dèm pha Vương Lâm không xứng đại nho lan khắp Triệu quốc, hai trong ba môn sinh cũ cũng lên tiếng nghi ngờ, hoàng đế gửi chín đạo thánh chỉ mời làm đế sư đều bị từ chối. Tiếng đồn lan tới sơn thôn khiến phụ thân Vương Lâm lâm bệnh, mẹ hắn nhờ người viết thư gửi tới. Đọc thư, Vương Lâm lần đầu nổi giận vì cha mẹ là điều hắn không thể dung thứ ai xúc phạm, tuyên bố giảng học mười năm đón thiên hạ tới Tô thành luận học. Đại Phúc hưng phấn đi sắp xếp truyền tin."},{"chuong":1507,"tieuDe":"Ngươi Dám","tomTat":"Bốn tháng sau khi Vương Lâm tuyên bố giảng học mười năm tại phủ Tô Đạo ở Tô thành, tin tức lan khắp Triệu quốc, hoàng đế âm thầm thôi động văn sinh đổ về chất vấn. Hơn ngàn người tụ tập, Vương Lâm bình thản lần lượt đối đáp về sinh lão bệnh tử, ý nghĩa mưa, tiên nhân đối phàm nhân, nhân quả — câu đáp về mưa khiến nhiều danh sĩ cảm phục vái lạy. Tô Nhất (đệ nhất môn sinh Tô Đạo, nay là văn thần đương triều) chất vấn Vương Lâm có thực sự coi tiên nhân như kiến hôi được không. Vương Lâm đáp có gì không thể, lập tức một thanh niên đạo bào (tu sĩ hầu cận nam tử trung niên hoa phục bí ẩn ở tửu lâu đối diện) hóa cầu vồng cầm kiếm lao tới phán tội chết. Vương Lâm không chút sợ hãi, ngửa mặt gầm một tiếng, bộc phát luồng khí mênh mông kèm vô số lôi đình gào thét, phong vân biến sắc, uy áp bao phủ thiên địa, khiến nam tử hoa phục tái nhợt và tu sĩ còn lại sợ hãi khôn cùng."},{"chuong":1508,"tieuDe":"Nhà Dưới Hằng Nhạc Sơn","tomTat":"Vương Lâm một tiếng quát phát ra uy áp chính khí mênh mông khiến hai tu sĩ Trúc Cơ phun máu kinh hồn, phi kiếm rơi xuống đất, cả hai cung kính xin rời Tô thành vĩnh viễn. Toàn bộ văn sinh và lão giả quỳ bái kiến, tôn Vương Lâm làm đại nho Triệu quốc, hoàn toàn thay thế sư tôn Tô Đạo, trở thành đại nho khiến tiên nhân khiếp sợ chưa từng có trong lịch sử. Tám năm nữa trôi qua, tổng cộng hai mươi tám năm ở Tô thành, Vương Lâm từ bốn mươi thành năm mươi tuổi, tóc gần nửa bạc, mỗi tháng vài ngày ngồi họa thuyền uống Quế Hoa tửu chờ người hẹn ước nhưng không ai tới. Hắn gặp lại Chu Nhị và Từ Phi trên sông, nhận ra nữ tử họ Chu là người duy nhất cả đời khiến mình động tâm, vẫn giữ tấm áo khoác nàng tặng hơn hai mươi năm trước. Hai thuyền lướt qua nhau rồi xa dần, Chu Nhị quay đầu nhìn nhưng không nhận ra hắn. Cuối cùng Vương Lâm quyết định không đợi nữa, cùng Đại Phúc lên xe ngựa rời Tô thành về nhà dưới chân Hằng Nhạc Sơn."},{"chuong":1509,"tieuDe":"Hoài Trung Lão Phụ Minh","tomTat":"Vương Lâm cùng Đại Phúc rời Tô thành bằng xe ngựa hướng về quê hương. Chu Nhị và Từ Phi rời họa thuyền, biết được ông lão trên thuyền ban ngày chính là đại nho Vương Lâm, Chu Nhị bay lên trời tìm hắn khắp Tô thành nhưng bất thành. Sau bốn tháng hành trình, Vương Lâm về tới sơn thôn Hằng Nhạc Sơn, quỳ trước cha mẹ già yếu, hứa ở lại hầu hạ tới hết đời. Thân thích Vương gia và quan viên đến bái kiến vị đại nho Triệu quốc, phụ thân đắc ý tổ chức tiệc rượu lớn. Năm năm sau, phụ thân lâm chung trên giường, nhắc lại đã nhờ người chỉnh sửa lời con thành sách, trong nụ cười tự hào có sự sợ hãi tử vong. Vương Lâm ôm cha an ủi, phụ thân dần buông bỏ sợ hãi, nhắm mắt ra đi trong lòng con trai. Chiếc lá cuối cùng trên cây đại thụ trăm năm rơi xuống rồi bay theo gió về phía xa."},{"chuong":1510,"tieuDe":"Liễu Mi, Mi Nghĩa Là Lông Mày","tomTat":"Sau khi phụ thân qua đời, mẫu thân Vương Lâm cũng mất trong giấc ngủ với nụ cười hạnh phúc. Vương Lâm giữ mộ cha mẹ ba năm, tóc bạc trắng, lưng còng, đã gần sáu mươi tuổi. Hắn nhận ra còn thiếu một tia cảm ngộ đối với thiên địa, từ biệt Đại Phúc già nua, nhờ ông trông coi nhà cửa rồi một mình rời sơn thôn bằng xe ngựa. Mấy tháng sau tới biên giới Triệu quốc, lần đầu tiên trong kiếp mộng rời khỏi đất nước. Ngay lúc bước qua biên giới, Liễu Mi cưỡi cầu vồng cùng nhóm tu sĩ bay qua, nhận ra Vương Lâm liền tự ý bay xuống gặp. Nàng nói đã gặp hắn mấy chục năm trước, nay lần thứ hai vẫn cảm thấy quen thuộc đau lòng bí ẩn — không phải từ hai lần gặp này mà từ đâu đó xa hơn. Nàng tặng hắn viên đan dược bảo trì tinh lực rồi cưỡi mây bay đi. Khi nàng đã xa, Vương Lâm dùng hết khí lực hét vọng theo: dù kiếp sau, luân hồi hay mộng, đừng bao giờ quen biết tu sĩ tên Vương Lâm — bản ngã tu sĩ xuyên qua lớp mộng phàm nhân."},{"chuong":1511,"tieuDe":"Khách Đến Từ Tuyết Vực","tomTat":"Vương Lâm nuốt viên đan dược nhận vô tận tinh lực, rồi một mình chu du Chu Tước Tinh suốt mười lăm năm dưới thân phận phàm nhân. Hắn đi qua vô số quốc gia, gặp hoàng đế các nước, giáo hóa dân chúng, bước vào tông phái tu chân đàm luận với tu sĩ, giúp người có cơ hội Hóa Thần. Danh tiếng đại nho Vương Lâm truyền khắp Chu Tước Tinh cả phàm lẫn tu chân giới. Vẻ ngoài già nua bảy mươi tuổi, lưng còng nhưng đôi mắt sáng ngời, khí chất vượt cả sư phụ Tô Đạo năm xưa, ẩn chứa nhân quả, sinh tử, thật giả. Sau mười hai năm, hắn đến đô thành từng thấy trong mộng, gặp gia đình thợ rèn, nhìn bé trai giống Đại Ngưu nhưng không phải, uống rượu không phân biệt được mộng hay thực. Năm thứ mười lăm, hắn đứng trong mái đình nhìn mưa, muốn vượt biển sang nơi có nữ tử trong mộng. Lúc này một nữ tử trung niên ôm đứa trẻ bước tới trong mưa, toàn thân tỏa hàn ý vô tận khiến nước mưa đóng băng, tự xưng tới từ Tuyết Vực quốc để tìm Vương Lâm hỏi chuyện."},{"chuong":1512,"tieuDe":"Lý Mộ Uyển","tomTat":"Nữ tử Tuyết Vực lạnh như băng tìm tới Vương Lâm (đại nho nổi tiếng Chu Tước Tinh), ôm theo đứa bé gái nhặt được trong tuyết — cha mẹ mất lúc sinh, thiên tư cực cao với khí tức ngũ hành trong người, nhưng mệnh số mang đại kiếp sinh tử, bị nữ tử dùng thần thông hạn chế lớn lên. Vương Lâm ôm đứa bé, cảm nhận luồng khí tức quen thuộc, nhìn con bướm trú mưa dưới lá mà đặt tên nó là Hồng Điệp. Hắn dùng nước mưa vẽ lên bàn đá một trận pháp cực kỳ thâm áo từ ký ức trong mộng, dặn nữ tử lấy tóc bé đặt vào trong để hóa giải kiếp nạn. Năm thứ mười lăm rời Triệu quốc, Vương Lâm chu du tới vùng ven biển, lên thương thuyền vượt đại dương năm tháng. Trên biển xuất hiện hải thị thận lâu — huyễn cảnh ngọn núi lửa bộc phát, thủy thủ quỳ lạy cầu khẩn hải linh, Vương Lâm nhận ra đây là hiện tượng Thận trong sách cổ. Trong huyễn cảnh từ mây đen bước ra nữ tử bạch y ôn nhu như tiên tử chỉ tay dập tắt núi lửa — Vương Lâm nhận ra là Lý Mộ Uyển, toàn thân ngây dại, hai hàng nước mắt trào ra, dựa vào mạn thuyền nhìn nàng không rời."},{"chuong":1513,"tieuDe":"Một Ánh Mắt","tomTat":"Hình ảnh hư ảo trên biển biến mất, Vương Lâm tựa vách thuyền rơi lệ nhớ bóng áo trắng. Chín tháng sau, thương thuyền gặp bão biển nộ hải dữ dội, sấm sét ầm vang, sóng cuồn cuộn. Vương Lâm đứng giữa bão cảm ngộ vạn tượng vô tình là đạo lý chân chính, trái tim mở rộng đủ dung nạp thiên địa. Các thuyền viên cùng cất bài ca nghịch hành bất khuất giữa cơn giận của biển cả, khơi dậy tinh thần sinh tồn. Nghe bài ca, Vương Lâm minh ngộ ba cảnh giới sinh tử — thuận sinh thuận tử, nghịch ý khinh miệt sinh tử, và cảnh giới thứ ba mà hắn đã ngộ nhưng chưa nói ra được vì có tấm màng ngăn. Thuyền sống sót, tháng thứ mười một tới đại lục xa lạ. Ba năm chu du đại lục (tổng mười chín năm từ rời Triệu quốc), Vương Lâm trở thành đại nho thời nay danh tiếng khắp nơi, đôi mắt ẩn chứa thiên địa chỉ nhìn đã khiến người mê mang. Mùa thu năm thứ mười chín, tại vùng núi lửa đang bộc phát, hắn gặp nữ tử áo trắng tóc dài cầm bình ngọc thu thập vật phẩm — chỉ một ánh mắt khiến hắn run lên, như đã đợi cả đời, mấy ngàn năm."},{"chuong":1514,"tieuDe":"Mộng Hỏi Bản Thân","tomTat":"Vương Lâm trong thân phận đại nho già nua tự vấn bản thân về Lý Mộ Uyển và luân hồi, tự hỏi liệu bản thể tu sĩ muốn cắt đứt nhân quả với nàng để nàng không phải chờ đợi cô độc hai ngàn năm. Hắn cười to nhưng nước mắt chảy dài, rồi giác ngộ hoàn toàn bản chất thế giới Mộng Đạo: tất cả do bản thể tu sĩ nuốt ba đạo quả, dùng Mộng Đạo thuật trở lại hai ngàn năm trước mà tạo ra, mọi thứ đều là tưởng tượng. Hắn vạch trần từng nhân quả giả tạo được sắp đặt — Tô Đạo, Liễu Mi, Hồng Điệp, Luyện Hồn Tông — và tiết lộ đã biết sự thật từ hơn 55 năm trước khi nhìn thấy dấu tay trên cánh tay phải người điên, nhưng tự lừa gạt bản thân đến nay. Hắn kịch liệt phản đối việc cắt đứt nhân quả với Lý Mộ Uyển, tuyên bố mọi chuyện khác có thể bỏ qua nhưng riêng chuyện này không thể tiếp nhận. Hắn ngửa mặt gầm thét khiến thiên địa chấn động, dòng xoáy khổng lồ trên trời lộ ra thế giới đen tối chứa luồng sáng đỏ với hai thi thể nhắm mắt, một thi thể tóc bạc có dấu hiệu dãy dụa muốn thức tỉnh. Hắn điểm chỉ lên dòng xoáy, phát luồng khí mênh mông, vung tay áo khiến sấm sét ầm vang, dòng xoáy nhỏ dần biến mất hóa thành con chim trắng bay đi. Hắn khẳng định không ai trong thiên địa hiểu rõ hơn hắn về nhân quả, sinh tử, thật giả, tuyên bố đạo quả, ký ức, thế giới giả dối đừng động tới hắn."},{"chuong":1515,"tieuDe":"Duyên Khởi Không","tomTat":"Sau chín năm sáu tháng rời Triệu quốc, Vương Lâm gần tám mươi tuổi trong mộng, dừng chân tại Hỏa Phần quốc, ở căn phòng hoang gần tông phái Lý Mộ Uyển. Suốt nhiều năm hắn ngồi trên tảng đá xanh lam cảm ngộ thiên địa, không ăn uống, quên cả đói, thân như hợp nhất với thiên nhiên. Hắn ngộ ra giữa nhân và quả tồn tại «duyên» — duyên tạo nhân quả rồi tán thành «không». Trạng thái và những lời hắn lẩm bẩm mỗi năm một câu khiến tu sĩ khắp thế giới mộng bị kéo đến nghe giảng đạo, phạm vi mấy ngàn dặm, bao gồm Độn Thiên, Chu Vũ Thái, Vân Tước Tử, Đằng Hóa Nguyên, Hoàng Long Chân Nhân, Từ Phi, Vương Trác, tu sĩ Tuyết Vực và cả Chu Tước Tử phá không mà tới. Lý Mộ Uyển y phục trắng từ tông phái đi ra, cảm thấy hắn quen thuộc khắc sâu trong linh hồn nhưng bị phong ấn ngăn cản. Vương Lâm điểm ngón tay lên mi tâm nàng phá vỡ phong ấn, nàng trở thành người đầu tiên trong thế giới mộng ảo tỉnh lại, nước mắt tuôn rơi ôm chặt hắn. Giọng hắn hóa thành vô số tơ liễu bay kín bầu trời ghi lại cuộc đời mỗi tu sĩ, hai đám tơ liễu dính chặt bay xuống trước hai người tượng trưng nhân duyên không tách rời. Lý Mộ Uyển nói muốn ở trong mộng chờ chàng tỉnh lại."},{"chuong":1516,"tieuDe":"Hồng Nhan","tomTat":"Trong giấc mộng do chính mình mượn đạo quả tạo thành, Vương Lâm sống những năm cuối cùng như phàm nhân bên Lý Mộ Uyển. Hắn hồi tưởng cảnh chứng kiến nàng từ hồng nhan tới khô cốt, tự nhận trái tim đã chết từ ngày đó và không hồng nhan nào — Liễu Mi, Lý Thiến Mai — có thể thay thế. Năm thứ 31 sau rời Triệu quốc, hai người ngồi trên tảng đá giữa vô số tu sĩ cảm ngộ thiên địa. Năm thứ 32, Lý Mộ Uyển dìu Vương Lâm bay đi trước mắt hàng ngàn tu sĩ; Liễu Mi nhìn từ xa, vẻ mê man biến thành căm giận. Tại sơn cốc, Lý Mộ Uyển dùng thần thông biến mình thành bà lão để cùng Vương Lâm già đi như phàm nhân. Năm thứ 35, cảm nhận tử vong sắp tới, Vương Lâm yêu cầu nàng đưa hắn về Triệu quốc mang theo Đại Phúc tới Tô thành hoàn thành ước hẹn cuối cùng. Bên ngoài mộng, ánh sáng viễn cổ Thanh Lâm đã sụp đổ, Thanh Thủy hóa thân Vương Lâm bị Hư Thần Thiên Tôn trọng thương gần chết, tin Phong Tôn tử vong lan rộng, giới nội bỏ Vân Hải, Triệu Hà, Côn Hư, tử thủ La Thiên trước Chu Tước Tinh — cố hương Phong Tôn — quyết chiến với giới ngoại."},{"chuong":1517,"tieuDe":"Hội Ngộ Với Bản Thân","tomTat":"Đã 35 năm kể từ khi Vương Lâm rời Triệu quốc. Hắn cùng Lý Mộ Uyển (đã hóa bà lão) đi xe ngựa trở về quê, ngang qua nhà trọ đổ nát nơi hắn từng tỉnh lại năm xưa. Về sơn thôn dưới Hằng Nhạc Sơn gặp lại Đại Phúc — ông lão đã chờ đợi suốt 35 năm theo lời hẹn không quá 38 năm, trên cổ tay vẫn còn dấu tay vàng. Sáng hôm sau Vương Lâm đưa Lý Mộ Uyển tới viếng mộ cha mẹ phía sau thôn, giới thiệu nàng là con dâu, hai người quỳ trước mộ trầm mặc rồi cùng vái. Rời quê đi Tô thành, hắn nhấc rèm nhìn lại quê hương chìm trong tuyết, nhớ lại 73 năm trước lần đầu rời nhà. Tại Tô thành thuê họa thuyền uống Quế Hoa tửu chờ đợi cuộc hẹn. Tháng sáu năm thứ 75, Vương Lâm cười vang ngâm bài thơ về tâm nghịch hành, đời như giấc mộng. Cánh chim trắng đã rất lâu không xuất hiện bay tới, lao xuống cầu đá hóa dòng xoáy ánh sáng trắng — từ trong đó bước ra một thanh niên tóc bạc thần sắc lạnh lùng mê man, chính là bản thể tu sĩ của Vương Lâm. Hai ánh mắt giao nhau, thời gian mộng cảnh hoàn toàn dừng lại, vạn vật bất động. Thanh niên tóc bạc bước lên mũi thuyền ngồi xuống cầm bầu rượu, nhưng không nhìn bản thân lão niên mà nhìn Lý Mộ Uyển đã thành bà lão rất lâu rất lâu."},{"chuong":1518,"tieuDe":"Mộng Tỉnh (Hóa Phàm Chung)","tomTat":"Vương Lâm đối ẩm với thanh niên tóc bạc — thực chất là phân thân tạp niệm của chính hắn — trên họa thuyền trong mộng cảnh, được giải thích giấc mộng do tạp niệm trong ba đạo quả tự thôi diễn. Thanh niên tóc bạc hôn mi tâm Lý Mộ Uyển rồi hóa cánh chim trắng bay đi, để lại bầu rượu. Vương Lâm gảy khúc mộng cầm cuối cùng bên Lý Mộ Uyển, hồi tưởng toàn bộ cuộc tình từ Hỏa Phần quốc qua nhiều lần luân hồi. Uống cạn bầu rượu, hắn lần lượt thốt lời phá hủy đại địa rồi phá hủy sinh linh — mọi quốc gia, địa danh, tu sĩ và phàm nhân trên Chu Tước Tinh trong mộng đều tiêu tan, kể cả Lý Mộ Uyển, Liễu Mi, Từ Phi, Vương Trác, Chu Vũ Thái và các tu sĩ khác. Chỉ còn Vương Lâm và Đại Phúc giữa bầu trời trống không. Vương Lâm rơi nước mắt hứa sẽ đánh thức Lý Mộ Uyển, rồi cầm tay Đại Phúc, nắm dấu ấn trên cánh tay hắn, nhắm mắt tỉnh mộng — giấc mộng phàm trần Hóa Phàm chính thức kết thúc."},{"chuong":1519,"tieuDe":"Nhân Quả Ấn","tomTat":"Trong hư vô đen tối, quầng huyết quang bao quanh hai thi thể đã ảm đạm suốt mười năm. Vương Lâm mở mắt thức tỉnh sau hơn bảy mươi năm mộng đạo — giấc mộng do hắn tự tạo bằng cách bắt chước thuật lừa đảo của Lưu Kim Bưu để lừa gạt chính bản thân, sống trọn một cuộc đời khác. Sấm sét ầm vang và biển lửa chín màu bùng nổ khắp hư vô nghênh đón hắn. Hắn lần lượt ngưng tụ Lôi bổn nguyên đại thành — chín tia sét dung hợp thành lôi ấn ký bất diệt hình thái hỗn độn — và Hỏa bổn nguyên đại thành — chín màu hợp nhất vượt hư hỏa thành đạo hóa, uy lực đủ giết tu sĩ Không Niết hậu kỳ đại viên mãn trở xuống. Cuối cùng, dùng khí tức đại nho từ cảm ngộ thiên địa trong mộng, hắn ngưng tụ Nhân Quả bổn nguyên trên tay phải — mở tay là nhân, nắm tay là quả — sáng tạo thần thông thứ tư: Nhân Quả ấn. Hắn tuyên bố muốn phá tan không môn trở thành tu sĩ bước thứ ba, đồng thời nhắc đến kẻ thù: Chưởng Tôn, Hư Thần Thiên Tôn và mấy tiên phi."},{"chuong":1520,"tieuDe":"Trước Mặt Chúng Tu Không Môn Hiện","tomTat":"Vương Lâm ngộ ra Nhân Quả ấn — thức thần thông thứ tư do hắn tự sáng tạo — đánh dấu nhân quả bổn nguyên đại thành. Ba đạo bổn nguyên (lôi đình, hỏa, nhân quả) đều đại thành, khí tức bước thứ ba tăng gấp bội, uy lực vượt Không Niết đại viên mãn. Trong khi đó tại Côn Hư tinh vực, toàn bộ đã thất thủ, chỉ còn Chu Tước Tinh là điểm kháng cự cuối cùng — chưa đầy tám ngàn tu sĩ giới nội do Nam Vân Tử cầm đầu quyết tử chiến trước mấy vạn quân giới ngoại. Tư Đồ Nam (đã đột phá bước thứ ba nhờ Thanh Lâm trợ giúp) quay lại Chu Tước Tinh tử chiến thay vì rút về La Thiên. Long Bàn Tử dùng Sơn Hà Đồ bao phủ bảo vệ Chu Tước Tinh, Lỗ Phu Tử chọn ở lại chết trong chiến trận, Thanh Long Thánh Hoàng tái xuất cùng Tứ Thánh Tông. Phe giới ngoại có ba tu sĩ bước thứ ba, trong đó nam tử áo thanh y cảm ngộ băng bổn nguyên đánh bại Long Bàn Tử và Tư Đồ Nam, còn Chu Cẩn — nguyên nô bộc Vương Lâm — phản bội mang Phụng Thiên Lang tộc gây tang tóc giới nội. Giữa lúc tuyệt vọng, Không Đại Môn khổng lồ bất ngờ hiện ra giữa tinh không, đại biểu có người sắp trở thành tu sĩ bước thứ ba. Chu Cẩn nhận ra khí tức quen thuộc từ ấn ký nô bộc của Vương Lâm, gần hồn phi phách tán."},{"chuong":1521,"tieuDe":"Bổn Nguyên Xuất, Vạn Nhân Kinh","tomTat":"Không môn xuất hiện trong tinh không bên ngoài Chu Tước Tinh, uy áp khủng khiếp khiến trận chiến giới nội — giới ngoại tạm dừng, đẩy bật tu sĩ hai phía. Từ không môn lần lượt hiện ra Lôi bổn nguyên, Hỏa bổn nguyên, Nhân Quả đại đạo, rồi đạo bổn nguyên thứ tư — Sinh Tử (Vương Lâm trong hư vô sáng tạo Sinh Tử Ấn, thức thần thông thứ năm, dung hợp ba đạo bổn nguyên trước), và đạo bổn nguyên thứ năm — Thật Giả. Tư Đồ Nam mơ hồ nhận ra khí tức từ không môn giống huynh đệ mình, cực kỳ kích động. Nam Vân Tử nắm thời cơ ra lệnh Côn Hư phản công giới ngoại, Tư Đồ Nam, Long Bàn Tử, Lỗ Phu Tử cùng mấy ngàn tu sĩ lao vào chém giết. Nhưng sương mù màu tím đột ngột xuất hiện, một trong Thái Cổ Ngũ Tôn (lão già thần sắc uy nghiêm) một đòn đánh Nam Vân Tử phun máu, quét thương Tư Đồ Nam, Long Bàn Tử, Lỗ Phu Tử. Tư Đồ Nam kích hoạt ngọc giản pháp bảo Thanh Lâm tặng (vỡ tan) để thoát thân, Long Bàn Tử cuốn hai người rút vào Chu Tước Tinh. Lão già sương tím lạnh lùng nhìn không môn, đồng tử co rụt lại."},{"chuong":1522,"tieuDe":"Nơi Đây Là Tiên Cương Đại Lục","tomTat":"Hư Thần Thiên Tôn — một trong Thái Cổ Ngũ Tôn — quở trách thủ hạ bất lực, đích thân bước tới tấn công Chu Tước Tinh. Trong hư vô, Vương Lâm hoàn thành bổn nguyên thứ năm Thật Giả đại thành, ngưng tụ thần thông thứ sáu Chân Giả Ấn, rồi nắn vỡ Sát Lục Kiếm hấp thu sát lục bổn nguyên thành đạo bổn nguyên thứ sáu, tuyên bố dùng sáu đạo bổn nguyên thành tựu bước thứ ba toàn năng. Hắn thu hồi giọt máu bất diệt thể tiên nhân bị Chưởng Tôn tách năm xưa, đặt lên mi tâm làm pháp bảo tương lai. Phá vỡ hư vô tạo hai dòng xoáy: một về Chu Tước Tinh, một tới Tiên Cương đại lục — đại lục chín mặt trời tiên khí cực đậm nơi nữ đồng Oa Oa truyền âm tự giới thiệu. Vương Lâm liên hệ hàng loạt bí mật kinh thiên xuyên suốt giới nội giới ngoại rồi chọn đường về Chu Tước Tinh. Bên ngoài, Hư Thần Thiên Tôn một vỗ tay sương mù tím phá nát trận pháp Chu Tước Tinh kiên trì mấy tháng, bước vào thấy tượng Phong Tôn và mấy ngàn tu sĩ giới nội, đang định hủy diệt thì biến sắc vì người trong không môn sáu bổn nguyên vừa phá môn ra."},{"chuong":1523,"tieuDe":"Mở Cửa Chính Là Bậc Toàn Năng","tomTat":"Bên ngoài Chu Tước Tinh cạnh Không Môn khổng lồ, một vòng xoáy tỏa khí tức quen thuộc khiến mấy vạn tu sĩ giới ngoại run rẩy, Hư Thần Thiên Tôn và nam tử áo xanh sợ hãi, còn Tư Đồ Nam, Thập Tam, Nam Vân Tử cùng các tu sĩ giới nội kích động gào thét Phong Tôn vinh quang. Vương Lâm áo trắng tóc bạc từng bước đi ra từ vòng xoáy, tuyên bố trở về sau khi được cho là đã chết. Hư Thần Thiên Tôn phân thân tuyên bố năm xưa đoạt xá không thành, lao tới giết, nhưng Vương Lâm chỉ một câu quát phóng chính khí đại nho nhập linh hồn khiến hắn khựng lại lùi mấy trượng hoảng sợ. Vương Lâm bỏ mặc Hư Thần Thiên Tôn, xướng chú triệu sáu đạo bổn nguyên ngưng tụ Không Môn mạnh nhất lịch sử — lôi đình, hỏa diễm, nhân quả, sinh tử, chân giả, sát lục. Hồi tưởng Thanh Thủy năm đó một kiếm phá một góc Không Môn bằng sát lục bổn nguyên, Chu Cẩn dốc toàn lực mới mở được chút; sáu đạo bổn nguyên chưa từng có nên cửa này cũng mạnh nhất. Vương Lâm bóp nát quang cầu sáu đạo dung nhập thân thể, tuyên bố muốn làm điều chưa ai từng làm, rồi lao thẳng tới Không Môn hướng bậc toàn năng bước thứ ba."},{"chuong":1524,"tieuDe":"Một Tiếng Lôi Đình Bốn Biển Ầm Vang","tomTat":"Vương Lâm hô hiệu lệnh lôi đình trong thiên địa, một quyền đánh lên Không Môn sáu đạo bổn nguyên, chấn động khiến mấy vạn tu sĩ phun máu tươi, Không Môn chậm rãi hé ra một chút. Chu Cẩn tuyệt vọng lui về sau, hy vọng duy nhất là Vương Lâm mở thất bại vì đó mới là con đường sống của hắn. Nam tử áo xanh (Không Huyền Sơ Kỳ) cũng lui, hiểu rằng cản trở lúc này ngược lại thành trợ giúp. Hư Thần Thiên Tôn ban đầu cười lạnh khinh thường, tin tiểu bối sẽ chết dưới Không Môn. Phe giới nội — Tư Đồ Nam nắm chặt tay lo lắng, Nam Vân Tử quyết dốc toàn lực trợ giúp ở thời điểm mấu chốt, Thanh Long Thánh Hoàng triệu ra bốn bảo vật truyền thừa Tứ Thánh Tông chuẩn bị hỗ trợ. Vương Lâm kêu một tiếng dài, dẫn động toàn bộ lôi đình tứ đại tinh vực Côn Hư, Vân Hải, Triệu Hà, La Thiên bay về Chu Tước Tinh — kể cả lôi đình bất diệt vạn năm ở cửa Lôi Tiên Giới cũng lần đầu thoát ra. Hư Thần Thiên Tôn khiếp sợ kêu thất thanh trước thanh thế chưa từng có."},{"chuong":1525,"tieuDe":"Mở Cửa Một Bước Thành Danh","tomTat":"Vương Lâm đứng bên ngoài Chu Tước Tinh trước Không Môn, phát tiếng kêu dài dẫn động lôi đình từ giới nội lẫn giới ngoại qua lỗ hổng Phong Giới Đại Trận tại Vân Hải. Toàn bộ lôi đình hội tụ phá vỡ hoàn toàn Không Môn thứ nhất, khí thế hắn đạt mức Không Niết sơ kỳ. Tuy nhiên hắn từ chối hấp thu sức mạnh Không Môn vì chỉ dựa một đạo lôi đình bổn nguyên thì chỉ đạt sơ kỳ, mục tiêu của hắn là sáu đạo bổn nguyên dung hợp để một bước thành danh. Chu Cẩn muốn rời đi nhưng bị áp lực tinh không khóa lại, bị một cái liếc mắt của Vương Lâm chấn động tâm thần phun máu. Hư Thần Thiên Tôn lần đầu thật lòng gọi Vương Lâm là Phong Tôn, nhận ra hắn muốn mỗi đạo bổn nguyên mở một Không Môn để thành bước thứ ba toàn năng, sát khí trong mắt càng nồng đậm. Vương Lâm gọi hỏa bổn nguyên nhân danh mình, dẫn lửa từ Côn Hư, Vân Hải, La Thiên, Triệu Hà và Thái cổ Tinh Thần tạo biển lửa thiêu hủy Không Môn thứ hai. Sau hai lần phá cửa, khí thế hắn bạo tăng từ Không Niết sơ kỳ lên Không Niết trung kỳ."},{"chuong":1526,"tieuDe":"Vạn Không Cốt Môn","tomTat":"Vương Lâm không dừng ở Không Niết Trung Kỳ hai đạo bổn nguyên mà ép Không Môn tiếp tục sụp đổ. Lô Vân Tử chỉ một ngón tay khiến vòng xoáy tinh không dẫn ra đồng thời Không Môn thứ ba đến thứ năm. Vương Lâm lần lượt dùng Nhân Quả Ấn phá cửa thứ ba (lên Không Niết Hậu Kỳ), Sinh Tử Ấn xé toạc cửa thứ tư (đạt Không Niết Đại Viên Mãn, mi tâm hiện khe thiên địa bản thân), và Chân Giả Đạo quét vỡ cửa thứ năm (khí thế Không Linh Sơ Kỳ, khe mi tâm hiện hoàn toàn). Hắn tiếp tục hấp thụ sát lục bổn nguyên do Thanh Thủy tặng, đại thành tức thì, dẫn ra Không Môn thứ sáu — Vạn Không Cốt Môn bằng bạch cốt hình đầu lâu khổng lồ. Gợn sóng từ cửa lan ra giết gần vạn tu sĩ, khiến họ già đi rồi thành tro bụi. Tu sĩ giới ngoại hoảng loạn bỏ chạy, nam tử áo xanh (Không Huyền Sơ Kỳ) nhận ra Vương Lâm minh ngộ ba bổn nguyên hư ảo. Hư Thần Thiên Tôn và Nam Vân Tử nhận ra đây là Vạn Không Cốt Môn trong truyền thuyết — cửa không thuộc Phong Giới mà hiện ở quê hương Phong Tôn, người dẫn động được nếu không gặp tai họa ắt thành Đại Tôn."},{"chuong":1527,"tieuDe":"Xuất Thủ Đại Đạo","tomTat":"Vương Lâm đối mặt Vạn Không Cốt Môn — Không Môn thứ sáu quỷ dị, dùng sát lục bổn nguyên hóa huyết chưởng đánh lên cánh cửa nhưng chỉ khiến nó nứt. Hắn lần lượt vận lôi, hỏa, Nhân Quả Ấn, Sinh Tử Ấn, Chân Giả Đạo, dồn sáu đạo bổn nguyên đại thành vào một quyền toàn lực đánh sập Vạn Không Cốt Môn. Sức mạnh Không Môn từ vòng xoáy tinh không phun vào cơ thể, sáu bổn nguyên dung hợp, tu vi tăng vọt qua Không Niết trung kỳ, hậu kỳ, đại viên mãn rồi đạt Không Linh sơ kỳ trong Không Tứ Cảnh, chính thức trở thành bước thứ ba toàn năng. Hư Thần Thiên Tôn nhận ra đây là cơ hội cuối để giết Vương Lâm, cùng nam tử áo xanh và Chu Cẩn liều mạng lao tới. Nam Vân Tử và đồng bạn định trợ chiến nhưng bị Vương Lâm ngăn bằng một câu nhẹ nhàng đầy uy lực. Vương Lâm trong lúc hấp thụ sức mạnh điểm một chỉ chứa đạo niệm từ ba đạo quả, khiến tinh không như ngừng lại, kiềm chế cả ba địch thủ. Hắn áp sát nam tử áo xanh, dùng Định Thân Thuật rồi thi triển Nhân Quả Ấn rút ra bổn nguyên của y dưới dạng sương mù hư ảo."},{"chuong":1528,"tieuDe":"Hư Thần Thiên Tôn","tomTat":"Vương Lâm thi triển Nhân Quả Ấn lên nam tử áo xanh (tu vi Không Huyền), rút hơn phân nửa bổn nguyên của hắn, tuyên bố chỉ lấy bổn nguyên và phong ấn ngàn năm chứ không giết, bức lui hắn mấy ngàn trượng. Hư Thần Thiên Tôn (phân thân, mang sát khí) thi triển Vạn Hà Hư Thần Đạo mở khe khổng lồ phóng hàng vạn pho tượng và hồn phách hương hỏa, kết hợp vòng xoáy oan hồn và Không Môn sụp đổ vây khốn Vương Lâm, đồng thời hóa sương tím thành trường thương vung tới. Vương Lâm thân hóa hư ảo cho pho tượng xuyên qua, rồi phản công liên hoàn bằng Sinh Tử Ấn, Định, Lôi, Hỏa, Nhân Quả, Chân Giả Đạo và Sát lục chém đôi Thiên Tôn hóa hai đám sương tím. Nhờ Chân Giả Đạo, Vương Lâm phát hiện lớp sương chỉ là áo, bản thể phân thân là một đám khí vô hình hư ảo — thân Hư Thần Thiên Tôn từ xưa nay thủy chung đều hư ảo, hắn là kẻ khó giết nhất Thái Cổ Ngũ Tôn. Đám khí phân thân vội bay đi trốn thoát. Nam tử áo xanh sau khi bỏ chạy đã dừng lại, quay trở về chiến trường nhìn Vương Lâm bị vây."},{"chuong":1529,"tieuDe":"Bước Thứ Ba Giương Cung","tomTat":"Vương Lâm điểm mi tâm lấy giọt máu vàng, dựa vào cảm ứng triệu hồi Cung Lý Quảng cùng mũi tên đã dung hợp bên trong. Hắn kéo cung nhắm Hư Thần Thiên Tôn đang bỏ chạy, tuyên bố một tiễn này để giành lại Côn Hư. Mũi tên thực chất hóa, tinh không sụp đổ, xuyên diệt nam tử áo xanh dù hắn đã dùng hương hỏa giới, hồn phách hương hỏa và phá tộc ấn chống lại — trở thành tu sĩ Không Huyền đầu tiên tử vong trong cuộc chiến. Gợn sóng từ mũi tên lan khắp Côn Hư, bỏ qua tu sĩ giới nội nhưng quét sạch lượng lớn tu sĩ giới ngoại ở mọi hướng, cứu nhiều nhóm tu sĩ giới nội đang bị truy sát. Phân thân Hư Thần Thiên Tôn chạy tới biên giới Vân Hải nhưng bị mũi tên truy đến xuyên diệt, bản thể trong tinh vực sương mù Thái cổ Tinh Thần phun máu trọng thương và sinh kiêng kỵ với giới nội. Vương Lâm thu cung tên về giọt máu vàng, đặt lại mi tâm, nhìn Không Môn chưa tan và tự biết quá trình ngưng tụ bước thứ ba còn thiếu một phần, Thiên Kiếp bước thứ ba sắp tới. Chu Cẩn là tu sĩ giới ngoại duy nhất gần đó không bị gợn sóng giết, run rẩy kinh hãi. Nam Vân Tử, Tư Đồ Nam và mấy ngàn tu sĩ giới nội trên Chu Tước Tinh xúc động hô vang Phong Tôn vinh quang."},{"chuong":1530,"tieuDe":"Khôi Phục Bảo Vật Cũ","tomTat":"Trong vòng xoáy Không Môn, Vương Lâm hoàn tất dung hợp đạo sát lục bổn nguyên thứ sáu, tu vi tăng từ Không Linh sơ kỳ lên Không Linh trung kỳ. Hắn dùng sức mạnh Không Môn lần lượt ngưng tụ sáu thanh bổn nguyên kiếm: lôi đình, hỏa diễm, nhân quả, sinh tử, chân giả và sát lục. Khi khí tức Thiên Kiếp mạnh nhất đời hắn truyền tới từ tận cùng tinh không, Vương Lâm thi triển Định Thân Thuật cưỡng ép giữ vòng xoáy Không Môn đang tiêu tán, dùng bản tính thôn hồn hút thêm lượng lớn sức mạnh Không Môn để khôi phục các bảo vật cũ. Xạ Thần Xa đã hủy được lấy ra hấp thụ Không Môn lực, Thanh Quang Thuẫn hoàn toàn khôi phục thành hình, giáp cổ tay Cổ Thần cũng trở lại trạng thái hoàn chỉnh. Khi vòng xoáy sụp đổ, một ý chí cực mạnh khuếch tán ra, Vương Lâm không khuất phục mà nói sẽ báo đáp việc mượn sức mạnh Không Môn. Thiên Nghịch Châu trong tâm thần hắn đột nhiên chuyển động."},{"chuong":1531,"tieuDe":"Người Thứ Ba","tomTat":"Ý chí từ vòng xoáy Không Môn sụp đổ lao tới Vương Lâm mang sức trấn áp, khí thế đại nho giúp hắn chống lại trong khi Thiên Nghịch Châu trong tâm thần xoay tròn thức tỉnh hấp thụ ý chí ấy. Sức mạnh Không Môn trào ra chữa lành mảnh giáp Cổ Thần và khôi phục Thập Ức Tôn Hồn Phiên tàn phá, rồi sáu đạo bổn nguyên dung nhập vào hồn, Vương Lâm chính thức tiến vào bước thứ ba Không Linh trung kỳ với đồ hình Vạn Không Cốt Môn khắc sâu trong tim. Nam Vân Tử và Tư Đồ Nam dẫn mấy ngàn tu sĩ giới nội bay ra muốn hội ngộ nhưng sương mù thiên kiếp cuồn cuộn đẩy lui tất cả kể cả Chu Tước Tinh khỏi quỹ đạo, chỉ còn một mình Vương Lâm trong phạm vi trăm vạn trượng. Chiến lão quỷ áo tím từ xa quan sát, nhận ra tiễn khí mạnh và nhắc sáu đạo bổn nguyên, rồi thấy tay mình cũng có Vạn Không Cốt Môn và nghi Vương Lâm là người thứ ba. Trong cung điện đen ở Thái Cổ Tinh Thần, Chưởng Tôn hoảng loạn bộc lộ nỗi sợ vì hai lần giết Vương Lâm thất bại, nhắc Lam Mộng ngăn lần đầu, chủ nhân cứu lần hai qua huyết mạch và cung tên Lý Quảng, đồng thời lo sợ chủ nhân khôi phục trí nhớ sẽ trừng phạt vì mình khuất phục Thất Thải. Thiên Vận Tử tái xuất ở Triệu Hà tinh vực đã bị giới ngoại chiếm, xác nhận Vương Lâm đạt bước thứ ba và tuyên bố đại kế mấy vạn năm bắt đầu. Vương Lâm đứng một mình giữa sương mù thiên kiếp, tuyên bố trời không có tư cách giáng kiếp và chủ động gọi lôi kiếp nổi lên nhân danh mình."},{"chuong":1532,"tieuDe":"Kiếp Của Ta!","tomTat":"Vương Lâm chủ động bước vào thiên kiếp bước thứ ba với ý chí trấn áp và trừng phạt lại thiên kiếp, mở ra cảnh tượng thiên kiếp đối thiên kiếp chưa từng có ở giới nội. Hắn hóa ấn ký mắt phải thành lôi kiếp đỏ như máu đối kháng thiên lôi xanh giáng xuống từ vòng xoáy, nhưng thiên kiếp tăng tới chín đạo hợp nhất áp chế lôi kiếp đỏ tiêu tan. Chiến lão quỷ đang quan sát ban đầu thất vọng cho rằng Vương Lâm không phải người thứ ba, nhưng khi thấy hắn trực tiếp bước tới chạm vào thiên lôi xanh thì lập tức đổi thái độ, hai mắt sáng rực. Vương Lâm dùng thân phận chủ lôi bổn nguyên ép chín đạo thiên lôi xanh hợp nhất tan rã, rồi triệu hàng vạn xích lôi phá nát hoàn toàn vòng xoáy thiên kiếp. Sau khi vòng xoáy tan, khe nứt vạn trượng mở ra lộ tế đàn bốn góc với thân ảnh mơ hồ ngồi giữa và bốn thanh kiếm. Vương Lâm chuyển sang phát động hỏa kiếp bằng đồ hình mắt trái, biển lửa mấy vạn dặm nuốt khe nứt và tế đàn, rồi áp sát thân ảnh mơ hồ thi triển Nhân Quả Ấn."},{"chuong":1533,"tieuDe":"Huyễn Chân Kiếp","tomTat":"Vương Lâm dùng Nhân Quả Ấn rút khí tức bốn kiếm và tế đàn thiên kiếp, phá nát tế đàn trong biển lửa. Sứ giả thiên kiếp lao ra tấn công nhưng bị Sinh Tử đại ấn đánh tan chỉ bằng một đòn, cho thấy sức mạnh hiện tại đã vượt xa thời vấn đỉnh. Vương Lâm chính diện chất vấn thiên kiếp và trời, hỏi vì sao có tư cách giáng nạn và cướp đi Lý Mộ Uyển, lời truyền tới Tư Đồ Nam và mấy ngàn tu sĩ giới nội khiến họ nhiệt huyết sôi trào. Trời giáng Huyễn Chân Kiếp, sương mù hóa thành cha mẹ, tứ thúc, Vương Trác, Trương Hổ, Liễu Mi ôm đứa trẻ bị hắc khí bao quanh, Lý Mộ Uyển lệ đẫm mỉm cười cùng nhiều người khác để công phá tâm thần hắn. Nhờ đã minh ngộ chân giả bổn nguyên, Vương Lâm nhắm mắt vung tay đưa mọi thân ảnh về hư vô, rồi dùng Chân Giả Đạo biến ra Chu Như, Bạch Phàm, Thanh Thủy, Thác Sâm cùng vô số người oán trời tạo thành thiên kiếp phản kích. Cuối cùng hắn khuếch tán thần thức phủ khắp Côn Hư tinh vực, gom oán niệm và ký ức linh hồn người chết đánh vào cái khe thiên kiếp, khiến cái khe lần đầu run lên và tiếng rít gào ngừng lại. Bên ngoài sương mù, Chiến lão quỷ quan sát với ánh mắt tham lam, nhận định Vương Lâm có ba phần khả năng là người thứ ba."},{"chuong":1534,"tieuDe":"Không Chịu Nổi Một Đòn","tomTat":"Vương Lâm không né tránh thiên kiếp bước thứ ba mà chủ động tiến về khe vạn trượng, muốn truy xét nguồn gốc kiếp nạn. Tam Thiên phất trần cán gỗ tím bay ra từ khe, ba nghìn sợi tơ bạc diễn hóa thành ba nghìn loại thần thông mà hắn từng biết hoặc chứng kiến, mang tiên lực tinh thuần công kích hắn. Nhờ giọt máu vàng tiên nhân bất diệt thể trên mi tâm và kinh nghiệm gặp người điên, Vương Lâm nhận ra tiên khí này khác tiên ngọc Tứ Đại Tiên Giới, từ đó suy ra Viễn cổ Tiên Vực sau khe có liên hệ lớn với Tiên Cương đại lục. Trấn Tiên bảo tháp chín tầng màu vàng bay ra trấn áp hắn, uy lực đủ giết Không Niết đại viên mãn. Bên ngoài sương mù, Tư Đồ Nam cảm thấy Vương Lâm gặp nguy và định xông vào nhưng bị Nam Vân Tử cản, cuối cùng đặt hạn nửa nén nhang. Chiến lão quỷ hưng phấn, tiết lộ Tam Thiên phất trần, Trấn Tiên bảo tháp và Phong Mệnh là bộ ba pháp bảo được ai đó đưa vào khi bài trí thiên kiếp trong phủ. Bên trong tháp, ba nghìn sợi tơ quấn chặt Vương Lâm như phong ấn, hào quang vàng định luyện hóa hắn bằng tiên lực, nhưng Vương Lâm hiện tinh điểm Cổ Thần, hóa thân Cổ Thần kéo đứt gần hết sợi tơ rồi tung quyền đánh lên đỉnh tháp."},{"chuong":1535,"tieuDe":"Phong Mệnh Hoàn","tomTat":"Vương Lâm hiển hóa đầu lâu Đạo Cổ, dung hợp uy thế vào ba quyền phá sập hoàn toàn bảo tháp thiên kiếp đang phong ấn hắn. Từ cái khe vạn trượng trên trời, pháp bảo thứ ba xuất hiện dưới dạng quầng sáng vàng mang uy áp vượt xa hai pháp bảo trước, khiến mấy ngàn tu sĩ gồm cả Tư Đồ Nam và Nam Vân Tử phải lùi xa. Chiến lão quỷ nhận ra đó là Phong Mệnh Hoàn, bảo vật có danh tiếng ở Tiên Cương đại lục, và kỳ vọng nếu Vương Lâm thu phục được thì khả năng trở thành 'người thứ ba' càng cao. Vương Lâm cố ý để Phong Mệnh Hoàn phong ấn thân thể, Nguyên Thần và hồn phách nhằm tự thân cảm thụ kết cấu bảo vật. Qua tâm thần tính toán, hắn phát hiện bảo vật này do hơn mười triệu ký hiệu cấu thành, là bán thành phẩm được kẻ nào đó dung nhập vào thiên kiếp để hoàn thiện, cơ chế gần giống lực phong ấn của Phong Diệt Tộc. Trong khi hắn đã điều khiển được ba phần ký hiệu, cái khe tiếp tục mở ra phóng thích mười hai Cổ Tộc bát tinh gồm bốn Cổ Thần, bốn Cổ Ma, bốn Cổ Yêu vây sát bốn phía."},{"chuong":1536,"tieuDe":"Viễn Cổ Tiên Vực","tomTat":"Trong thiên kiếp, Vương Lâm đối đầu bốn bát tinh Cổ Thần, hiện thất tinh vương tộc áp chế và đánh lui cả bốn nhưng nương tay vì cùng tộc. Chuyển sang diệt bốn Cổ Ma không cùng tộc, phá chiến phủ và hấp thu toàn bộ ma khí vào mắt trái. Quầng sáng màu vàng trên trán bị giọt máu tiên nhân bất diệt thể bao phủ, kim quang chuyển thành thuộc về hắn, hoàn tất thu phục bảo vật khiến Chiến lão quỷ kích động, nâng nhận định hắn là người thứ ba lên năm phần. Sau khi Mộng Đạo thức tỉnh, Vương Lâm thi triển Dịch Linh Ấn uy lực vượt xa năm xưa, diệt bốn Cổ Yêu rồi đổi hướng diệt bốn Cổ Thần bị xóa trí nhớ thành con rối để giải thoát đồng tộc. Hắn tuyên bố thiên kiếp nên kết thúc, bước vào khe vạn trượng và phát hiện thế giới vô tận đầy tượng đá Cổ Thần, Cổ Ma, Cổ Yêu cùng tiên khí chân chính của Tiên Cương đại lục. Trên một pho tượng Cổ Yêu, hắn thấy một thanh niên tóc bạc áo trắng giống hệt mình về hình dáng, thần sắc và khí tức, khiến hắn chất vấn đối phương là ai."},{"chuong":1537,"tieuDe":"Bổn Ngã Kiếp","tomTat":"Vương Lâm bị thanh niên tóc bạc giống hệt mình chặn đường trước đại lục khôn cùng, đối phương tự xưng là chính hắn và gọi đây là Bổn Ngã kiếp. Vương Lâm thử phá màn ngăn tiên khí để vào đại lục nhưng bị phản chấn. Hai người giao thủ bằng bổn nguyên, cùng rút bổn nguyên đối phương rồi dùng Nhân Quả ấn bù hao tổn, cùng phun máu ngang nhau. Thanh niên tóc bạc thi triển Sinh Tử Ấn, Vương Lâm dùng cùng thuật đối kháng, kết quả cả hai cùng bị chấn động, pho tượng cổ Yêu sụp đổ. Vương Lâm vận Chân Giả Đạo và Định thần thuật nhưng đối phương đều làm theo y hệt, khiến hai bên bất động rơi xuống đất. Trong lúc rơi, Vương Lâm xác nhận mọi hành động trước đó đều là thăm dò có chủ ý, vì hắn phân tích rằng đối phương có thể cảm ứng suy nghĩ của mình."},{"chuong":1538,"tieuDe":"Trảm Bổn Ngã","tomTat":"Vương Lâm dùng Định Thần thuật khóa thần thức và suy nghĩ của cả hai bên để tranh thủ tính toán mà không bị bản ngã kiếp cảm ứng. Khi Định Thần thuật tan, hai bên giao chiến bằng hơn mười loại thần thông hoàn toàn giống nhau bao gồm tiên thuật của Bạch Phàm và Thanh Thủy, hỏa bổn nguyên, lôi đình bổn nguyên, kết quả lưỡng bại câu thương. Vương Lâm nhận ra đối phương sao chép toàn bộ thân thể Cổ Thần, tu vi Không Linh trung kỳ và pháp bảo của mình. Hắn âm thầm dùng Mộng Đạo hóa thành Đạo lừa gạt của Lưu Kim Bưu để tự lừa bản thân rơi vào trạng thái điên cuồng nhưng vẫn giữ một phần tỉnh táo. Khi dụ thanh niên tóc bạc nhắm mắt theo Chân Giả Đạo, Vương Lâm bất ngờ mở mắt khiến đối phương lần đầu có động tác khác hắn, dùng Nhân Quả Ấn rút bổn nguyên rồi Sinh Tử Ấn đánh vào mi tâm gây trọng thương. Khi thanh niên tóc bạc cố lùi về tấm màn ngăn, Vương Lâm tự đánh nát đùi phải lợi dụng liên hệ song trùng khiến đối phương chịu thương thế giống hệt và chậm lại. Hắn lao tới va chạm trực tiếp khiến thân thể thanh niên tóc bạc tứ phân ngũ liệt, tấm màn ngăn tan rã. Sau trận, Vương Lâm chữa chân phải rồi bước vào phía sau tấm màn vừa tan nhưng sững lại vì nhìn thấy điều gì đó chưa được tiết lộ."},{"chuong":1539,"tieuDe":"Một Động Phủ","tomTat":"Vương Lâm đặt chân vào Viễn cổ tiên vực, nơi tồn tại ngoài giới nội và giới ngoại, cổ xưa hơn tứ đại tiên vực, phát hiện bầu trời hôn ám có chín mặt trời giống hệt Tiên Cương đại lục và mặt đất sừng sững vô số pho tượng giống người sống bị hóa thạch. Hắn bay tới mặt trời thứ nhất, phất tay cuốn sương mù rồi vung tay nhiều lần khiến mặt trời sụp đổ, phát hiện bên trong phong ấn một tia lôi đình chín màu — căn nguyên dẫn dắt thiên kiếp thứ nhất. Đưa thần thức vào tia sét nghịch chuyển thời gian, Vương Lâm chứng kiến một nam tử trung niên mặc đạo bào bảy màu tự xưng bổn tôn, tuyên bố động phủ bốn tôn tự thành một giới, vạn vật do hắn tạo ra, sẽ cướp thiên đạo và chế tạo sấm sét thiên kiếp trừng phạt nghịch tu. Vương Lâm ấn chứng bí mật chấn động: giới nội giới ngoại chẳng qua chỉ là một động phủ của đại tôn trên Tiên Cương đại lục biến thành, nhớ lại lời Chiến lão quỷ từng nói giới nội là nội phủ, rồi cười điên cuồng chỉ vào bầu trời."},{"chuong":1540,"tieuDe":"Chúa Tể Vận Mệnh","tomTat":"Vương Lâm minh ngộ hoàn toàn chân tướng thiên đạo: toàn bộ thiên địa tu sĩ sinh sống chỉ là động phủ do nam tử bảy màu sáng tạo, tu sĩ bên trong không phải người của Tiên Cương đại lục. Hắn cười điên cuồng tuyên bố sẽ bước ra khỏi động phủ, tiến vào Tiên Cương đại lục khiến các đại tôn khuất phục. Vương Lâm lần lượt đánh tan tám mặt trời, mỗi mặt trời chứa bản chất một thiên kiếp: chân tướng, hóa kiếp, thiên uy, bốn thanh kiếm, huyễn chân kiếp, ba pháp bảo, hồn lực tam tộc điều khiển sứ giả thiên đạo, và Bổn Ngã kiếp. Hắn thâm nhập mặt trời thứ chín — bổn nguyên thiên kiếp chứa vận mệnh hết thảy chúng sinh — tìm thấy khí tức vận mệnh bản thân, thôn phệ dung nhập, chính thức trở thành chúa tể vận mệnh của mình, siêu thoát khỏi mọi ràng buộc thiên đạo. Hắn tiếp tục thu hồi vận mệnh cho cha mẹ, Thập Tam, Đồng tử đầu to, Chu Dật, Thanh Sương, Thanh Lâm, Vương Trác, Độn Thiên, Vương Bình, Chu Như, Hồng Điệp, Mộc Băng Mi, Tây Tử Phượng, Lý Thiến Mai và nhiều bằng hữu khác. Tuy nhiên hắn không tìm thấy vận mệnh của Thanh Thủy, Tư Đồ Nam và Thiên Vận Tử — gợi ý ba người này không thuộc hệ thống vận mệnh của động phủ. Quan trọng nhất, vận mệnh Lý Mộ Uyển có dấu hiệu tồn tại nhưng đã bị kẻ bí ẩn nào đó sớm một bước đem đi."},{"chuong":1541,"tieuDe":"Tàn Tiên Chữa Thương","tomTat":"Vương Lâm dùng thần thức tìm kiếm trong mặt trời thứ chín của động phủ viễn cổ tiên vực nhưng không tìm thấy khí tức vận mệnh của Tư Đồ Nam và Thanh Thủy, suy luận vận mệnh hai người có thể không thuộc nơi này. Hắn phát hiện vận mệnh Uyển Nhi (Lý Mộ Uyển) vốn có dấu vết nhưng đã bị ai đó đánh cắp, nổi sát khí phát lời thề tại viễn cổ tiên vực nhất định sẽ thu hồi, dù phải huyết tẩy Tiên Cương đại lục. Hắn nhận ra bước đầu tiên để Uyển Nhi thức tỉnh là khiến nàng siêu thoát khỏi vận mệnh. Vương Lâm hạ xuống mặt đất đầy pho tượng tam tộc cổ, lần lượt phá hủy tất cả để giải thoát hồn linh — hư ảnh tam tộc hiện ra ôm quyền vái rồi tan biến, khí tức Cổ Thần, Cổ Ma, Cổ Yêu dung nhập vào tinh điểm mi tâm và hai mắt hắn. Khi phá hủy pho tượng Cổ Thần sát cửu tinh cao mấy ngàn trượng, tại trung tâm chín tinh điểm xuất hiện dòng xoáy, một sinh vật khô gầy bí ẩn mang khí tức uy nghiêm vô thượng thò tay ra đe dọa sẽ giết Vương Lâm và diệt cả bộ tộc. Vương Lâm túm cánh tay giật mạnh lôi ra ném xuống đất, tuyên bố muốn lấy trí nhớ của sinh vật này bất kể đó là tiên hay tu sĩ."},{"chuong":1542,"tieuDe":"Định Không Thuật","tomTat":"Vương Lâm lao xuống hố sâu, đối mặt lão già tiên nhân gầy gò vừa thức tỉnh do phôi thể ký sinh trong pho tượng Cổ Thần bát tinh bị hủy diệt. Lão già cao ngạo tự xưng bổn tiên, là một trong trăm hộ vệ của tiên tôn, coi tu sĩ hạ giới là kiến hôi. Vương Lâm ở cảnh giới Không Linh trung kỳ dễ dàng trấn áp: dùng một trảo vặn xoắn quy tắc thiên địa khóa chặt lão già, rồi đánh một chưởng nát tay trái lão ta. Lão già hồi tưởng lai lịch: trong trận đại chiến năm xưa tại nơi này bị trọng thương, chọn ký sinh vào pho tượng Cổ Thần bát tinh để mượn lực lượng chữa thương. Lão già kinh hãi nhận ra Vương Lâm là nghịch tu bước thứ ba, điều mà thiên kiếp được thiết lập để ngăn chặn và chưa từng có tiền lệ trên toàn Tiên Cương đại lục. Tuyệt vọng cố thi triển thủ đoạn bảo mạng nhưng Vương Lâm thong dong điểm một ngón tay niệm Định, thi triển Định Không Thuật đình chỉ mọi chuyển động kể cả năm tháng trong thiên địa. Lão già nhận ra đó là đại thần thông cấp tiên tôn trước khi bị định thân hoàn toàn. Vương Lâm đặt tay lên thiên linh lão già chuẩn bị đọc ký ức tìm hiểu trận đại chiến năm xưa."},{"chuong":1543,"tieuDe":"Phong Ấn Hiện","tomTat":"Vương Lâm dùng thần thức cường hành xâm nhập thức hải lão già sĩ tiên để thu lấy trí nhớ, khiến lão ta thất khiếu chảy máu. Lão già tự xưng sĩ tiên dưới trướng tiên tôn, có huyết mạch tiên nhân, đe dọa Vương Lâm phạm tội giết tiên. Trong khi đó, bốn Thánh Hoàng bên trong pho tượng tam tộc cổ ở trung tâm giới bàn luận: Bạch Hổ trào phúng Vương Lâm không biết lượng sức, Chu Tước tiết lộ Vương Lâm không nằm trong kế hoạch nhưng là người đầu tiên đến được nơi này, Thánh Hoàng thứ tư đánh giá hắn là tu sĩ nghịch tu bước thứ ba đầu tiên mình gặp. Cả bốn kết luận phong ấn tiên tôn liên thủ cũng không phá nổi. Trong thức hải lão già, Vương Lâm gặp sương mù phong toả giống phong ấn từng thấy ở Ngân Y Luyện Thi, tiến sâu phát hiện nam tử trung niên bảy màu ngồi khoanh chân — chính là chân thân pho tượng bảy màu trong khe trữ vật. Vương Lâm lần lượt thử phá phong ấn bằng chưởng ấn, dòng suối thần thức và song chỉ dung hợp Cổ Thần lực, nhưng tất cả đều tan rã ở giới hạn ba tấc bên ngoài thân nam tử. Song chỉ mất gần nửa, dùng Cổ Thần lực hồi phục. Động lực hành động của Vương Lâm: giới nội giới ngoại chỉ là động phủ tiên tôn, cộng thêm khí tức Lý Mộ Uyển biến mất khiến thống hận đỉnh điểm. Hắn nhận định phá phong ấn rất gian nan nhưng không phải không có khả năng."},{"chuong":1544,"tieuDe":"Ký Ức Tiên Nhân","tomTat":"Vương Lâm quyết tâm phá phong ấn ký ức lão già gầy gò để biết chân tướng thiên địa. Hắn lần đầu tiên đồng thời kích phát lực lượng Cổ Thần, Cổ Ma, Cổ Yêu cùng đầu lâu Đạo Cổ, tam tộc cổ đồng thời hiện ra phía sau. Hắn thi triển thần thông tự sáng tạo — Cổ Tộc Bất Diệt Chỉ — ngưng tụ toàn bộ lực tam tộc vào ngón trỏ, ngón tay tan rã-khôi phục nghìn vạn lần xuyên qua phong ấn ba tấc của tiên tôn, phá vỡ phong ấn và đoạt tinh thể ký ức bằng Định Thần Thuật trước khi nó tự huỷ. Lão già gầy gò thức hải sụp đổ, thân thể nổ tung chết, lực trùng kích huỷ diệt nhiều pho tượng và một số tiên nhân đang ngủ say bên trong. Tứ Thánh Hoàng lần lượt hiện thân chấn kinh — Bạch Hổ khiếp sợ, Huyền Vũ tiết lộ phong ấn là thần thông tiên tôn bảo vệ ký ức hạch tâm của Thất Đạo Tông, Thánh Hoàng thứ ba quyết định thay đổi kế hoạch, Chu Tước im lặng thần sắc biến hoá. Vương Lâm bình tĩnh cười lạnh đối mặt."},{"chuong":1545,"tieuDe":"Thất Đạo Tông","tomTat":"Vương Lâm dùng Cổ Tộc Bất Diệt Chỉ liên tục điểm phá sóng trùng kích, tạo lỗ hổng bước ra ngoài, chu vi mấy trăm ngàn dặm biến thành đống đổ nát. Hắn lấy tinh thể ký ức màu vàng nhạt của lão già gầy gò, dùng giọt máu tiên nhân bất diệt thể ở mi tâm để đọc toàn bộ ký ức. Ký ức cho thấy Tiên Cương đại lục có chín mặt trời đại biểu chín đại thiên tôn, Thất Đạo Tông do đôi đạo lữ khai tông, tông chủ Thất Thải Thiên Tôn chính là viễn cổ tiên hoàng được khắc thành pho tượng bảy màu, lão già gầy gò là sĩ tiên chỉ dưới tứ đại chiến tướng. Đêm nọ hai mặt trời xuất hiện kèm uy áp kinh hoàng, Thất Thải Thiên Tôn cùng đạo lữ bay về phía hai mặt trời, mấy tháng sau một mình trở về, đạo lữ không quay lại. Đạo Cổ Diệp Mịch có thanh danh hiển hách ở đại tôn cổ quốc tìm đến chỉ trích Thất Thải vứt bỏ đạo lữ đoạt bảo vật, trận đại chiến nổ ra trong động phủ, ba kẻ phát kim quang tấn công, tử vong thảm trọng, một kẻ tự xưng Bổn vương tiến tới cánh cửa đá bên trong. Ký ức kết thúc và tinh thể tan nát. Vương Lâm nhận ra giọng Bổn vương chính là giọng người điên đang ngủ trong trữ vật, xác nhận ngân y nữ tử là nữ tử của tiên tôn, đặt nghi vấn về bản chất Thiên Nghịch và nhóm tu sĩ bên ngoài mang Côn Cực Tiên, cảm thấy ngày càng gần đáp án bí mật viễn cổ."},{"chuong":1546,"tieuDe":"Tiên Nhân Là Phải Như Vậy","tomTat":"Vương Lâm tiến sâu vào Viễn cổ Tiên Vực, thắc mắc về danh tính Thất Thải Đạo Nhân nếu Thất Thải Tiên Tôn đang trọng thương bế quan. Hắn phá hủy thêm nhiều pho tượng Tam tộc cổ, giải phóng bảy tám tiên nhân đang trị thương bên trong nhưng bỏ qua ý định sưu hồn. Phía trước xuất hiện bốn pho tượng khổng lồ chọc trời, mỗi pho tượng có vòng xoáy chứa khí tức bá đạo của bốn chiến tướng. Vương Lâm nhận ra một đạo là khí tức Chu Tước, giống Chu Tước đời thứ nhất ở Điên Lạc, xác định có một đạo là phân thân. Bạch Hổ chiến tướng (Không Huyền Sơ Kỳ) bước ra tấn công nhưng bị Vương Lâm một quyền đẩy lùi, dưới ánh mắt uy áp theo bản năng lùi lại. Vương Lâm tuyên bố thẳng Viễn cổ Tiên Vực chỉ là đám tu sĩ tàn phế đại lục Tiên Cương tự xưng tiên nhân, khiến Bạch Hổ chấn động sợ hãi khi biết hắn đã phá được phong ấn đọc ký ức. Cuối cùng Vương Lâm ra tối hậu thư cho Chu Tước chiến tướng: nếu không ra gặp sẽ giết người sưu hồn, uy áp vô hình lan ra bao phủ bốn phía."},{"chuong":1547,"tieuDe":"Hổ Khiếu Sơn Hà","tomTat":"Bạch Hổ Thánh Hoàng đang chữa thương, tu vi chỉ phát huy Không Huyền sơ kỳ, nhưng sự cao ngạo của tiên nhân không cho phép lùi bước trước Vương Lâm. Hắn thi triển thức thứ nhất trong ba thức thần thông bổn nguyên hung tinh Bạch Hổ — Hổ Khiếu Sơn Hà — triệu hoán hư ảnh Bạch Hổ cao tận trời gầm thét chấn động thiên không đại địa, uy lực đủ cuốn tan tinh không. Vương Lâm nhắm mắt vận dụng Chân Giả bổn nguyên, cho ngoại giới toàn bộ là giả do tâm sinh, khiến thân thể hoàn toàn bất khả xâm phạm — cuồng phong hổ gầm không lay động, khai thiên đao chém hàng ngàn lần xuyên qua như hư ảnh. Bạch Hổ lão giả kinh hãi nhận ra hư bổn nguyên, hồi tưởng tiên tôn từng hạ bảy đạo pháp tắc phong kín hư bổn nguyên nhưng vì trọng thương rút ra nên Vương Lâm mới lĩnh ngộ được. Vương Lâm phản kích bằng Nhân Quả bổn nguyên, vỗ chưởng lôi bạch quang từ cơ thể Bạch Hổ lão giả ra bóp nát, khiến lão phun máu hai lần. Cuối cùng Vương Lâm triệu hoán đầu lâu Đạo cổ cùng hư ảnh tam tộc cổ gầm thét, sóng âm áp đảo hoàn toàn tiếng hổ gầm, buộc Bạch Hổ lão giả phải dung hợp với hư ảnh Bạch Hổ hóa thành Bạch Hổ khổng lồ vừa rít gào vừa lùi."},{"chuong":1548,"tieuDe":"Kỵ Hổ Bất Hạ","tomTat":"Vương Lâm điểm chỉ khiến đầu lâu Đạo cổ lao về phía Bạch Hổ khổng lồ, lực trùng kích phá hủy mặt đất viễn cổ tiên vực và nổ tung vô số bức tượng tam tộc cổ, đánh tan hư ảnh Bạch Hổ, khiến Bạch Hổ lão giả phun máu bị găm vào pho tượng. Không chịu khuất phục, Bạch Hổ lão giả tự xưng truyền thừa Bạch Hổ, thi triển đại thuật thần thông Kỵ Hổ Nan Hạ — ngưng bạch quang thành Bạch Hổ khổng lồ dưới chân Vương Lâm phong ấn thiên địa, rồi phóng hổ linh bản mệnh mưu nuốt thiên linh Vương Lâm để trấn thần hồn dưới sáu mươi bảy đạo thiên sơn tiên cương đại lục. Vương Lâm không dùng thần thông mà nhắm mắt bùng phát khí thế bậc đại nho, tay trái đè lên hổ khẩu, trấn áp bằng minh ngộ cả đời cùng hư bổn nguyên bước thứ ba. Hổ linh run rẩy, nảy sinh ý niệm nhìn thấy tổ tiên Bạch Hổ linh tộc quỳ bái trước bầu trời buổi sơ khai tiên cương đại lục, sợ hãi tận linh hồn rồi cúi đầu quy phục. Chương xác nhận Bạch Hổ lão giả là tiên nhân chân chính từ tiên cương đại lục, tứ đại chiến tướng của Thất Thải Tiên Tôn, huyết mạch chứa tiên lực nhưng thương thế chưa khôi phục hoàn toàn. Tu vi Vương Lâm là Không Linh trung kỳ, thân thể Cổ Thần cùng thần thông đủ đánh Không Huyền sơ kỳ, và cố ý giữ lại cung Lý Quảng không dùng."},{"chuong":1549,"tieuDe":"Tĩnh!","tomTat":"Hổ linh cúi đầu vái Vương Lâm rồi dung hợp lại thành Bạch Hổ khổng lồ, Bạch Hổ bỏ đi không thèm để ý Bạch Hổ chiến tướng nữa, hóa bạch quang tiêu tán trong viễn cổ tiên vực. Nhân lúc bạch quang chói mắt, Thanh Long chiến tướng và Huyền Vũ chiến tướng đồng thời bước ra từ dòng xoáy pho tượng, phối hợp cùng Bạch Hổ chiến tướng cầm khai thiên đao, ba người liên thủ đánh lén Vương Lâm. Vương Lâm dùng Cổ Tộc Bất Diệt chỉ bức lùi Thanh Long khiến y phun máu, kích hoạt giọt máu tiên nhân bất diệt thể xuyên thấu nắm tay Huyền Vũ, rồi thi triển sáu chưởng ấn liên hoàn phá nát khai thiên đao và trọng thương Bạch Hổ. Bạch Hổ chiến tướng điên cuồng đòi mở phong ấn tu vi ở mi tâm, nhưng Vương Lâm rút cung Lý Quảng kéo căng dây cung, chỉ cần xuất hiện đã trấn áp hoàn toàn cả bốn chiến tướng. Cuối cùng Chu Tước chiến tướng mặc hồng bào bước ra, vẻ xấu hổ, ôm quyền xưng Vương Lâm là tiên hữu và cầu hòa."},{"chuong":1550,"tieuDe":"Giao Dịch","tomTat":"Vương Lâm thu cung Lý Quảng và gặp mặt Chu Tước chiến tướng — lão già mặc hồng bào bộ dạng cực giống Chu Tước đời thứ nhất ở Điên Lạc. Chu Tước tiết lộ trong tứ đại chiến tướng chỉ mình hắn lưu bổn tôn ở bên ngoài (Điên Lạc), đang ở Viễn Cổ Tiên Vực là phân thân; thời gian quá lâu khiến bổn tôn không còn thao túng phân thân, bổn tôn muốn về quê còn phân thân muốn tìm Tiên Tôn. Bạch Hổ hỏi về cung Lý Quảng nhưng bị Vương Lâm cự tuyệt trả lời. Thanh Long phân tích Vương Lâm dùng giọt máu tiên nhân bất diệt thể giương cung nhưng không phải tiên nhân nên chỉ bắn được vài mũi tên, đồng thời tiết lộ trước đó tứ đại chiến tướng đã giao pháp bảo tiên nhân cho người hạ giới dung nhập đại trận phòng thủ 100 năm, đã qua hơn 90 năm còn 3 năm. Vương Lâm đề xuất giao dịch: cam kết hủy Viễn Cổ Tiên Vực giới ngoại và bảo vệ bọn họ 3 năm, đổi lại bốn yêu cầu — giết hết người giới ngoại, bảo toàn tu sĩ giới nội, giải phóng sinh linh khỏi động phủ, được tới đại lục Tiên Cương nhận tài nguyên. Hắn phân tia thần thức ngưng tụ hình cành liễu làm thệ ước và cho tứ đại chiến tướng một ngày quyết định. Nội tâm Vương Lâm tiết lộ mục đích thật: lợi dụng môn nhân Thất Đạo Tông ra ngoài tìm Viễn Cổ Tiên Tôn, suy đoán Thất Thải Đạo Nhân và chiến lão quỷ cùng các phe phái dường như cùng tìm kiếm Thiên Đạo, muốn trong sự hỗn loạn đạt mục đích riêng."},{"chuong":1551,"tieuDe":"Cùng Tư Đồ Say Một Trận","tomTat":"Một ngày sau sự kiện trong viễn cổ tiên vực, Vương Lâm mang theo tứ đại chiến tướng rời đi qua cái khe thiên kiếp, nhận rõ Thiên Nghịch châu là vật mấu chốt ra vào tiên vực. Lần đầu cảm thấy thiên địa hoàn toàn hư ảo, hắn không thể nói với ai rằng giới nội giới ngoại chỉ là động phủ của tiên tôn. Hắn nhận thức Phong Tôn đời trước chỉ là thủ hạ của tiên tôn đến từ Tiên Cương đại lục, tới giới nội sắp đặt cho chủ nhân, có lẽ nảy lòng thương xót dân chúng nên mới có những chuyện về sau. Trước mấy ngàn tu sĩ hoan hô, Vương Lâm trầm mặc mê man rồi xin Tư Đồ Nam uống say một lần cuối cùng. Hai người ngồi trên đỉnh núi vô danh trên Chu Tước Tinh suốt đêm, Vương Lâm tự sự toàn bộ hành trình tu đạo: vì cha mẹ mà tu, cha mẹ chết vì hắn tu đạo, báo thù diệt Đẳng gia, vì Uyển nhi mà tiếp tục, trở thành Phong Tôn nhưng vẫn ghét tu đạo. Tư Đồ Nam nói thế gian không có trường sinh, chỉ vì sợ chết mà theo đuổi bất tử. Cuối cùng Vương Lâm tiết lộ bí mật: đã giết một tiên nhân trong viễn cổ tiên vực và lục soát trí nhớ, phát hiện giới nội giới ngoại chỉ là một tòa động phủ của viễn cổ tiên tôn, một giới tạo ra để thu thập hương hỏa. Tư Đồ Nam sửng sốt đứng phắt dậy, ánh mắt khiếp sợ, vô thức buông rơi bầu rượu."},{"chuong":1552,"tieuDe":"Đảm Đương","tomTat":"Vương Lâm kể cho Tư Đồ Nam bí mật thiên địa: giới nội và giới ngoại thực chất chỉ là bên trong và bên ngoài động phủ của Thất Thải Tiên Tôn — tông chủ Thất Đạo Tông trên đại lục Tiên Cương. Thiên Đạo do Tiên Tôn cướp được rồi nuôi dưỡng, Thiên Kiếp do hắn tạo ra để diệt trừ nghịch tu. Tư Đồ Nam rơi vào trầm mặc sợ hãi khi nghĩ mình chỉ là đồ chơi bị sắp đặt, nhưng tin tưởng vì người nói là Vương Lâm. Vương Lâm tổng kết ba quá trình tu đạo của mình và tuyên bố bước vào quá trình thứ ba — tu hành với sự kiên định chưa từng có, muốn trở nên mạnh hơn và ra khỏi thiên địa này. Hắn ngộ ra ý nghĩa thực sự của danh hiệu Phong Tôn chính là sự đảm đương: không chỉ chống ngoại xâm mà phải dẫn tu sĩ giới nội thoát khỏi động phủ. Hắn tuyên bố muốn giết Tiên Tôn để giành vận mệnh tự do, nhưng trước đó phải bảo vệ biên cương ba năm. Lần đầu nhìn pho tượng Phong Tôn cầm Khai Thiên Phủ của chính mình trên Chu Tước Tinh, cảm nhận khí thế quyết không quay đầu, liên tưởng tới Tán Linh Thượng Nhân. Đứng trên đỉnh đầu pho tượng phát lời kêu gọi tu sĩ Chu Tước Tinh cùng tới La Thiên đánh giới ngoại, vô số tu sĩ đáp lời hóa cầu vồng bay lên tụ lại."},{"chuong":1553,"tieuDe":"Rất Yên Tĩnh","tomTat":"Vương Lâm đứng trên pho tượng nhìn xuống đám tu sĩ giới nội đã tập hợp — Thập Tam, Đồng tử đầu to, Tư Đồ Nam, Nam Vân Tử cùng mấy ngàn người. Hắn hô hào cùng giành lại giang sơn giới nội rồi hóa cầu vồng dẫn đầu lao vào tinh không, toàn bộ tu sĩ theo sau như vô số lưu tinh xông ra khỏi Chu Tước Tinh. Sát tâm Vương Lâm bùng phát mạnh nhất kể từ trận diệt Đằng gia hơn hai ngàn năm trước, hắn tự nhận hiểu rõ hai chữ đảm dương và mục tiêu tối thượng là phá vỡ động phủ ra ngoài. Hắn khuếch tán thần thức bao trùm toàn bộ Côn Hư tinh vực, đơn thân truy sát và diệt sạch mọi tu sĩ giới ngoại sống sót — mấy chục người đầu tiên, cặp huynh đệ song sinh thiên nhân nhị suy nổi danh tàn bạo, cùng nhiều nhóm khác. Cặp song sinh mồ côi từ nhỏ được dã lang nuôi lớn, hợp kích ngang thiên nhân tam suy, nhưng người anh bị chém đầu, người em gào thê lương lao vào Vương Lâm rồi cũng chết. Vương Lâm mang theo mấy trăm đầu lâu bị phong ấn linh hồn và nguyên thần, quét sạch Côn Hư tinh vực rồi tiến tới biên giới Triệu Hà, chậm rãi nói rằng đã rất yên tĩnh rồi."},{"chuong":1554,"tieuDe":"Còn Chưa Đủ","tomTat":"Vương Lâm kích hoạt mấy trăm đầu lâu phía sau, lần đầu thi triển Sanh Tử Chân Giả Nhân Quả trận — trận pháp bổn nguyên do dung hợp tam đại bổn nguyên minh ngộ — vây khốn nguyên thần trong đầu lâu bằng thống khổ sinh tử chân giả vô tận, là bước đầu gieo trồng mầm mống sát lục. Hắn bước vào Triệu Hà tinh vực tràn ngập mùi máu tanh, sát lục bổn nguyên bộc phát khiến bốn phía xuất hiện bông tuyết đỏ đậm, tinh không đóng băng. Trên tu chân tinh đầu tiên, hắn dùng Nhân Quả ấn — chưởng ấn khổng lồ mang ấn ký Vạn Không Cốt Môn — tiêu diệt mấy ngàn tu sĩ giới ngoại, rút nguyên thần phong ấn vào đầu lâu, rồi tuyên bố còn chưa đủ và tiếp tục tiến lên. Thần thức bao phủ Triệu Hà phát hiện đại năng bước thứ ba Không Linh hậu kỳ giới ngoại nhưng hắn chẳng thèm quan tâm, chủ động để kẻ đó tìm mình. Tại tu chân tinh thứ hai đổ nát tràn ngập tử khí, nơi Minh Linh tộc — tiểu tộc Thái Cổ Tinh Thần tu luyện bằng hấp thu tử khí — được Trường Tôn hội ban thưởng vì lập đại công, Vương Lâm bất ngờ phát hiện Chu Tử Hồng nằm trong số tù binh giới nội bị giam trong bọt khí xám, hai mắt nhắm nghiền, sắc mặt tái nhợt. Mặt đất nứt ra, lực hút cuốn ba trăm bọt khí gồm Chu Tử Hồng vào bên trong khe nứt."},{"chuong":1555,"tieuDe":"Chém Bước Thứ Ba","tomTat":"Tộc trưởng Minh Linh tộc (tu vi thiên nhân ngũ suy) ẩn trong khe nứt tràn sương mù tử khí trên tu chân tinh, đang rút sinh cơ ba trăm nữ tu Triệu Hà bằng thuật Minh phệ cực lạc, trong đó có Chu Tử Hồng. Vương Lâm bạch y đầu bạc xuất hiện, hừ lạnh một tiếng đánh tan song chưởng tộc trưởng, một trảo nát thân thể hắn rồi phong ấn nguyên thần vào đầu lâu. Dùng sấm sét từ mắt phải chia thành vô số tia giáng xuống diệt toàn bộ tộc nhân Minh Linh tộc, thu gần vạn đầu lâu. Vung tay áo đưa nguyên thần ba trăm nữ tu trở lại cơ thể, hút toàn bộ tử khí mặt đất ngưng tụ thành quả cầu sương mù, khôi phục sinh cơ cho tu chân tinh. Sau đó phóng cơn lốc tử vong bức một tu sĩ giới ngoại Bước thứ ba hiện thân, dùng nhân quả phá tấm khiên mai rùa, Định Thần thuật khống chế rồi chém đầu. Vương Lâm tuyên bố dưới Không Huyền không ai là địch thủ, cầm đầu lâu đi vào tinh không."},{"chuong":1556,"tieuDe":"Phương Pháp","tomTat":"Vương Lâm dùng thuật sưu hồn lấy ký ức từ đầu lâu tu sĩ bước thứ ba đầu tiên bị giết, biết được hệ thống tu luyện bước thứ ba: từ Không Linh lên Không Huyền cần hư bổn nguyên — loại bổn nguyên vô hình chỉ có thể cảm ngộ, kỳ nhân đã sáng tạo phương pháp nuôi dân hương hỏa tu luyện trong hương hỏa giới hư ảo rồi thôn phệ hư bổn nguyên họ sinh ra. Vương Lâm quét sạch toàn bộ tu sĩ giới ngoại trong Triệu Hà tinh vực, đầu lâu tăng từ một vạn lên gần năm vạn. Tư Đồ Nam dẫn mấy ngàn tu sĩ tới Triệu Hà, chứng kiến tinh vực đã sạch bóng, tu sĩ Triệu Hà gia nhập đại quân theo bước chân Vương Lâm. Vương Lâm bước vào Vân Hải tinh vực, nhận ra năm vạn đầu lâu có thể tạo thành sinh tử trận, khuếch tán thần thức bá đạo bao phủ toàn tinh vực khiến tất cả tu sĩ giới ngoại kinh hãi. Thần thức quét qua phế tích Phá Thiên Tông phát hiện nữ tử thanh y bí ẩn trong nụ hoa tím khổng lồ, quét qua đại lục trôi nổi thấy lão già hồng bào ấn ký dơi đen trên tượng dơi cánh đen. Tại La Thiên, hơn mười vạn tu sĩ giới ngoại đang vây khốn trận pháp 990 tu chân tinh, bên trong có Mộc Băng Mi cùng những thân ảnh quen thuộc với Vương Lâm đang cố thủ."},{"chuong":1557,"tieuDe":"Mạnh Mẽ","tomTat":"Vương Lâm có mặt tại Vân Hải tinh vực nhưng không tiến thẳng tới La Thiên vì một mình không thể phá vỡ trận đại chiến ở đó, quyết định quét sạch tu sĩ giới ngoại ở các tinh vực khác trước để thu đầu lâu và nguyên thần tạo trận pháp cực mạnh. Sau khi thu đủ năm vạn đầu lâu, hắn chia hai dòng xoáy sinh/tử rồi dung hợp, phun tâm thần huyết bước thứ ba ngưng kết thành hình bánh xe khổng lồ mười vạn trượng — Sinh Tử trận thành. Hắn tiếp tục tàn sát để thu nguyên liệu cho trận pháp thứ hai Nhân Quả đại trận. Trên đường hắn gặp nữ tu sĩ bước thứ ba giới ngoại đóng trên tu chân tinh, nàng thi triển thần thông biến cả tu chân tinh thành hình đầu nữ tử khổng lồ nghênh chiến. Vương Lâm đánh giá thần thông không tồi nhưng tu vi quá yếu, triệu huyết kiếm dung nhập lực lượng hủy diệt Không Linh trung kỳ, một kiếm bổ đôi tu chân tinh lẫn bổn tôn, thu đầu lâu. Quét sạch toàn bộ Vân Hải tinh vực, hắn phát hiện một đại lục đang cố chạy trốn qua lỗ hổng vào Thái Cổ Tinh Thần, phóng bánh xe sinh tử đánh thẳng vào, tuyên bố mượn đầu chúng tế sinh tử đại trận."},{"chuong":1558,"tieuDe":"Hướng Về La Thiên","tomTat":"Vương Lâm thi triển Sinh Tử đại trận tại Vân Hải tinh vực, triệu bánh xe sinh tử hủy diệt toàn bộ đại lục trong sương mù, tu sĩ tu vi yếu bị diệt, nguyên thần phong ấn vào đầu lâu. Lão già đối thủ dùng hắc phong hóa miệng khổng lồ nuốt bánh xe nhưng thất bại, bị Vương Lâm giết chết, thân thể nổ tung. Một nửa đại lục trong lỗ hổng Phong Giới Đại Trận cũng bị hủy diệt thành bụi bặm. Sau khi kết thúc, Vương Lâm nén dòng xoáy đầu lâu thành bánh xe thứ hai, trên dưới thân có hai bánh xe khổng lồ (sinh tử và nhân quả), mái tóc bạc trắng, sát khí băng hàn, dịch chuyển tới La Thiên tinh vực. Tại La Thiên, tinh trận giới nội do 990 tu chân tinh tạo thành đang sụp đổ, giờ chỉ còn chưa tới 300, tu sĩ giới nội biết đã thất bại nhưng mấy lần muốn đồng quy vu tận đều bị năm bậc toàn năng Không Huyền giới ngoại ngăn cản. Giới ngoại triển khai năm bậc Không Huyền (ba tiên phi, bà lão, lão già áo đen, quý phụ áo tím), bảy bậc Không Niết/Không Linh cùng mấy chục vạn tu sĩ bao vây. Trong đám tu sĩ giới ngoại còn có phân thân Vân Lạc đại ti, thần sắc sầu lo, bổn tôn đã tử vong."},{"chuong":1559,"tieuDe":"Nữ Nhi Của Thanh Thủy","tomTat":"Vân Lạc đại ti chỉ huy đại quân giới ngoại tám hướng tổng công kích tinh trận 990 tu chân tinh — phòng tuyến cuối cùng của giới nội, nhiều tu chân tinh liên tục bị phá hủy. Mộc Băng Mi đứng cùng mấy ngàn tu sĩ Thần Tông còn sót, kiên quyết không lui vào tế đàn, bị Đạo Phi Hủ (tộc trưởng Phi tộc, một trong bảy bậc toàn năng) nhạo là hồng nhan của Phong Tôn đã chết. Nữ tử áo hồng dẫn gần ba nghìn tu sĩ Côn Hư tử thủ, uể oải thì thầm rằng còn chưa nói cho hắn biết mình là ai. Tây Tử Phượng, Chiến Không Liệt, Thân Công Hổ, Viêm Lôi Tử cùng tu sĩ La Thiên chuẩn bị tự bạo khi màn sáng sụp đổ. Thanh Lâm trọng thương vẫn ra đánh với lão già áo đen, nữ tử tử y (thủ lĩnh Triệu Hà) xuất trận bị tiên phi đón đánh. Thanh Thủy ngồi trong tế đàn bị trọng thương nghiêm trọng với thất khiếu bảy luồng hắc khí, Hồng Sam Tử cảnh báo không giúp thì ba khắc sẽ chết nhưng bị Thanh Thủy quát đuổi, cuối cùng bi ai rời đi ra ngoài đối mặt bà lão bước thứ ba giới ngoại. Thanh Thủy ngẩng đầu nhìn về phía nữ tử áo hồng với ánh mắt nhu hòa, nói 'Là nó sao… hẳn là nó rồi' — gợi ý nhận ra nàng là con gái mình. Đại hán toàn năng phá tan màn sáng tu chân tinh nữ tử áo hồng, kéo mấy vạn tu sĩ lao tới."},{"chuong":1560,"tieuDe":"Chưởng Tôn Hiện !","tomTat":"Thanh Thủy dù chỉ còn sống ba khắc, cảm nhận khí tức hồn phách nữ nhi nơi nữ tử áo hồng — bí mật không ai biết kể cả Vương Lâm — quyết liều mạng bảo vệ nàng. Hắn bùng phát sát lục bổn nguyên, dùng bông tuyết đỏ và sát lục tâm xé nát Lôi Long màu đen vạn trượng của đại hán phong lôi, chém đối thủ vết thương từ mi tâm tới ngực suýt chết, nhưng sau đó thân thể sụp đổ phun máu đen, được nữ tử áo hồng đỡ lấy. Cùng lúc, tấm màn sáng tu chân tinh Mộc Băng Mi tan nát, Đạo Phi Hủ tiến vào nhắm chiếm đoạt nàng; Thanh Lâm, nữ tử Triệu Hà và Hồng Sam Tử cũng gặp nguy cơ sinh tử khi giao chiến với toàn năng Không Huyền giới ngoại. Khe không gian khổng lồ mở ra, Chưởng Tôn lần đầu dùng bổn tôn bước vào giới nội cùng hành cung cung điện, mặc hắc bào với cánh tay khô héo như xương khô, đánh chưởng ấn khổng lồ che lấp tinh không nhắm Hồng Sam Tử, nữ tử Triệu Hà và Thanh Lâm, tuyên bố kết thúc chiến tranh. Đúng lúc tuyệt vọng, từ ranh giới La Thiên và Vân Hải Tinh Vực, mũi tên mang phẫn nộ và sát lục gầm thét vang lên, lấn áp cả chưởng ấn Chưởng Tôn — Vương Lâm đã tới."},{"chuong":1561,"tieuDe":"Đại Bộc Phát!","tomTat":"Vương Lâm bạch y tóc bạc xuất hiện trên mũi tên Lý Quảng vạn trượng, mang sát lục tích từ Côn Hư, Triệu Hà, Vân Hải xé rách tinh không lao tới La Thiên. Thanh Thủy, Mộc Băng Mi, Thanh Lâm, Hồng Sam Tử cùng hơn mười vạn tu sĩ đều chấn động. Mũi tên lần lượt phá chưởng ấn bảy màu, bảy tầng màn sáng, mặt trời huyết mạch tiên nhân có thái sơ quy tắc, và mũi tên hư ảo từ giếng hương hỏa giới thứ hai của Chưởng Tôn, xuyên thấu thân thể hắn và phá hủy cung điện thánh vật. Chưởng Tôn tiết lộ Vương Lâm đã bỏ tiên nhân bất diệt thể làm tiên lực cho cung, chỉ đủ bắn thêm hai lần, sau đó tuyệt đối không thể thành tiên nhân. Chưởng Tôn dùng phong diệt tộc tam mệnh thuật tái sinh rồi lập tức nhảy vào khe bỏ trốn. Vân Lạc đại ti run rẩy nhận ra Vương Lâm chính là Người hủy diệt thiên địa mà nàng từng nhìn thấy khi tính toán. Vương Lâm xoay người bảo vệ Mộc Băng Mi, tuyên bố nàng là mẫu thân con trai Vương Bình, nhìn thẳng đe dọa Đạo Phi Hủ đang đứng gần nàng."},{"chuong":1562,"tieuDe":"Quyết Chiến (Nhất)","tomTat":"Đạo Phi Hủ kinh hãi trước uy lực Vương Lâm, hối hận vì đã trêu chọc Mộc Băng Mi, tuyệt vọng lao tới định bắt nàng làm con tin nhưng bị Vương Lâm chặn đứng. Vương Lâm phá nát tứ chi rồi vỗ mi tâm khiến thân thể Đạo Phi Hủ nổ tung, bóp nát nguyên thần — bậc toàn năng bước ba Không Niết hoàn toàn tử vong. Đại hán phong lôi bỏ chạy, thi triển cơn lốc máu kết hợp lôi cầu đỏ nhưng Vương Lâm thể hiện lôi bổn nguyên đại thành viên mãn khiến mọi lôi đình thuần phục, phá tan công kích. Vương Lâm điểm vào cổ đại hán, hút sạch máu huyết, sinh cơ, xương cốt, nguyên thần biến thành quả cầu sương mù. Sau đó Vương Lâm xua bảy luồng hắc khí độc tố khỏi thất khiếu Thanh Thủy, ấn quả cầu sương mù vào cơ thể sư huynh để hồi phục thương thế. Vương Lâm nói rõ lý do: Mộc Băng Mi là mẫu thân Vương Bình, tuyệt đối không cho phép ai khinh nhờn. Xong việc, Vương Lâm liếc nữ tử áo hồng bên cạnh Thanh Thủy rồi xoay người đi vào tinh không."},{"chuong":1563,"tieuDe":"Quyết Chiến (Nhị)","tomTat":"Vương Lâm tuyên chiến với tu sĩ giới ngoại, phát lệnh tổng phản công dẫn gần tám vạn tu sĩ giới nội (Thanh Lâm, Hồng Sam Tử, Triệu Hà, Mộc Băng Mi, Thần Tông) xông ra từ tinh trận. Hắn triệu xuất bánh xe Sinh Tử trận thi triển trấn áp thương sinh, khiến mấy vạn tu sĩ giới ngoại phun máu, một số tan nát tử vong. Vương Lâm xông vào giữa đại quân mở con đường máu, đầu lâu kẻ địch ngưng tụ thành áo choàng đầu người phía sau. Hắn nhắm tiên phi (Không Huyền trung kỳ) làm mục tiêu đầu tiên: dùng thân thể Cổ Thần ngạnh kháng ngũ tạng thuật dù ngũ tạng vỡ vụn, tung quyền dung hợp Đạo cổ và tam tộc cổ đánh lui nàng. Rút Xạ Thần xa chấn nhiếp tiên phi bỏ chạy, dùng Định khống chế, thi triển tiên thuật Bạch Phàm và Âm Nguyệt Hữu Tình xé tan dung nhan nàng. Hé lộ thân phận tiên phi là phi tử tông chủ Thất Đạo Tông từ Tiên Cương đại lục khiến nàng kịch chấn sững lại. Cuối chương Vương Lâm rút huyết kiếm vung chém xuống tiên phi, kết quả chưa rõ."},{"chuong":1564,"tieuDe":"Quyết Chiến (Tam)","tomTat":"Vương Lâm phối hợp Dịch Linh Ấn và huyết kiếm hạ sát tiên phi đầu tiên, khiến nàng hình thần câu diệt, nhưng bản thân bị thương bởi thần thông huyết mạch tiên nhân lúc nàng chết. Hắn biến thành sương mù đen thôn phệ hơn vạn tu sĩ giới ngoại, khôi phục hơn phân nửa thương thế. Lão già áo đen tu vi Không Huyền sơ kỳ thừa cơ đánh lén bằng kiếm khí, Vương Lâm thi triển Nhân Quả trận biến kiếm khí của lão thành năm vạn đạo kiếm khí quét ngang tám hướng, giết năm vạn tu sĩ giới ngoại. Hắn tiếp tục dùng Sinh Tử Ấn và Nhân Quả Ấn đánh trúng lão già, kéo một phần bổn nguyên ra bóp nát, rồi tung Thất Thải Đinh đâm ngực. Tiên phi áo lam bỏ Thanh Lâm lao tới vây công, Vương Lâm kích hoạt Thiên Hoàng Lô dung hợp Cổ Thần tinh điểm, giọt máu tiên nhân bất diệt thể cùng thần thông Lưu Nguyệt tạo cánh cửa đá, thôn phệ và trấn áp cả tiên phi áo lam lẫn lão già áo đen vạn vạn năm. Cuối chương Vương Lâm hô Thanh Lâm, Hồng Sam Tử, Triệu Hà liên thủ chặn hai Không Huyền cuối cùng, bản thân chuẩn bị bố trí Sinh Tử Nhân Quả Chân Giả đại trận, quyết giết hết tu sĩ giới ngoại để xem Chiến lão quỷ và đạo nhân bảy màu rốt cục muốn gì."},{"chuong":1565,"tieuDe":"Quyết Chiến (Tứ)","tomTat":"Vương Lâm ngồi trên Thiên Hoàng Lô triển khai trận pháp tam đại bổn nguyên — chồng ba bánh xe Sinh Tử, Chân Giả, Nhân Quả thành thần thông mạnh nhất hắn tự sáng tạo, cả đời chỉ ngưng tụ được một lần duy nhất. Một vạn tu sĩ giới nội tự nguyện hiến nguyên thần làm trận linh, bánh xe bành trướng sánh ngang bầu trời quay vòng đầu tiên phá tan tinh trận và giết ba phần tu sĩ giới ngoại. Toàn bộ tu sĩ giới nội kể cả Mộc Băng Mi đồng loạt xuất nguyên thần đẩy vòng hai, lại giết thêm ba phần. Thanh Lâm cùng Hồng Sam Tử, nữ tử Triệu Hà, Thanh Thủy xuất nguyên thần đẩy vòng ba khiến tinh không thực sự sụp đổ. Vương Lâm đích thân xuất nguyên thần hoàn thành vòng bốn, quét ngang toàn bộ La Thiên diệt sạch hơn mười vạn tu sĩ giới ngoại. Bà lão áo lục Không Huyền hình thần câu diệt, chỉ tiên phi Không Huyền dùng thần thông tổn mệnh của Tiên Cương đại lục mở khe thoát thân. Toàn bộ tu sĩ giới nội nguyên thần kiệt quệ đồng loạt phun máu trọng thương. Vương Lâm phun máu, mang Thiên Hoàng Lô và bánh xe bay đi, tuyên bố ba năm cuối cùng và hứa bảo vệ mọi người ba năm tu dưỡng."},{"chuong":1566,"tieuDe":"Hồi Phục","tomTat":"Bánh xe vận mệnh quét sạch toàn bộ tu sĩ giới ngoại trong tứ đại tinh vực, chỉ một tiên phi xé không gian chạy thoát và Vân Lạc đại ti sống sót nhờ bóp nát ngọc giản bảo mạng na di về tế đàn tộc Thái Cổ Tinh Thần. Vương Lâm bị thương nặng kiệt sức từ ba nguồn nhưng tuyên bố bảo vệ giới nội ba năm, rồi mang ý niệm điên cuồng cuốn bánh xe tam đại bổn nguyên lao về Vân Hải tinh vực — nơi lỗ hổng Phong Giới Đại Trận ngàn trượng gần ngàn năm không khép. Tư Đồ Nam đến muộn cùng mấy ngàn tu sĩ trở thành lực lượng bảo vệ cho giới nội chữa thương. Thanh Thủy nhận ra nữ tử áo hồng là nữ nhi của mình nhưng không nói được, chỉ khuyên nàng đuổi theo Vương Lâm đừng do dự. Mộc Băng Mi hóa phượng hoàng lam, nữ tử áo hồng, Tây Tử Phượng và nữ tử áo tím bậc toàn năng Không Huyền từ Triệu Hà lần lượt đuổi theo Vương Lâm. Thanh Lâm cảm thán rằng Vương Lâm đã biết chút sự thật mà chính Thanh Lâm năm đó phải tự lừa mình quên đi. Giới nội chỉ còn chưa tới năm vạn tu sĩ từ gần năm mươi vạn trước đó, La Thiên Tinh Vực còn mười chín tu chân tinh trở thành nơi chữa thương mới."},{"chuong":1567,"tieuDe":"Bát Phi","tomTat":"Nữ tu tên Tử Hà từ Triệu Hà tinh vực tới gặp Vương Lâm trước lỗ hổng Phong Giới Đại Trận, tự xưng tiên phi thứ tám của Thất Thải Tiên Tôn. Nàng yêu cầu Vương Lâm giao tiên phi thứ năm đang bị phong ấn và bắt hết các tiên phi còn lại. Vương Lâm lạnh lùng cự tuyệt, không giao tiên phi, không bắt tiên phi. Tử Hà chuyển sang dụ dỗ bằng cơ duyên gia nhập Thất Đạo Tông và một đại lục trên Tiên Cương, nhưng Vương Lâm khinh bỉ đáp rằng Thất Thải Tiên Tôn chỉ là tiểu chư hầu, Thất Đạo Tông chỉ là tiểu tông phái. Hắn phát sát khí đuổi Tử Hà đi. Vương Lâm hồi tưởng tổng kết tình trạng tám tiên phi và suy đoán nữ tử có ước định ở Vân Hải tinh vực có thể là tiên phi thứ nhất hoặc thứ bảy. Trong tâm hắn lập chí sẽ giết tiên tôn lấy thiên đạo để giải phóng dân chúng trong động phủ ra Tiên Cương đại lục. Sau đó hắn ngồi hấp thu thiên địa nguyên lực và dùng Nhân Quả ấn rút bổn nguyên khôi phục tu vi, quyết tâm khi Phong Giới Đại Trận chết sẽ tự dùng tu vi tạo trận mới thay thế."},{"chuong":1568,"tieuDe":"Hủy Trận","tomTat":"Vương Lâm suy ngẫm về con đường bước thứ ba độc nhất của mình: không cần hương hỏa, dựa vào minh ngộ và thôn phệ bổn nguyên, có thể đạt tới bảy, tám, chín, thậm chí mười đạo bổn nguyên — con đường chưa ai từng đi. Hắn cũng nhớ lại thông tin về Chưởng Tôn chỉ vượt ba lần huyền kiếp, Lam Mộng Đạo Tôn dừng ở Không Huyền hậu kỳ viên mãn đỉnh phong vì còn một việc chưa hoàn thành, và Chiến lão quỷ — người duy nhất trong lịch sử động phủ vượt tới huyền kiếp thứ tám nhờ một tiên duyên bí ẩn sau khi đột kiếp thứ năm thất bại. Vương Lâm đứng dậy đạp lên Phong Giới Đại Trận đang thoi thóp, vái nó một vái rồi tuyên bố sẽ bố trí đại trận mới hoàn toàn thuộc về tu sĩ giới nội. Hắn thi triển Nhân Quả trừu linh lần lượt rút ra và hủy diệt bảy trận linh — trong đó trận linh thứ nhất là thánh vật Thiểm Lôi tộc. Phong Giới Đại Trận sụp đổ hoàn toàn, ranh giới giới nội – giới ngoại bị xóa bỏ trước mắt mấy vạn tu sĩ. Cuối cùng hắn cho bát linh — Khai Thiên Phủ, pháp khí vô thượng Cổ Thần tộc — lựa chọn trở về tay hắn hoặc bị hủy diệt, hư ảnh khổng lồ mang khí tức Cổ Thần chậm rãi trôi ra."},{"chuong":1569,"tieuDe":"Tân Kỷ Nguyên","tomTat":"Khai Thiên Phủ xuất hiện với khí tức cổ Thần và oan hồn bao quanh, khí linh bên trong do dự giữa nhận chủ hoặc bị hủy. Vương Lâm ra tối hậu thư rồi Khai Thiên Phủ phản kháng chém về phía hắn. Vương Lâm hóa chân thân cổ Thần ngàn trượng, dùng nắm đấm đánh văng lưỡi búa dù tay bị thương tới xương, rồi triệu huyết kiếm trăm trượng giao chiến liên tục đánh bại khí linh. Khi khí linh hóa hư ảnh cổ Thần khổng lồ lao tới, Vương Lâm xưng vương tộc cổ Thần và triệu đầu lâu Đạo cổ gào lên uy hiếp, khiến khí linh tan nát rồi ôm quyền quy phục. Vương Lâm cắn lưỡi phun máu tạo ấn ký thu phục Khai Thiên Phủ, dung nhập mi tâm, hoàn toàn dựa sức mình. Sau đó hắn thi triển Nhân Quả ấn lần cuối cùng lôi ngọc bội chữ tiên (trận linh cuối cùng) ra khỏi Phong Giới Đại Trận, ngọc bội vỡ thành năm mảnh, đại trận hoàn toàn tan rã, tứ đại tinh vực được giải phóng, giới nội giới ngoại hợp nhất. Mộc Băng Mi, Tây Tử Phượng, nữ tử áo hồng chứng kiến trong Vân Hải tinh vực, mặt tái nhợt. Các bậc toàn năng La Thiên kích động vì lực ngăn hương hỏa biến mất. Vương Lâm trở thành người đầu tiên từ cổ chí kim hủy Phong Giới Đại Trận, mang danh Phong Tôn thế hệ mới chuẩn bị dẫn tu sĩ giới nội ra Tiên Cương đại lục."},{"chuong":1570,"tieuDe":"Khai Ích","tomTat":"Phong Giới Đại Trận sụp đổ hoàn toàn sau mấy canh giờ giằng co, khí tức Thái Cổ Tinh Thần tràn ngập giới nội mang lại sinh cơ cho tu sĩ, chấm dứt vòng tuần hoàn ác tính kéo dài từ thời thượng cổ. Tu sĩ giới ngoại còn sót lại trong Thái Cổ Tinh Thần chấn động, đồng loạt bay về hướng giới nội. Vương Lâm đứng giữa tinh không tuyên bố lập trận pháp mới tên Vô Danh, dùng bánh xe tam đại bổn nguyên khuếch trương tới vô tận thay thế Phong Giới Đại Trận bao phủ toàn bộ tứ đại tinh vực. Hắn kêu gọi linh hồn pháp bảo đã tan nát và tinh hồn tu chân tinh bị hủy diệt trong trăm năm chiến tranh dung hợp vào bánh xe, khiến trận pháp trở nên thực chất với uy áp vượt thiên địa. Hắn dùng thần thông gió lốc cuốn trên trăm vạn tàn hồn tu sĩ giới ngoại từ khắp tứ đại tinh vực phong ấn vào trận pháp, ép chúng đẩy bánh xe đời đời kiếp kiếp chuộc tội vĩnh viễn, đồng thời loại bỏ nguồn oán khí gây tâm ma cho tu sĩ tu vi thấp. Trận pháp Vô Danh ngăn cách giới nội giới ngoại nhưng không cản khí tức Thái Cổ Tinh Thần, mở ra thời đại mới và là bước đầu tiên trong kế hoạch giết tiên tôn. Cuối cùng Vương Lâm kính cẩn ôm quyền vái tinh không, thỉnh mời hồn phách tiên nhân giới nội nguyện làm trận linh bất diệt được đời đời cúng bái."},{"chuong":1571,"tieuDe":"Tế Bái","tomTat":"Vương Lâm thực hiện nghi thức tế bái chưa từng có trong lịch sử giới nội, cúng tế toàn bộ vong hồn tử trận trong chiến tranh giới nội – giới ngoại từ viễn cổ tới nay. Ba lớp anh hồn theo thời đại xuất hiện: tàn hồn viễn cổ, tiên nhân thượng cổ từ tứ đại tiên giới, và tu sĩ cận đại. Hàng chục vạn anh hồn tự nguyện dung nhập vào bánh xe tam đại bổn nguyên, trở thành trận linh bất diệt. Tu sĩ khắp tứ đại tinh vực đồng loạt tự phát vái lạy. Chiến lão quỷ trong Côn Hư tinh vực nhận ra đồng đạo cũ, khi vái lạy bị một luồng lực lượng bí ẩn trong cơ thể ngăn cản nhưng cưỡng ép hoàn thành, tiết lộ đã biết một bí mật kinh người trong tiên duyên. Thiên Vận Tử ẩn trong Triệu Hà tinh vực, xác nhận mình là người thứ nhất trừ hai kẻ kia thức tỉnh trí nhớ. Một thanh niên bí ẩn từ thiên kiếp Vương Lâm cũng ẩn trong Triệu Hà, khinh miệt tế bái, gọi anh hồn là chim trong lồng, lần đầu tiên tiết lộ cái tên Thất Đạo Tông khi gọi giới nội là động phủ của Thất Đạo Tông, và nhắc Mã sư bá sắp thức tỉnh."},{"chuong":1572,"tieuDe":"Lập Lại Thế Giới","tomTat":"Vương Lâm khai mở Vô Danh Chuyển Luân trận, dùng tam đại bổn nguyên biến thành bánh xe, lấy anh hồn giới nội làm trận linh và tàn hồn giới ngoại làm nô dịch đẩy bánh xe vận chuyển. Trận pháp ngăn tu sĩ mang ấn ký thái cổ xâm nhập giới nội nhưng cho phép khí tức Thái Cổ Tinh Thần tràn vào, giải phóng tu sĩ giới nội khỏi hạn chế tế luyện hương hỏa. Vương Lâm tuyên bố Phong Giới Đại Trận năm xưa bất công, nay muốn lập lại tinh không mở lại tinh vực, đồng thời triệu tập hồn phách phàm nhân vô tội chết trong chiến tranh tu sĩ suốt vô số năm để tiễn vào thiên đạo luân hồi, nhờ đó giới nội mở rộng lên ba phần. Sau cùng Vương Lâm tự dung nhập trận pháp trở thành trận linh, khoanh chân ngồi trên Thiên Hoàng Lô trước lỗ hổng Vân Hải tinh vực, thề bảo vệ giới nội ba năm, trận pháp khuếch trương tới bốn phần. Chưởng Tôn quan sát từ cung điện, phán đoán Vương Lâm chỉ còn sức bắn hai mũi tên, bèn truyền lệnh Trường Tôn hội ngưng tụ toàn bộ lực lượng trong ba năm phải hủy diệt trận pháp, ép toàn năng Thái Cổ Tinh Thần và tu sĩ thiên nhân đệ ngũ suy phục tùng, đồng thời mở bảo khố lấy viễn cổ bí chiếu. Chưởng Tôn tới Lam Sơn giao dịch với Lam Mộng Đạo Tôn, đề nghị nếu Lam Mộng dẫn động được một mũi tên của Vương Lâm thì sẽ trợ giúp bức hồn phách tiên phi thứ năm ra khỏi nhục thân thê tử Vương Lâm, rồi triệu tiên phi thứ bảy đang bế quan khôi phục thương thế ra tay tham chiến. Cuối cùng Chưởng Tôn đi sâu vào Thái Cổ Tinh Thần, tới nơi sáu đại lục lơ lửng tạo thành vòng tròn có trận pháp chỉ huyết mạch tiên nhân mới vào được, cung kính cầu kiến sư tôn của mình."},{"chuong":1573,"tieuDe":"Thuộc Về Tây Tử Một Năm","tomTat":"Chưởng Tôn tới chín đại lục trôi nổi trong Thái Cổ Tinh Thần bái kiến sư tôn — đạo nhân bảy màu, thân ảnh huyễn hóa từ cầu vồng bảy màu. Chưởng Tôn bẩm báo thất bại trong trận đánh giới nội-giới ngoại, cây cung Lý Quảng đã rơi vào tay Vương Lâm. Đạo nhân bảy màu hé lộ khái niệm người thứ ba — kẻ ẩn thế luân hồi vô số lần, giờ phải đi ra, và nói Vương Lâm cũng không loại trừ khả năng là người thứ ba. Đạo nhân lộ mưu đồ thôn phệ người thứ ba để vượt Chiến lão quỷ, coi chủ nhân bí ẩn của Chưởng Tôn là thuốc bổ. Vương Lâm khoanh chân ngồi trên Thiên Hoàng Lô trong Vô Danh Chuyển Luân trận, trấn áp phong ấn hai bậc toàn năng Không Huyền bên trong. Tây Tử Phượng cùng Mộc Băng Mi và Hoa Phi tới nơi Vương Lâm bảo vệ, ba nàng đã thỏa thuận mỗi người một năm bên hắn. Tây Tử Phượng xin một năm, bị cự tuyệt rồi được đồng ý, ngồi bên cạnh hâm rượu cho hắn. Ba tháng trôi qua, đại quân giới ngoại mười vạn tu sĩ, năm bước thứ ba và chiến xa ngàn trượng ngưng tụ tấn công lần nữa."},{"chuong":1574,"tieuDe":"Rượu Còn Chưa Đủ Ấm","tomTat":"Giới ngoại huy động toàn bộ lực lượng cực hạn cuối cùng — mười vạn tu sĩ, năm bậc toàn năng bước thứ ba, chiến xa bọc da thú và bia đá chín quan tài — dàn trận trước Vô Danh Chuyển Luân trận theo lệnh tử chiến của Trường Tôn hội. Đòn đầu tiên do lão già tóc bạc chỉ huy: năm toàn năng dung hợp lực lượng thi triển viễn cổ thuật tạo đại kiếm vạn trượng hợp nhất mười vạn nguyên thần chém xuống, nhưng trận pháp phản lực bộc phát đánh bật kiếm vỡ tan, lão già thổ huyết. Không chịu lùi, lão già kêu gọi mười vạn tu sĩ hiến tế toàn bộ thọ nguyên, nguyên thần dung hợp thành hắc động triệu hồi ánh sáng viễn cổ kim quang mang khí tức Tiên Cương đại lục, suýt phá bánh xe tam đại bổn nguyên. Chưởng Tôn quan sát từ xa, nhận định thần thông này rất mạnh ngay cả hắn cũng phải cố sức đối kháng, tò mò xem Vương Lâm có dùng Xạ Thần xa hay không. Vương Lâm bình tĩnh thi triển Phần Giới Cổ Tán mở ô diệt giới bao phủ kim quang, đồng thời triệu xuất trường thương bảy màu phá nát ánh sáng viễn cổ. Sau khi phá giải, hắn vung tay áo bước về bên Tây Tử Phượng, uống rượu bình thản nói rượu còn chưa đủ ấm."},{"chuong":1575,"tieuDe":"Viễn Cổ Mãnh Thú","tomTat":"Vương Lâm tuyên bố trong ba năm ai muốn vào giới nội phải bước qua xác hắn, thi triển trường thương bảy màu lao vào dòng xoáy mười vạn nguyên thần, đối kháng ánh sáng viễn cổ — hai bên triệt tiêu lẫn nhau. Chưởng Tôn từ Thái Cổ Tinh Thần nhận ra thần thông tuyệt mật của sư tôn Thất Thải Tiên Tôn trên tay Vương Lâm, oán hận vì chưa bao giờ được truyền thụ cấp bậc này dù cúc cung tận tụy nhiều năm. Vương Lâm tiếp tục dùng Phần Giới cổ Tán với biển lửa diệt giới che hắc động, đốt cháy dòng xoáy nguyên thần khiến năm bậc toàn năng và mấy vạn tu sĩ phun máu trọng thương. Năm bậc toàn năng không dám lui vì Trường Tôn hội uy hiếp diệt toàn tộc, lão già trong nhóm hạ lệnh chiến xa oanh kích. Hơn mười chiếc chiến xa viễn cổ mãnh thú — chí bảo Trường Tôn hội, mỗi chiếc trấn áp hồn phách mãnh thú có tổ tiên từ Tiên Cương — được đẩy tới. Tu sĩ cảm tử bị bắn tung từ chiến xa hóa lưu tinh tử vong đánh lên trận pháp, khí tức tử vong tích tụ hình thành ký hiệu quỷ dị hấp dẫn mãnh thú thức tỉnh đồng loạt tấn công, Vô Danh Chuyển Luân trận chấn động run rẩy. Vương Lâm tuyên bố hắn cũng có viễn cổ cự thú còn sống có thân thể, điểm lên mi tâm triệu hồi — dòng xoáy tỏa khí tức tang thương và u quang lóe lên."},{"chuong":1576,"tieuDe":"Là Mắt Trái Sao","tomTat":"Giữa lúc hơn mười hồn phách mãnh thú viễn cổ tấn công Vô Danh Chuyển Luân trận, U Minh thú của Vương Lâm bất ngờ xuất hiện với hư ảnh khổng lồ bao trùm trận pháp, uy áp tự nhiên khiến mãnh thú run rẩy lùi lại do nỗi sợ khắc sâu trong ký ức tổ tiên. Bản tính nhát gan bộc phát, U Minh thú bị hình dạng dữ tợn của mãnh thú và tiếng hét tu sĩ dọa cho sợ gần bất tỉnh, nhưng tiếng gầm hoảng sợ của nó lại khiến mấy vạn tu sĩ giới ngoại và năm bậc toàn năng kinh hãi lùi lại. Vương Lâm bước lên thân U Minh thú trấn an qua tâm thần tương liên, ra lệnh nó nuốt trọn hơn mười hồn phách mãnh thú nhưng ngăn hút tu sĩ để tránh nó ngủ say nhiều năm — cũng là lý do trước đó ở chiến trường La Thiên không triệu hoán nó. Sau khi mười vạn nguyên thần và chiến xa Trường Tôn hội đều bị hủy, quân giới ngoại dùng vũ khí cuối cùng: tấm bia đá khổng lồ mang chín sợi xích sắt gắn chín quan tài. Chín ký hiệu trên bia đá lóe sáng kích hoạt chín quan tài, tóc đen yêu dị tràn ngập tinh không, năm bậc toàn năng và mấy vạn tu sĩ quỳ bái phun nguyên thần tinh huyết hiến tế gọi hồn phách Thái cổ hoàng thần. Chín quan tài vỡ tan bùng lên luồng khí tức Đạo cổ biến đổi giữa Cổ Thần – Cổ Ma – Cổ Yêu, Vương Lâm nhận ra thuộc về Đạo cổ Diệp Mịch nhưng phán đoán không phải mắt trái vì khí tức chưa đủ mạnh, chương kết thúc với câu hỏi bỏ ngỏ về bản chất thực sự của vật phong ấn."},{"chuong":1577,"tieuDe":"Cổ Tộc Chiến Ấn","tomTat":"Chín chiếc quan tài lần lượt nổ tung, chín phần thân thể dung hợp thành nam tử trung niên ngàn trượng mang khí tức Đạo cổ Diệp Mịch, mi tâm có hai tinh điểm Cổ Thần, mắt trái ba yêu tinh, mắt phải ba ma tinh. Chưởng Tôn tiết lộ đây là chí bảo Trường Tôn hội do hắn và đạo nhân bảy màu tạo nên, xuất ra để bức Vương Lâm bắn tên Xạ Thần xa và hy vọng hai kẻ mang truyền thừa Đạo cổ tự giết nhau gây thiên biến tạo vết rách trên trận pháp. Sâu trong La Thiên Tinh Vực, tại Đông Lâm tinh bị đóng băng, nữ Cổ Thần bảy tinh điểm cảm nhận được khí tức huyết mạch phụ tổ, dung hợp bảy tinh điểm thành ấn ký hình giọt máu. Nam tử trung niên dùng Cổ tộc Chiến Ấn — ấn ký chí cao vô thượng tam tộc cổ — khiêu chiến Vương Lâm, ép đấu sanh tử, kẻ thua mất toàn bộ. Vương Lâm nhận ra ấn ký từ trí nhớ truyền thừa Đạo cổ, đáp lại bằng Chiến Ấn, lần đầu tiên rời khỏi Vô Danh Chuyển Luân trận. Thân thể hắn bành trướng tới ngàn trượng, lao ra tinh không Thái cổ Tinh Thần đấu quyền trực tiếp với nam tử, va chạm chấn động giới nội giới ngoại. Mục đích của Vương Lâm là đoạt khí tức Đạo cổ trên người đối phương để tiến tới bát tinh Cổ Thần. Tây Tử Phượng ở trong trận pháp im lặng hâm rượu, tin rằng Vương Lâm sẽ không bại."},{"chuong":1578,"tieuDe":"Diệp Mịch Không Có Con Trai !","tomTat":"Vương Lâm giao tranh khốc liệt bằng thân thể cổ tộc với nam tử trung niên, hai bên trao đổi chín quyền cận chiến, dư chấn khiến mấy vạn tu sĩ giới ngoại phải lui hơn mười vạn trượng và Vô Danh Chuyển Luân trận bị vặn vẹo. Vương Lâm hợp song quyền xuyên phá Cổ Thần nhất chỉ (hư ảnh Cổ Thần tám tinh điểm), đánh lõm ngực đối thủ nhưng cũng bị đá bắn lùi mấy ngàn trượng. Nam tử trung niên liên hoàn thi triển Cổ Yêu thôn thiên, Cổ Ma phệ địa, Cổ Thần nổi giận, rồi triệu hư ảnh Đạo Cổ Diệp Mịch, tự xưng con trai Đạo cổ đòi thu hồi truyền thừa. Vương Lâm nếm máu đối phương phân tích ra Đạo Cổ Diệp Mịch KHÔNG có con trai, trước khi chết ba ngàn giọt máu hóa thành tam tộc cổ, trong đó chín giọt tâm huyết; nam tử trung niên do đám Chưởng Tôn giới ngoại qua vô tận năm tháng giết vô số người tam tộc cổ, ngưng tụ tám giọt tâm huyết tạo thành. Vương Lâm bộc phát khí tức Đạo cổ, triệu hồi đầu lâu Đạo cổ (không mắt trái) quyết sinh tử. Nếu thắng, tám giọt tinh huyết sẽ khiến tinh điểm Cổ Thần ngưng hóa đến tám cái, đồng thời tăng tinh điểm Cổ Yêu và Cổ Ma, tương đương cơ hội truyền thừa Đạo cổ lần thứ hai."}];
